insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (224, 'Git Repository Exposure Detected on Web Server', 3, 2, 0, 'Reconnaissance', 'T1083 - File and Directory Discovery', 'Detects HTTP requests attempting to access .git/ directories and related version control files on web servers. Exposed Git repositories can reveal source code, credentials, API keys, database connection strings, and internal infrastructure details. Attackers enumerate these paths to find sensitive information for further exploitation.

Next Steps:
