', '2026-02-09 16:37:04.303053', true, false, 'origin', null, '[{"indexPattern":"v11-log-apache-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":[{"indexPattern":"v11-log-nginx-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-15m","count":3},{"indexPattern":"v11-log-iis-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-15m","count":3}],"within":"now-15m","count":3}]', '["lastEvent.log.request","adversary.ip"]');
