  )) ||
  (contains("log.message", "groovy") && contains("log.message", "execute")) ||
  (contains("log.message", "script_score") && regexMatch("log.message", "(?i)(java\\.|Runtime|Process)"))
)
', '2026-02-09 16:37:05.016334', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (236, 'Elasticsearch External Reindex Exfiltration Detection', 3, 2, 1, 'Data Exfiltration', 'T1048 - Exfiltration Over Alternative Protocol', 'Detects _reindex API calls with remote/external source or destination that could indicate data exfiltration to attacker-controlled Elasticsearch clusters. The reindex API can transfer entire indices to remote clusters.

Next Steps:
1. Review the reindex request for remote host configuration
2. Verify the remote Elasticsearch cluster is legitimate
3. Check what index data is being transferred
4. Restrict reindex.remote.whitelist configuration
5. Monitor outbound network connections from the cluster
6. Block unauthorized external reindex operations
', '["https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-reindex.html","https://attack.mitre.org/techniques/T1048/"]', 'exists("log.message") &&
(
  (contains("log.message", "_reindex") && contains("log.message", "remote")) ||
  (contains("log.message", "reindex") && contains("log.message", "remote.host")) ||
  (contains("log.message", "reindex.remote.whitelist") && contains("log.message", "updated")) ||
  (contains("log.message", "reindex") && regexMatch("log.message", "(?i)https?://[0-9]+\\.[0-9]+\\.[0-9]+\\.[0-9]+"))
)
', '2026-02-09 16:37:05.161420', true, false, 'origin', null, '[]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (237, 'Elasticsearch Snapshot Exfiltration Detection', 3, 1, 1, 'Data Exfiltration', 'T1048 - Exfiltration Over Alternative Protocol', 'Detects creation of snapshot repositories pointing to external or attacker-controlled storage (S3, NFS, Azure, GCS). Attackers register external snapshot destinations to exfiltrate index data in bulk.

Next Steps:
1. Review the snapshot repository configuration and endpoint
2. Verify the repository URL/bucket is a legitimate company resource
3. Check what indices are included in snapshot operations
4. Remove unauthorized snapshot repositories
5. Restrict _snapshot API access to administrator accounts
6. Monitor outbound network traffic from the Elasticsearch cluster
', '["https://www.elastic.co/guide/en/elasticsearch/reference/current/snapshot-restore.html","https://attack.mitre.org/techniques/T1048/"]', 'exists("log.message") &&
(
  (contains("log.message", "_snapshot") && contains("log.message", "repository")) ||
