    contains("log.message", "s3://") ||
    contains("log.message", "gs://") ||
    contains("log.message", "azure://") ||
    contains("log.message", "hdfs://")
  )) ||
  (contains("log.message", "register repository") && exists("origin.ip"))
)
', '2026-02-09 16:37:05.306447', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (238, 'Elasticsearch Node Compromise Indicators', 3, 3, 3, 'Initial Access', 'System Compromise', 'Detects patterns indicating potential compromise of an Elasticsearch node, including authentication failures from unusual locations and critical errors.', '["https://www.elastic.co/guide/en/elasticsearch/reference/current/audit-event-types.html","https://attack.mitre.org/techniques/T1190/"]', '(equals("action", "authentication_failed") || equals("severity", "high")) && exists("origin.ip") && exists("log.nodeName")', '2026-02-09 16:37:05.446363', true, false, 'origin', null, '[{"indexPattern":"v11-log-elasticsearch-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"action","operator":"filter_term","value":"authentication_failed"}],"or":null,"within":"now-15m","count":5}]', '["lastEvent.log.nodeName","adversary.ip"]');
