', '2026-02-09 16:37:06.792023', true, false, 'origin', null, '[{"indexPattern":"v11-log-iis-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"target.path","operator":"filter_match","value":"169.254.169.254 OR localhost OR 127.0.0.1 OR metadata OR gopher://"}],"or":null,"within":"now-10m","count":3}]', '["adversary.ip","target.path"]');
