insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (265, 'MongoDB Collection Dropping Attempts', 1, 3, 3, 'Impact', 'Data Destruction', 'Detects attempts to drop collections or databases which could indicate destructive attacks or ransomware behavior. This includes drop commands for collections, databases, and indexes.

