', '2026-02-09 16:37:13.081506', true, false, 'origin', '["adversary.ip","adversary.path"]', '[{"indexPattern":"v11-log-nginx-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"log.statusCode","operator":"filter_term","value":"401"}],"or":[{"indexPattern":"v11-log-nginx-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"log.statusCode","operator":"filter_term","value":"403"}],"or":null,"within":"now-5m","count":10}],"within":"now-5m","count":10}]', null);
