  (contains("origin.path", "/etc/passwd") || contains("origin.path", "/etc/shadow")) ||
  (contains("origin.path", "windows/system32") || contains("origin.path", "win.ini"))
)
', '2026-02-09 16:37:13.226510', true, false, 'origin', null, '[{"indexPattern":"v11-log-nginx-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"origin.path","operator":"filter_match","value":"../ OR ..%2f OR %2e%2e OR etc/passwd OR win.ini"}],"or":null,"within":"now-10m","count":5}]', '["adversary.ip","target.ip"]');
