insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (291, 'Nginx HTTP Request Smuggling Detection', 3, 3, 2, 'Web Application Attack', 'T1190 - Exploit Public-Facing Application', 'Detects HTTP request smuggling and desync attacks targeting Nginx. These attacks exploit discrepancies between how front-end and back-end servers parse HTTP requests, potentially allowing cache poisoning, session hijacking, or security bypass.

Next Steps:
1. Review the request headers for conflicting Content-Length and Transfer-Encoding
2. Check for evidence of successful request smuggling in backend logs
3. Review Nginx and backend server configurations for parsing discrepancies
4. Implement strict HTTP parsing and reject ambiguous requests
5. Deploy a WAF with request smuggling detection capabilities
6. Block the source IP if confirmed malicious
', '["https://portswigger.net/web-security/request-smuggling","https://attack.mitre.org/techniques/T1190/"]', 'exists("origin.ip") &&
(
  (exists("log.request") && (
    regexMatch("log.request", "(?i)Transfer-Encoding:\\s*chunked.*Content-Length:") ||
    regexMatch("log.request", "(?i)Content-Length:.*Transfer-Encoding:\\s*chunked") ||
    regexMatch("log.request", "(?i)Transfer-Encoding:\\s*chunked\\s*,\\s*identity") ||
    contains("log.request", "Transfer-Encoding: chunked") ||
    contains("log.request", "Transfer-encoding: cow") ||
    contains("log.request", "Transfer-Encoding: xchunked") ||
    contains("log.request", "Transfer-Encoding : chunked") ||
    contains("log.request", "X-Forwarded-Host:") ||
    contains("log.request", "0\r\n\r\n")
  )) ||
  (exists("log.message") && (
    contains("log.message", "client sent duplicate") ||
    contains("log.message", "client sent both") ||
    contains("log.message", "client sent invalid") ||
    contains("log.message", "upstream sent invalid chunked")
  ))
)
', '2026-02-09 16:37:13.371487', true, false, 'origin', null, '[{"indexPattern":"v11-log-nginx-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-10m","count":3}]', '["adversary.ip","target.ip"]');
