Next Steps:
1. Review the request for internal IP addresses or metadata endpoint references
2. Check Nginx proxy_pass configuration for open redirect vulnerabilities
3. Verify that upstream backend restrictions are properly configured
4. Implement Host header validation in Nginx configuration
5. Block access to internal IP ranges and metadata endpoints
6. Block the source IP if confirmed malicious
', '["https://owasp.org/www-community/attacks/Server_Side_Request_Forgery","https://attack.mitre.org/techniques/T1090/"]', 'exists("origin.ip") &&
(
  (exists("origin.path") && (
    contains("origin.path", "169.254.169.254") ||
    contains("origin.path", "metadata.google.internal") ||
    regexMatch("origin.path", "(?i)@(127\\.0\\.0\\.1|localhost|10\\.|172\\.(1[6-9]|2[0-9]|3[01])\\.|192\\.168\\.)") ||
    regexMatch("origin.path", "(?i)https?://(127\\.0\\.0\\.1|localhost|0\\.0\\.0\\.0)") ||
    contains("origin.path", "file:///") ||
    contains("origin.path", "gopher://")
  )) ||
  (exists("log.request") && (
    regexMatch("log.request", "(?i)Host:\\s*(127\\.0\\.0\\.1|localhost|169\\.254\\.169\\.254|10\\.[0-9])") ||
    regexMatch("log.request", "(?i)X-Forwarded-Host:\\s*(127\\.0\\.0\\.1|localhost|169\\.254)")
  ))
)
', '2026-02-09 16:37:13.581789', true, false, 'origin', null, '[{"indexPattern":"v11-log-nginx-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"origin.path","operator":"filter_match","value":"169.254.169.254 OR localhost OR 127.0.0.1 OR metadata OR gopher://"}],"or":null,"within":"now-10m","count":3}]', '["adversary.ip","target.ip"]');
