insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (439, 'System Linux: Reverse Shell Created via Named Pipe', 3, 2, 3, 'Execution', 'T1059.004 - Command and Scripting Interpreter', 'Identifies a reverse shell via the abuse of named pipes on Linux with the help of OpenSSL or Netcat. First in, first out (FIFO) files are special files for reading and writing to by Linux processes. For this to work, a named pipe is created and passed to a Linux shell where the use of a network connection tool such as Netcat or OpenSSL has been established. The stdout and stderr are captured in the named pipe from the network connection and passed back to the shell for execution.', '["https://attack.mitre.org/tactics/TA0002/","https://attack.mitre.org/techniques/T1059/004/"]', 'regexMatch("log.message", "((sh|bash|openssl) (-i|-connect))") && exists("log.host.id")', '2026-02-09 16:51:30.007173', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
