)
', '2026-02-09 16:37:15.192156', true, false, 'origin', null, '[{"indexPattern":"v11-log-postgresql-*","with":[{"field":"target.host","operator":"filter_term","value":"{{target.host}}"}],"or":null,"within":"now-10m","count":3}]', '["lastEvent.log.sessionId","adversary.host"]');
