    contains("log.msg", "system(")
  ))
)
', '2026-02-09 16:37:15.351332', true, false, 'origin', null, '[{"indexPattern":"v11-log-postgresql-*","with":[{"field":"target.host","operator":"filter_term","value":"{{target.host}}"}],"or":null,"within":"now-10m","count":3}]', '["lastEvent.log.sessionId","adversary.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (304, 'PostgreSQL Privilege Escalation Attempt Detected', 3, 3, 2, 'Privilege Escalation', 'T1068 - Exploitation for Privilege Escalation', 'Detects attempts to escalate privileges in PostgreSQL through role manipulation, grant statements, security definer functions, or configuration changes. This includes attempts to grant superuser privileges, create security definer functions, modify system settings, or use dangerous extensions that could lead to privilege escalation.

Next Steps:
