', '["https://attack.mitre.org/techniques/T1078/","https://docs.fortinet.com/document/fortigate/7.4.1/fortios-log-message-reference/160372/list-of-log-types-and-subtypes"]', 'equals("log.logid", "0100032001") && 
equals("log.type", "event") && 
