exists("origin.ip") &&
exists("log.user")
', '2026-02-09 16:41:54.437750', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-fortigate-traffic-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"log.logdesc","operator":"filter_term","value":"Admin login failed"},{"field":"log.user","operator":"filter_term","value":"{{log.user}}"}],"or":null,"within":"now-15m","count":5}]', '["adversary.ip","target.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (368, 'Fortinet Antivirus Malware Outbreak Detection', 3, 3, 2, 'Initial Access', 'T1566 - Phishing', 'Detects potential malware outbreak when multiple antivirus detections occur from the same source or targeting multiple destinations in a short time period. This could indicate a widespread infection attempt or a compromised system attempting to spread malware.

Next Steps:
1. Identify the specific malware detected by reviewing the virus field in the alert details
2. Isolate the affected source IP addresses to prevent further spread
3. Check if the blocked malware attempts indicate successful infections on any endpoints
4. Review antivirus logs for the specific virus signature to understand the threat
5. Scan all systems that communicated with the identified source IPs
6. Update antivirus signatures and ensure all endpoints are protected
7. Consider blocking the source IP at the perimeter if it''s external
8. Document all affected systems and remediation actions taken
', '["https://docs.fortinet.com/document/fortigate/7.4.1/administration-guide/198726/antivirus","https://attack.mitre.org/techniques/T1566/"]', 'equals("log.type", "utm") && 
equals("log.subtype", "virus") && 
equals("action", "blocked") &&
(exists("origin.ip") || exists("target.ip"))
', '2026-02-09 16:41:54.583358', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-fortigate-traffic-*","with":[{"field":"log.type","operator":"filter_term","value":"utm"},{"field":"log.subtype","operator":"filter_term","value":"virus"},{"field":"action","operator":"filter_term","value":"blocked"}],"or":null,"within":"now-1h","count":5}]', '["adversary.ip","target.ip"]');
