  contains("log.message", "cross site scripting") ||
  contains("log.message", "Cross Site Scripting") ||
  contains("log.message", "xss") ||
  contains("log.message", "XSS") ||
  contains("log.message", "sqli") ||
  contains("log.message", "SQLi") ||
  equals("log.main_type", "SQL/XSS Syntax Based Detection")
)
', '2026-02-09 16:41:56.287116', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-fortiweb-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"action","operator":"filter_term","value":"deny"}],"or":null,"within":"now-15m","count":3}]', '["adversary.ip","target.ip"]');
