', '2026-02-09 16:41:57.882248', true, false, 'origin', null, '[]', '["lastEvent.log.headCommitId","lastEvent.log.repositoryName"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (392, 'GitHub Workflow pull_request_target Injection', 3, 3, 1, 'Supply Chain Compromise', 'T1195.001 - Supply Chain Compromise: Compromise Software Dependencies and Development Tools', 'Detects modifications to GitHub Actions workflow files that may introduce pull_request_target trigger abuse. This trigger runs with repository write permissions and secrets access even on forked PRs, making it a high-value target for supply chain attacks.

Next Steps:
1. Review the workflow file changes for pull_request_target trigger usage
2. Check if the workflow checks out PR head code (dangerous with pull_request_target)
3. Verify the committer is an authorized repository maintainer
4. Review the workflow for unsafe uses of PR title, body, or labels in script context
5. Check for recent fork-based PRs that could exploit the workflow
6. If malicious, revert the workflow change and review PR history
7. Implement branch protection requiring code review for workflow changes
8. Use workflow_run instead of pull_request_target where possible
', '["https://docs.github.com/en/actions/using-workflows/events-that-trigger-workflows#pull_request_target","https://attack.mitre.org/techniques/T1195/001/"]', '(equals("log.action", "workflows.completed_workflow_run") ||
 equals("log.action", "workflows.created_workflow_run")) &&
exists("log.senderLogin") &&
(contains("log.workflowFileName", "pull_request_target") ||
 contains("log.event", "pull_request_target"))
', '2026-02-09 16:41:58.042469', true, false, 'origin', null, '[]', '["lastEvent.log.repositoryName","lastEvent.log.senderLogin"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (393, 'GitHub Workflow Modifications Detected', 3, 3, 2, 'Initial Access', 'T1195.001 - Supply Chain Compromise: Compromise Software Dependencies and Development Tools', 'Detects modifications to GitHub Actions workflows which could be used to inject malicious code into the CI/CD pipeline or steal secrets. Attackers may modify workflows to execute arbitrary code, exfiltrate secrets, or compromise the software supply chain.

Next Steps:
1. Review the modified workflow files to identify any suspicious changes or additions
2. Check if the user who made the modifications has legitimate access and business justification
3. Look for any attempts to access secrets or environment variables in the workflow
4. Verify if any external actions or Docker images were added that could be malicious
5. Review commit history and pull request approvals for the workflow changes
6. Consider temporarily disabling the workflow if suspicious activity is confirmed
7. Audit repository access permissions and enable branch protection rules for workflow files
8. Check for any unusual timing of modifications (off-hours, weekends)
9. Verify the integrity of the repository and look for other suspicious activities
10. Review access logs for the user account that made the modifications
', '["https://docs.github.com/en/actions/using-workflows/events-that-trigger-workflows","https://attack.mitre.org/techniques/T1195/001/"]', '(equals("log.action", "workflows.updated") || 
 equals("log.action", "workflows.created") || 
 equals("log.action", "workflow_run.completed") ||
 equals("log.action", "workflow_dispatch")) &&
exists("log.repositoryName") &&
exists("log.senderLogin") &&
(contains("log.headCommitModified", ".github/workflows/") ||
 contains("log.headCommitAdded", ".github/workflows/") ||
 contains("log.path", ".github/workflows/") ||
 contains("log.filename", ".github/workflows/"))
', '2026-02-09 16:41:58.207656', true, false, 'origin', null, '[]', '["lastEvent.log.repositoryName","lastEvent.log.senderLogin"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (396, 'IBM AIX NIM Master Exploitation Detection', 3, 3, 3, 'Lateral Movement', 'T1210 - Exploitation of Remote Services', 'Detects exploitation of IBM AIX Network Installation Management (NIM) master to deploy malicious packages, modify client configurations, or perform lateral movement across AIX infrastructure.

Next Steps:
1. Verify the NIM operations were authorized
2. Review NIM client configurations for unauthorized changes
3. Check for malicious LPP/installp packages in NIM resources
4. Verify NIM master access controls
5. Review NIM client machine definitions
