insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (394, 'IBM AIX Unauthorized Crontab Modification Detection', 2, 3, 2, 'Persistence', 'T1053.003 - Scheduled Task/Job: Cron', 'Detects unauthorized crontab modifications on IBM AIX systems that could indicate persistence establishment by an attacker. Monitors for crontab changes, at job submissions, and modifications to /var/spool/cron.

Next Steps:
1. Review the crontab entries that were added or modified
2. Verify the user account making the changes
3. Check the scheduled commands for malicious payloads
4. Review /var/spool/cron for all user crontabs
5. Implement cron.allow/cron.deny restrictions
6. Monitor execution of suspicious scheduled tasks
', '["https://www.ibm.com/docs/en/aix/7.2?topic=c-crontab-command","https://attack.mitre.org/techniques/T1053/003/"]', 'exists("log.message") &&
(
  (contains("log.message", "crontab") && (
    contains("log.message", "EDIT") ||
    contains("log.message", "REPLACE") ||
    contains("log.message", "-e") ||
    contains("log.message", "installed")
