  (contains("log.message", "/var/spool/cron") && (
    contains("log.message", "modified") ||
    contains("log.message", "created") ||
    contains("log.message", "changed")
  )) ||
  (contains("log.message", "at ") && contains("log.message", "job")) ||
  (contains("log.message", "cron") && contains("log.message", "CMD") && (
    contains("log.message", "/tmp/") ||
    contains("log.message", "wget") ||
    contains("log.message", "curl") ||
    contains("log.message", "bash -c") ||
    contains("log.message", "python")
  ))
)
', '2026-02-09 16:47:09.477618', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (395, 'IBM AIX Unauthorized HMC Access Detection', 3, 3, 3, 'Unauthorized Access', 'T1078 - Valid Accounts', 'Detects unauthorized access to the IBM Hardware Management Console (HMC) that controls Power Systems hardware. HMC access allows management of LPARs, firmware, and hardware resources.

Next Steps:
1. Verify the HMC access was from an authorized administrator
2. Review the HMC operations performed during the session
3. Check for LPAR configuration changes
4. Verify HMC user accounts and access controls
5. Review HMC audit logs for additional suspicious activity
6. Implement multi-factor authentication for HMC access
', '["https://www.ibm.com/docs/en/power9?topic=console-hardware-management","https://attack.mitre.org/techniques/T1078/"]', 'exists("log.message") &&
(
  (contains("log.message", "HMC") && (
    contains("log.message", "login") ||
    contains("log.message", "authentication") ||
    contains("log.message", "session")
  )) ||
  (contains("log.message", "hmcshutdown") || contains("log.message", "hmcrestart")) ||
  contains("log.message", "chsyscfg") ||
  (contains("log.message", "lpar") && (
    contains("log.message", "activate") ||
    contains("log.message", "shutdown") ||
    contains("log.message", "migrate")
  )) ||
  (contains("log.message", "Power Systems") && contains("log.message", "remote access"))
)
', '2026-02-09 16:47:09.612632', true, false, 'origin', null, '[{"indexPattern":"v11-log-ibm-aix-*","with":[{"field":"origin.host","operator":"filter_term","value":"{{origin.host}}"}],"or":null,"within":"now-30m","count":3}]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (397, 'IBM AIX Rootkit Indicator Detection', 3, 3, 3, 'Defense Evasion', 'T1014 - Rootkit', 'Detects AIX-specific rootkit indicators including hidden processes, modified system binaries, suspicious kernel extensions, and integrity violations in the Trusted Computing Base.

Next Steps:
1. Run trustchk command to verify system binary integrity
2. Compare running processes with ps output for hidden processes
3. Check for modified shared libraries in /usr/lib
4. Review recently loaded kernel extensions
5. Initiate forensic investigation on the affected system
6. Consider rebuilding the system from trusted media
', '["https://www.ibm.com/docs/en/aix/7.2?topic=security-trusted-computing-base","https://attack.mitre.org/techniques/T1014/"]', 'exists("log.message") &&
(
  (contains("log.message", "trustchk") && contains("log.message", "FAIL")) ||
  (contains("log.message", "tcbck") && contains("log.message", "violation")) ||
  (contains("log.message", "TCB") && contains("log.message", "integrity")) ||
  (contains("log.message", "genkex") && contains("log.message", "unknown")) ||
  (contains("log.message", "/dev/kmem") && !equals("origin.user", "root")) ||
  (contains("log.message", "ld.so") && contains("log.message", "preload")) ||
  (contains("log.message", "LIBPATH") && contains("log.message", "modified")) ||
  contains("log.message", "LD_PRELOAD")
)
', '2026-02-09 16:47:09.917960', true, false, 'origin', null, '[]', '["adversary.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (398, 'IBM AIX SSH Authorized Keys Manipulation Detection', 3, 3, 1, 'Persistence', 'T1098.004 - Account Manipulation: SSH Authorized Keys', 'Detects modifications to SSH authorized_keys files on IBM AIX systems. Attackers add their SSH public keys to maintain persistent access to compromised systems.

Next Steps:
1. Review the authorized_keys file changes
2. Verify the added SSH keys belong to authorized users
3. Check which user accounts had keys modified
4. Remove unauthorized SSH keys immediately
5. Implement SSH key management policies
6. Monitor for SSH connections using the new keys
', '["https://www.ibm.com/docs/en/aix/7.2?topic=security-configuring-openssh","https://attack.mitre.org/techniques/T1098/004/"]', 'exists("log.message") &&
(
  (contains("log.message", "authorized_keys") && (
    contains("log.message", "modified") ||
    contains("log.message", "changed") ||
    contains("log.message", "written") ||
    contains("log.message", "appended")
  )) ||
  (contains("log.message", ".ssh/authorized_keys") && exists("origin.user")) ||
  (contains("log.message", "ssh-rsa") && (
    contains("log.message", ">>") ||
    contains("log.message", "echo")
  )) ||
  (contains("log.message", "sshd_config") && contains("log.message", "AuthorizedKeysFile"))
)
', '2026-02-09 16:47:10.048060', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (399, 'IBM AIX Intrusion Detection Alert', 3, 3, 2, 'Privilege Escalation', 'T1068 - Exploitation for Privilege Escalation', 'Detects intrusion attempts and security violations identified by the IBM AIX intrusion detection system, including suspicious activities, privilege escalation attempts, and potential system compromises.

Next Steps:
1. Immediately isolate the affected system from the network to prevent lateral movement
2. Review the intrusion detection logs for specific details about the attack vector and affected resources
3. Check for any suspicious processes running with elevated privileges using ''ps aux'' and ''topas''
4. Examine system integrity with ''trustchk'' command to verify critical system files
5. Review recent user authentication logs and check for unauthorized account creation or privilege changes
6. Collect forensic evidence including memory dumps, system logs, and file modifications
7. Apply security patches and update AIX security configurations based on the vulnerability exploited
8. Monitor related systems for similar intrusion attempts
9. Check for any unauthorized file modifications using ''find'' command with modification time filters
10. Review network connections and active ports using ''netstat'' and ''lsof'' commands
11. Validate system configuration against security baselines and hardening guides
12. Document the incident details and update security monitoring rules based on attack patterns
', '["https://www.ibm.com/docs/en/powersc-standard/2.1.0?topic=ids-configuring-intrusion-detection-prevention-idp-aix-endpoints","https://attack.mitre.org/techniques/T1068/"]', '(
  equals("log.eventType", "ids") ||
  equals("log.eventType", "securityd") ||
  equals("log.eventType", "audit") ||
  contains("log.msg", "intrusion") ||
  contains("log.msg", "suspicious") ||
  contains("log.msg", "anomaly detected")
) && 
(
  contains("log.msg", "buffer overflow") ||
  contains("log.msg", "privilege escalation") ||
  contains("log.msg", "unauthorized modification") ||
  contains("log.msg", "rootkit") ||
  contains("log.msg", "backdoor") ||
  contains("log.msg", "suspicious process") ||
  contains("log.msg", "file integrity") ||
  contains("action", "ALERT") ||
  equals("log.returnCode", "1")
)
', '2026-02-09 16:47:10.192353', true, false, 'origin', null, '[]', '["target.host","target.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (400, 'IBM AIX Security Audit Subsystem Alert', 3, 3, 2, 'Defense Evasion', 'T1562.001 - Impair Defenses: Disable or Modify Tools', 'Detects critical security events from the IBM AIX audit subsystem, including audit configuration changes, audit service disruptions, or attempts to tamper with audit logs. This rule identifies when the audit subsystem fails, is disabled, or when audit-related files are modified.

Next Steps:
1. Verify the legitimacy of the audit subsystem changes with the system administrator
2. Check if this is part of scheduled maintenance or authorized configuration changes
3. Review the specific audit event type and return code for failure details
4. Examine the user account that performed the action and verify it has appropriate permissions
5. Investigate any recent changes to audit policies or configurations
6. Check for additional security events around the same time period
7. Verify audit log integrity and ensure no logs have been tampered with
8. Review system logs for any other indicators of compromise
', '["https://www.ibm.com/support/pages/aix-audit-audit-subsystem-aix","https://attack.mitre.org/techniques/T1562/"]', '(startsWith("log.eventType", "audit") && !equals("log.returnCode", "0")) || (contains("log.message", "audit") && (contains("log.message", "stop") || contains("log.message", "disable") || contains("log.message", "fail"))) || (equals("action", "FILE_MODIFY") && startsWith("log.objName", "/etc/security/audit/")) || (equals("log.commandType", "audit"))', '2026-02-09 16:47:10.337560', true, false, 'origin', null, '[]', '["lastEvent.log.eventType","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (401, 'IBM AIX System Integrity Violation Detected', 2, 3, 2, 'Defense Evasion', 'T1070 - Indicator Removal on Host', 'Detects attempts to compromise system integrity in IBM AIX, including unauthorized modifications to critical system files, audit tampering, security configuration changes, and privilege escalation attempts. This rule monitors for various indicators of system compromise including audit event tampering, security configuration file modifications, suspicious sudo usage, and privilege escalation attempts.

Next Steps:
1. Immediately investigate the affected system and user account
2. Review audit logs for related suspicious activities
3. Check for unauthorized changes to system configuration files
4. Verify the legitimacy of any privilege escalation attempts
5. Monitor for additional indicators of compromise
6. Consider isolating the affected system if malicious activity is confirmed
7. Review backup and recovery procedures for critical system files
8. Examine command history and process execution logs
9. Validate user permissions and access controls
10. Check for presence of unauthorized tools or backdoors
', '["https://www.ibm.com/docs/en/ssw_aix_72/security/security_pdf.pdf","https://attack.mitre.org/techniques/T1070/"]', '(contains("log.eventType", "AUD_") && equals("action", "FILE_Write")) || (contains("log.objName", "/etc/security/") && equals("action", "FILE_Write")) || (equals("log.commandType", "sudo") && contains("origin.command", "passwd")) || (contains("log.msg", "audit") && contains("log.msg", "disable")) || (equals("log.osUserID", "root") && !equals("origin.user", "root"))', '2026-02-09 16:47:10.681940', true, false, 'origin', null, '[]', '["lastEvent.log.objName","adversary.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (402, 'IBM AIX Trusted Computing Base Violation', 3, 3, 2, 'Defense Evasion', 'T1070 - Indicator Removal', 'Detects violations of the Trusted Computing Base (TCB) in IBM AIX, including unauthorized modifications to critical system files, security database tampering, or attempts to modify files protected by TCB. TCB violations indicate potential system compromise or unauthorized privilege escalation attempts.

Next Steps:
1. Immediately investigate the user account and source host involved in the TCB violation
2. Review the specific object/file that was modified and assess the impact
3. Check system logs for any related authentication failures or privilege escalation attempts
4. Verify the integrity of critical system files using tcbck command
5. Review recent system changes and patches that might have triggered legitimate TCB events
6. If malicious activity is confirmed, isolate the affected system and initiate incident response procedures
7. Consider running a full system integrity check and malware scan
', '["https://www.ibm.com/docs/en/aix/7.2?topic=configuration-trusted-computing-base","https://attack.mitre.org/techniques/T1070/"]', '(equals("log.eventType", "tcbck") && contains("log.message", "FAIL")) || (contains("log.message", "TCB") && (contains("log.message", "violation") || contains("log.message", "modified"))) || (equals("log.eventType", "FILE_Mode") && exists("log.objName") && startsWith("log.objName", "/etc/security/")) || (equals("action", "FILE_MODIFY") && exists("log.objName") && (startsWith("log.objName", "/usr/bin/") || startsWith("log.objName", "/usr/sbin/") || startsWith("log.objName", "/etc/security/")))', '2026-02-09 16:47:10.802736', true, false, 'origin', null, '[]', '["lastEvent.log.objName","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (403, 'IBM AIX Trusted Execution Violation', 3, 3, 2, 'Defense Evasion', 'T1036 - Masquerading', 'Detects violations of Trusted Execution (TE) policies in IBM AIX, including execution of untrusted binaries, signature verification failures, or attempts to bypass trusted execution controls. These violations may indicate attempts to execute malicious or unauthorized code on the system.

Next Steps:
1. Immediately verify the integrity of the executed binary and its digital signature
2. Check if the binary is from a trusted source or has been tampered with
3. Review system logs for any concurrent privilege escalation attempts or suspicious activities
4. Examine the user''s recent activities, access patterns, and authentication history
5. Validate the system''s trusted execution configuration and policies are properly enforced
6. Check for any recent changes to the trusted execution database or policies
7. Analyze the source and nature of the untrusted binary or process
8. Consider isolating the affected system if malicious activity is confirmed
9. Review file system integrity and check for signs of compromise
10. Escalate to security team if this appears to be part of a broader attack
', '["https://www.ibm.com/support/pages/trusted-execution-enablement","https://attack.mitre.org/techniques/T1036/"]', '(equals("log.eventType", "trustchk") && !equals("log.returnCode", "0")) || (contains("log.msg", "Trusted Execution") && (contains("log.msg", "fail") || contains("log.msg", "violat"))) || (equals("log.eventType", "PROC_Execute") && contains("log.msg", "untrusted")) || (equals("action", "EXEC") && contains("log.objName", "/tmp/") && equals("origin.user", "root"))', '2026-02-09 16:47:10.933106', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (404, 'IBM AS/400 Audit Journal Disabling Detection', 2, 3, 1, 'Defense Evasion', 'T1562.002 - Impair Defenses: Disable Windows Event Logging', 'Detects attempts to disable or modify IBM AS/400 security auditing via CHGAUD, QAUDCTL, or QAUDLVL system value changes. Attackers disable auditing to cover their tracks.

Next Steps:
1. Verify the audit configuration change was authorized
2. Re-enable auditing immediately if unauthorized
3. Check QAUDJRN journal for recent entries before the change
4. Review system activity during the audit gap
5. Restrict CHGAUD and system value change authority
6. Implement monitoring for audit control system values
', '["https://www.ibm.com/docs/en/i/7.5?topic=auditing-changing-security","https://attack.mitre.org/techniques/T1562/002/"]', 'exists("log.message") &&
(
  contains("log.message", "CHGAUD") ||
  (contains("log.message", "QAUDCTL") && contains("log.message", "*NONE")) ||
  (contains("log.message", "QAUDLVL") && contains("log.message", "changed")) ||
  (contains("log.message", "QAUDLVL2") && contains("log.message", "changed")) ||
  (contains("log.message", "audit") && contains("log.message", "disabled")) ||
  (contains("log.message", "QAUDJRN") && contains("log.message", "DLTJRN")) ||
  contains("log.message", "CHGSYSVAL SYSVAL(QAUDCTL) VALUE(''*NONE'')")
)
', '2026-02-09 16:47:11.062849', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (405, 'IBM AS/400 Unauthorized IFS Access Detection', 3, 2, 1, 'Collection', 'T1005 - Data from Local System', 'Detects unauthorized access to the IBM AS/400 Integrated File System (IFS). Monitors for access to sensitive directories, configuration files, and bulk file operations that could indicate data theft.

Next Steps:
1. Review the IFS paths and files being accessed
2. Verify the user has authorization for the accessed directories
3. Check for bulk file downloads or copies
4. Review NetServer and FTP access logs
5. Restrict IFS directory permissions
6. Implement IFS object auditing for sensitive directories
', '["https://www.ibm.com/docs/en/i/7.5?topic=system-integrated-file","https://attack.mitre.org/techniques/T1005/"]', 'exists("log.message") &&
(
  (contains("log.message", "IFS") && (
    contains("log.message", "QSYS.LIB") ||
    contains("log.message", "/QIBM/") ||
    contains("log.message", "/home/") ||
    contains("log.message", "/tmp/")
  ) && (
    contains("log.message", "access") ||
    contains("log.message", "read") ||
    contains("log.message", "copy") ||
    contains("log.message", "download")
  )) ||
  (contains("log.message", "CPYFRMSTMF") || contains("log.message", "CPYTOSTMF")) ||
  (contains("log.message", "NetServer") && contains("log.message", "file access")) ||
  (contains("log.message", "FTP") && contains("log.message", "GET") && contains("log.message", "/QSYS"))
)
', '2026-02-09 16:47:11.207711', true, false, 'origin', null, '[{"indexPattern":"v11-log-ibm-as400-*","with":[{"field":"log.message","operator":"filter_match","value":"IFS OR CPYFRMSTMF OR CPYTOSTMF OR NetServer"}],"or":null,"within":"now-15m","count":10}]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (406, 'IBM AS/400 Exit Point Tampering Detection', 3, 3, 2, 'Persistence', 'T1562 - Impair Defenses', 'Detects tampering with IBM AS/400 exit points using ADDEXITPGM to register malicious programs. Exit points intercept system operations and can be used for credential capture, data interception, or persistent backdoor access.

Next Steps:
1. Review the exit point program being registered
2. Verify the exit point registration was authorized
3. Check the program source code for malicious functionality
4. List all registered exit points with WRKREGINF
5. Remove unauthorized exit point programs
6. Restrict ADDEXITPGM authority to security administrators
', '["https://www.ibm.com/docs/en/i/7.5?topic=programs-exit","https://attack.mitre.org/techniques/T1562/"]', 'exists("log.message") &&
(
  contains("log.message", "ADDEXITPGM") ||
  contains("log.message", "RMVEXITPGM") ||
  contains("log.message", "CHGEXITPGM") ||
  (contains("log.message", "exit point") && (
    contains("log.message", "registered") ||
    contains("log.message", "added") ||
    contains("log.message", "changed")
  )) ||
  (contains("log.message", "WRKREGINF") && contains("log.message", "exit"))
)
