(
  (contains("log.message", "SQL") && (
    regexMatch("log.message", "(?i)UNION\\s+(ALL\\s+)?SELECT") ||
    contains("log.message", "'' OR ''1''=''1") ||
    contains("log.message", "''; DROP") ||
