    contains("log.message", "SYSCOLUMNS") ||
    contains("log.message", "SYSTABLES") ||
    regexMatch("log.message", "(?i)CHAR\\s*\\([0-9]+\\)") ||
    contains("log.message", "information_schema")
  )) ||
  (contains("log.message", "ODBC") && contains("log.message", "SQL error")) ||
  (contains("log.message", "JDBC") && contains("log.message", "syntax error"))
)
