  regexMatch("raw", "(?i)\"alg\"\\s*:\\s*\"None\"") ||
  regexMatch("raw", "(?i)\"alg\"\\s*:\\s*\"NONE\"") ||
  regexMatch("raw", "(?i)\"alg\"\\s*:\\s*\"nOnE\"") ||
  (contains("raw", "\"alg\"") && contains("raw", "\"HS256\"") && contains("raw", "\"kid\"")) ||
  (contains("raw", "eyJ") && contains("raw", "\"alg\":\"none\"")) ||
  regexMatch("raw", "(?i)\"alg\"\\s*:\\s*\"HS(256|384|512)\".*\"jku\"") ||
  (contains("raw", "\"jwk\"") && contains("raw", "\"kty\"") && contains("raw", "\"n\""))
)
', '2026-02-09 16:47:13.577157', true, false, 'origin', null, '[]', '["adversary.ip","target.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (422, 'System Linux: Attempt to Disable Syslog Service', 1, 2, 3, 'Defense Evasion', 'T1562.001 - Impair Defenses', 'Adversaries may attempt to disable the syslog service in an attempt to an attempt to disrupt event logging and evade detection by security controls.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1562/001/"]', 'regexMatch("log.message", "((service|chkconfig) (syslog|rsyslog|syslog-ng) (stop|disable|off|kill))|((systemctl) (stop|disable|off|kill) (syslog|rsyslog|syslog-ng))")', '2026-02-09 16:51:27.253055', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (423, 'System Linux: Possible Brute Force Attack', 2, 2, 3, 'Credential Access', 'T1110 - Brute Force', 'Identifies multiple SSH login failures followed by a successful one from the same source address. Adversaries can attempt to login into multiple users with a common or known password to gain access to accounts.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1110/"]', 'equals("action", "system.auth") && regexMatch("log.message", "([Ss]ession opened)") && exists("origin.user") && exists("log.hostId")', '2026-02-09 16:51:27.447937', true, false, 'origin', null, '[{"indexPattern":"v11-log-linux-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"log.hostId","operator":"filter_term","value":"{{log.hostId}}"},{"field":"log.message","operator":"filter_match","value":"Failed password"}],"or":[{"indexPattern":"v11-log-linux-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"log.hostId","operator":"filter_term","value":"{{log.hostId}}"},{"field":"log.message","operator":"filter_match","value":"authentication failure"}],"or":null,"within":"now-15m","count":10}],"within":"now-15m","count":10}]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (424, 'System Linux: File made Immutable by Chattr', 1, 2, 3, 'Defense Evasion', 'T1222 - File and Directory Permissions Modification', 'Detects a file being made immutable using the chattr binary.  Making a file immutable means it cannot be deleted or renamed, no link can be created to this file,  most of the file is metadata can not be modified, and the file can not be opened in write mode.  Threat actors will commonly utilize this to prevent tampering or modification of their malicious  files or any system files they have modified for purposes of persistence', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1222/"]', 'regexMatch("log.message", "(chattr (\\+|-)i )")', '2026-02-09 16:51:27.607761', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (425, 'System Linux: Potential Disabling of SELinux', 1, 2, 3, 'Defense Evasion', 'T1562.001 - Impair Defenses', 'Identifies potential attempts to disable Security-Enhanced Linux (SELinux), which is a Linux kernel security feature to support access control policies. Adversaries may disable security tools to avoid possible detection of their tools and activities.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1562/001/"]', 'contains("log.message", "setenforce 0")', '2026-02-09 16:51:27.767571', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (426, 'System Linux: File Deletion via Shred', 1, 2, 3, 'Defense Evasion', 'T1070.004 - Indicator Removal', 'Malware or other files dropped or created on a system by an adversary may leave traces behind as to what was done within a network and how. Adversaries may remove these files over the course of an intrusion to keep their footprint low or remove them at the end as part of the post-intrusion cleanup process.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1070/004/"]', 'regexMatch("log.message", "(shred (-u|--remove|-z|--zero))")', '2026-02-09 16:51:27.927342', true, false, 'target', null, '[]', '["target.ip","target.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (427, 'System Linux: File Transfer or Listener Established via Netcat', 1, 2, 3, 'Execution', 'T1059.004 - Command and Scripting Interpreter', 'A netcat process is engaging in network activity on a Linux host. Netcat is often used as a persistence mechanism by exporting a reverse shell or by serving a shell on a listening port. Netcat is also sometimes used for data exfiltration.', '["https://attack.mitre.org/tactics/TA0002/","https://attack.mitre.org/techniques/T1059/004/"]', 'regexMatch("log.message", "((nc|ncat|netcat|netcat.openbsd|netcat.traditional) (-l|-p|-lp|(-e)(.+)(\\/bin\\/bash|\\/bin\\/sh)|(\\/bin\\/bash|\\/bin\\/sh)(.+)(-e)))")', '2026-02-09 16:51:28.087929', true, false, 'target', null, '[]', '["target.ip","target.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (428, 'System Linux: Kernel module load via insmod', 3, 3, 3, 'Persistence', 'T1547.006 - Boot or Logon Autostart Execution', 'Detects the use of the insmod binary to load a Linux kernel object file. Threat actors can use this binary, given they have root privileges,  to load a rootkit on a system providing them with complete control and the ability to hide from security products.  Manually loading a kernel module in this manner should not be at all common and can indicate suspcious or malicious behavior.', '["https://attack.mitre.org/tactics/TA0003/","https://attack.mitre.org/techniques/T1547/006/"]', 'regexMatch("log.message", "(insmod (.+).ko)")', '2026-02-09 16:51:28.247471', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (429, 'System Linux: Persistence via KDE AutoStart Script or Desktop File Modification', 2, 2, 3, 'Persistence', 'T1547 - Boot or Logon Autostart Execution', 'Identifies the creation or modification of a K Desktop Environment (KDE) AutoStart script or desktop file that will execute upon each user logon. Adversaries may abuse this method for persistence.', '["https://attack.mitre.org/tactics/TA0003/","https://attack.mitre.org/techniques/T1547/"]', 'regexMatch("log.message", "sh,desktop") && regexMatch("log.message", "(/home/(.+)/.config/autostart/|/root/.config/autostart/|/home/(.+)/.kde/Autostart/|/root/.kde/Autostart/|/home/(.+)/.kde4/Autostart/|/root/.kde4/Autostart/|/home/(.+)/.kde/share/autostart/|/root/.kde/share/autostart/|/home/(.+)/.kde4/share/autostart/|/root/.kde4/share/autostart/|/home/(.+)/.local/share/autostart/|/root/.local/share/autostart/|/home/(.+)/.config/autostart-scripts/|/root/.config/autostart-scripts/|/etc/xdg/autostart/|/usr/share/autostart/)") && !regexMatch("log.message", "(yum|dpkg|install|dnf|teams|yum-cron|dnf-automatic)")', '2026-02-09 16:51:28.407930', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (444, 'User Added to Admin Group via dscl', 3, 3, 2, 'Privilege Escalation', 'T1078.003 - Valid Accounts: Local Accounts', 'Detects the use of dscl to add a user to the admin group on macOS. This is a privilege escalation technique where attackers grant themselves or a compromised account administrative privileges to gain elevated access to the system.

Next Steps:
1. Identify which user was added to the admin group and by whom
2. Verify if the change was authorized by IT administration
3. Check for other privilege modifications on the same system
4. Review the user''s recent activity for signs of compromise
5. Remove unauthorized admin group membership immediately
6. Audit all admin group members across macOS endpoints
', '["https://attack.mitre.org/techniques/T1078/003/","https://github.com/SigmaHQ/sigma/blob/master/rules/macos/process_creation/proc_creation_macos_dscl_add_user_to_admin_group.yml"]', 'contains("log.eventMessage", "dscl") &&
contains("log.eventMessage", "-append") &&
contains("log.eventMessage", "/Groups/admin") &&
contains("log.eventMessage", "GroupMembership")
', '2026-02-09 16:52:18.727537', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (445, 'Suspicious Browser Child Process on macOS', 3, 3, 2, 'Initial Access', 'T1189 - Drive-by Compromise', 'Detects web browsers (Safari, Chrome, Firefox) spawning suspicious child processes such as bash, curl, wget, python, or osascript. This behavior indicates potential browser exploitation, drive-by download, or malicious content execution. Legitimate browsers rarely spawn shell interpreters or download utilities directly.

Next Steps:
1. Identify the browser tab or URL that triggered the child process
2. Capture the full command line of the spawned child process
3. Check browser history and downloads around the time of the event
4. Examine the system for downloaded payloads or persistence mechanisms
5. Scan the system for malware and check for additional exploitation indicators
6. Review browser extensions for malicious or compromised add-ons
', '["https://attack.mitre.org/techniques/T1189/","https://attack.mitre.org/techniques/T1203/","https://github.com/SigmaHQ/sigma/blob/master/rules/macos/process_creation/proc_creation_macos_susp_browser_child_process.yml"]', 'contains("log.eventMessage", ["/Applications/Safari.app", "/Applications/Google Chrome.app", "/Applications/Firefox.app", "com.apple.Safari", "com.google.Chrome", "org.mozilla.firefox"]) &&
contains("log.eventMessage", ["bash", "sh ", "curl ", "wget ", "python", "osascript", "perl ", "ruby "]) &&
(
  contains("log.eventMessage", "spawn") ||
  contains("log.eventMessage", "exec") ||
  contains("log.eventMessage", "fork") ||
  contains("log.eventMessage", "child process")
)
', '2026-02-09 16:52:18.848182', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (446, 'Apple Script Abuse Detection', 3, 3, 2, 'Execution', 'T1059.002 - Command and Scripting Interpreter: AppleScript', 'Detects suspicious AppleScript execution that could indicate malicious activity, including osascript command-line usage, automation attempts, and script-based attacks on macOS systems. AppleScript can be abused by attackers to execute commands, interact with applications, and perform system manipulation.

Next Steps:
1. Review the specific AppleScript commands being executed
2. Check if the script execution is part of legitimate automation or suspicious activity
3. Examine the process tree to understand the execution context
4. Verify if the user executing the script has legitimate reasons to do so
5. Look for additional indicators of compromise on the affected system
6. Consider blocking or monitoring the source if malicious intent is confirmed
', '["https://attack.mitre.org/techniques/T1059/002/","https://developer.apple.com/documentation/os/logging","https://www.crowdstrike.com/en-us/blog/how-to-leverage-apple-unified-log-for-incident-response/"]', '(oneOf("log.process", ["osascript", "Script Editor", "AppleScript", "Automator"]) ||
 contains("log.eventMessage", "osascript") ||
 contains("log.eventMessage", "AppleScript") ||
 equals("log.subsystem", "com.apple.applescript")) &&
(contains("log.eventMessage", "tell application") ||
 contains("log.eventMessage", "do shell script") ||
 contains("log.eventMessage", "keystroke") ||
 contains("log.eventMessage", "System Events") ||
 contains("log.eventMessage", "admin privileges") ||
 contains("log.eventMessage", "sudo") ||
 contains("log.eventMessage", "password")) &&
oneOf("log.eventType", ["logEvent", "traceEvent"])
', '2026-02-09 16:52:19.012354', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (447, 'macOS Cron Job Persistence', 2, 3, 1, 'Persistence', 'T1053.003 - Scheduled Task/Job: Cron', 'Detects crontab modifications on macOS systems. Although cron is deprecated on macOS in favor of launchd, attackers still use it for persistence as it is less commonly monitored.

Next Steps:
1. Review the crontab entry for suspicious commands
2. Check the user account that modified the crontab
3. Verify the scheduled command is not downloading or executing malware
4. Remove unauthorized cron entries
5. Check for other persistence mechanisms
', '["https://attack.mitre.org/techniques/T1053/003/"]', '(contains("log.eventMessage", "crontab") || equals("log.process", "cron")) &&
(contains("log.eventMessage", "REPLACE") || contains("log.eventMessage", "INSTALL") ||
 contains("log.eventMessage", "BEGIN EDIT") || contains("log.eventMessage", "END EDIT") ||
 contains("log.eventMessage", "crontab") && contains("log.eventMessage", "modified"))
', '2026-02-09 16:52:19.167469', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (448, 'Dynamic Library Hijacking Detected', 3, 3, 2, 'Persistence', 'T1574.004 - Hijack Execution Flow: Dylib Hijacking', 'Detects dynamic library (dylib) hijacking on macOS where attackers place malicious dylibs in locations searched before legitimate libraries, allowing code execution in the context of trusted applications.

Next Steps:
1. Identify the application loading the suspicious dylib
2. Check the dylib''s code signature and notarization status
3. Compare the dylib path against expected library locations
4. Verify the dylib hash against known-good versions
5. Check for weak dylib references using otool
6. Remove the malicious dylib and investigate the delivery method
', '["https://attack.mitre.org/techniques/T1574/004/","https://objective-see.org/blog/blog_0x46.html"]', '(contains("log.eventMessage", "dylib") || contains("log.eventMessage", "DYLD")) &&
(contains("log.eventMessage", "hijack") || contains("log.eventMessage", "suspicious") ||
 contains("log.eventMessage", "unsigned") || contains("log.eventMessage", "load failed") ||
 (contains("log.eventMessage", "DYLD_INSERT_LIBRARIES") && contains("log.eventMessage", "set")) ||
 regexMatch("log.eventMessage", "(?i)dylib.*(/tmp/|/Users/.*/Downloads/|/var/tmp/)"))
', '2026-02-09 16:52:19.323030', true, false, 'origin', null, '[]', '["lastEvent.log.eventMessage","adversary.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (670, 'Windows: Process Activity via Compiled HTML File', 3, 3, 1, 'Execution', 'T1204.002 - User Execution: Malicious File', 'Compiled HTML files (.chm) are commonly distributed as part of the Microsoft HTML Help system. Adversaries may conceal malicious code in a CHM file and deliver it to a victim for execution. CHM content is loaded by the HTML Help executable program (hh.exe).', '["https://attack.mitre.org/tactics/TA0002/","https://attack.mitre.org/techniques/T1204/002/"]', 'regexMatch("log.winlogEventDataProcessName", "(mshta.exe|cmd.exe|powershell.exe|pwsh.exe|powershell_ise.exe|cscript.exe|wscript.exe)") && regexMatch("log.winlogEventDataParentProcessName", "hh.exe")', '2026-02-09 16:57:25.167481', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (449, 'Endpoint Security Framework Bypass Attempt', 3, 3, 3, 'Defense Evasion', 'T1562.001 - Impair Defenses: Disable or Modify Tools', 'Detects attempts to bypass or tamper with the macOS Endpoint Security framework, which could indicate malicious activity trying to evade security monitoring. The Endpoint Security framework is a critical component for system security monitoring and its compromise can allow attackers to operate undetected.

Next Steps:
1. Investigate the affected system and identify the process attempting to bypass endpoint security
2. Check for suspicious process executions or file modifications around the time of the alert
3. Verify if any legitimate security tools were recently installed or updated
4. Review system logs for other indicators of compromise
5. Consider isolating the affected system if malicious activity is confirmed
6. Check for persistence mechanisms that might be attempting to disable security controls
', '["https://attack.mitre.org/techniques/T1562/001/","https://developer.apple.com/documentation/endpointsecurity"]', '(equals("log.subsystem", "com.apple.endpointsecurity") ||
 contains("log.process", "EndpointSecurity") ||
 contains("log.message", "ES_EVENT_TYPE")) &&
(contains("log.message", "bypass") ||
 contains("log.message", "failed authorization") ||
 contains("log.message", "client disconnected") ||
 contains("log.message", "authorization denied") ||
 contains("log.message", "invalid client") ||
 contains("log.message", "ES_RETURN_ERROR") ||
 equals("log.eventType", "error") ||
 contains("log.message", "memory leak detected"))
', '2026-02-09 16:52:19.652597', true, false, 'origin', null, '[{"indexPattern":"v11-log-macos-*","with":[{"field":"system.hostname","operator":"filter_term","value":"{{system.hostname}}"}],"or":null,"within":"now-15m","count":2}]', '["lastEvent.log.process","lastEvent.system.hostname"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (450, 'Folder Actions Script Abuse', 2, 3, 1, 'Persistence', 'T1546.002 - Event Triggered Execution: Screensaver', 'Detects abuse of macOS Folder Actions to establish persistence. Folder Actions allow scripts to be attached to folders and execute when files are added, providing a stealthy persistence mechanism.

Next Steps:
1. Review the Folder Action scripts attached to directories
2. Check ~/Library/Scripts/Folder Action Scripts/ for suspicious scripts
3. Use Folder Actions Setup.app to review attached actions
4. Verify the script content for malicious commands
5. Remove unauthorized Folder Action scripts
6. Check com.apple.FolderActions.plist for modifications
', '["https://attack.mitre.org/techniques/T1546/002/","https://posts.specterops.io/folder-actions-for-persistence-on-macos-8923f222343d"]', '(contains("log.eventMessage", "Folder Action") || contains("log.eventMessage", "FolderActions") ||
 contains("log.eventMessage", "com.apple.FolderActions")) &&
(contains("log.eventMessage", "attached") || contains("log.eventMessage", "enabled") ||
 contains("log.eventMessage", "added") || contains("log.eventMessage", "script") ||
 contains("log.eventMessage", "modified"))
', '2026-02-09 16:52:19.807273', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (451, 'Gatekeeper Bypass Attempt Detected', 2, 3, 2, 'Defense Evasion', 'T1553.001 - Subvert Trust Controls: Gatekeeper Bypass', 'Detects attempts to bypass Gatekeeper security checks through database manipulation, quarantine attribute removal, or exploitation of assessment vulnerabilities. Gatekeeper is a macOS security feature that verifies downloaded applications before they run, and bypassing it can allow malicious software to execute without proper verification.

Next Steps:
1. Immediately examine the affected system for unauthorized applications or modifications
2. Check system logs for unusual file downloads or installations around the time of the bypass attempt
3. Verify the integrity of applications in /Applications and ~/Applications directories
4. Review quarantine database (/var/db/SystemPolicy) for unauthorized modifications
5. Check for persistence mechanisms that might have been installed by bypassing Gatekeeper
6. Scan the system for malware using updated antivirus signatures
7. Consider reimaging the system if compromise is confirmed
8. Review user accounts and privileges for unauthorized changes
9. Monitor network traffic for suspicious outbound connections
10. Document the incident and update security policies as needed
', '["https://book.hacktricks.wiki/en/macos-hardening/macos-security-and-privilege-escalation/macos-security-protections/macos-gatekeeper.html","https://redcanary.com/blog/threat-detection/gatekeeper/","https://attack.mitre.org/techniques/T1553/001/"]', '(
  equals("log.process", "syspolicyd") && 
  (
    regexMatch("log.eventMessage", ".*assessment.*bypass.*") ||
    regexMatch("log.eventMessage", ".*quarantine.*removed.*") ||
    regexMatch("log.eventMessage", ".*GKE.*override.*")
  )
) ||
(
  regexMatch("log.eventMessage", ".*xattr.*-d.*com\\.apple\\.quarantine.*") &&
  equals("log.eventType", "logEvent")
) ||
(
  regexMatch("log.processImagePath", ".*/var/db/SystemPolicy.*") &&
  regexMatch("log.eventMessage", ".*(modify|write|delete).*")
) ||
(
  equals("log.subsystem", "com.apple.security.assessment") &&
  (contains("log.eventMessage", "bypass") || contains("log.eventMessage", "override") || contains("log.eventMessage", "disable"))
) ||
(
  equals("log.process", "spctl") &&
  contains("log.eventMessage", "--disable")
)
', '2026-02-09 16:52:19.967480', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
