insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (469, 'macOS Security Tools Disabled', 3, 3, 3, 'Defense Evasion', 'T1562.001 - Impair Defenses: Disable or Modify Tools', 'Detects attempts to disable or unload macOS security tools using launchctl or spctl. Attackers commonly disable endpoint security products such as LuLu, BlockBlock, Santa, CarbonBlack, CrowdStrike, and osquery, or disable Gatekeeper via spctl to execute malicious payloads without detection.

Next Steps:
1. Identify which security tool was disabled and restore it immediately
2. Determine what process or user initiated the disabling command
3. Check for malware or suspicious executables that may have been run after the tool was disabled
4. Review the timeline for other defense evasion or execution events
5. Re-enable all disabled security tools and verify their status
6. Investigate why the user had privileges to disable security tools
', '["https://attack.mitre.org/techniques/T1562/001/","https://github.com/SigmaHQ/sigma/blob/master/rules/macos/process_creation/proc_creation_macos_disable_security_tools.yml"]', '(
  contains("log.eventMessage", "launchctl") &&
  contains("log.eventMessage", "unload") &&
  (
    contains("log.eventMessage", "LuLu") ||
    contains("log.eventMessage", "BlockBlock") ||
    contains("log.eventMessage", "Santa") ||
    contains("log.eventMessage", "CarbonBlack") ||
    contains("log.eventMessage", "com.carbonblack") ||
    contains("log.eventMessage", "CrowdStrike") ||
    contains("log.eventMessage", "com.crowdstrike") ||
    contains("log.eventMessage", "osquery") ||
    contains("log.eventMessage", "com.facebook.osqueryd") ||
    contains("log.eventMessage", "com.objective-see")
  )
) ||
(
  contains("log.eventMessage", "spctl") &&
  contains("log.eventMessage", "--master-disable")
)
', '2026-02-09 16:52:22.877852', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (470, 'Shell Profile Modification for Persistence', 2, 3, 1, 'Persistence', 'T1546.004 - Event Triggered Execution: Unix Shell Configuration Modification', 'Detects modifications to shell profile files (.bash_profile, .zshrc, .zprofile) on macOS which attackers use to execute malicious commands every time a shell session starts.

Next Steps:
1. Review the modified shell profile file for injected commands
2. Compare against a known-good baseline
3. Check for reverse shells, downloaders, or environment variable manipulation
4. Identify the user and process that made the change
5. Restore the profile from backup if tampered
', '["https://attack.mitre.org/techniques/T1546/004/"]', '(contains("log.eventMessage", ".bash_profile") || contains("log.eventMessage", ".zshrc") ||
 contains("log.eventMessage", ".zprofile") || contains("log.eventMessage", ".bashrc") ||
 contains("log.eventMessage", ".zshenv") || contains("log.eventMessage", "/etc/zshrc") ||
 contains("log.eventMessage", "/etc/profile")) &&
(contains("log.eventMessage", "modified") || contains("log.eventMessage", "written") ||
 contains("log.eventMessage", "created") || contains("log.eventMessage", "changed"))
', '2026-02-09 16:52:22.997637', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (471, 'SSH Private Key Theft Attempt', 3, 2, 0, 'Credential Access', 'T1552.004 - Unsecured Credentials: Private Keys', 'Detects attempts to access or copy SSH private keys from user home directories on macOS, which attackers use for lateral movement and unauthorized access to remote systems.

Next Steps:
1. Identify the process and user accessing the SSH private key
2. Check if the key was copied or transmitted to an external location
3. Rotate the compromised SSH key pair immediately
4. Review authorized_keys on remote systems for the compromised key
5. Check for lateral movement using the stolen key
6. Investigate the initial compromise vector
', '["https://attack.mitre.org/techniques/T1552/004/"]', '(contains("log.eventMessage", ".ssh/id_rsa") || contains("log.eventMessage", ".ssh/id_ed25519") ||
 contains("log.eventMessage", ".ssh/id_ecdsa") || contains("log.eventMessage", ".ssh/id_dsa") ||
 contains("log.eventMessage", ".ssh/identity")) &&
(contains("log.eventMessage", "read") || contains("log.eventMessage", "copy") ||
 contains("log.eventMessage", "open") || contains("log.eventMessage", "cat") ||
 contains("log.eventMessage", "scp") || contains("log.eventMessage", "base64"))
', '2026-02-09 16:52:23.137988', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (472, 'Sudo Credential Caching Abuse', 3, 3, 1, 'Privilege Escalation', 'T1548.003 - Abuse Elevation Control Mechanism: Sudo and Sudo Caching', 'Detects abuse of sudo credential caching on macOS including timestamp manipulation, sudoers file modifications to extend timeout, and tty_tickets bypass attempts.

Next Steps:
1. Check the sudoers configuration for unauthorized timestamp_timeout changes
2. Review /var/db/sudo/ for timestamp manipulation
3. Verify if sudo was used to execute suspicious commands
4. Check for sudoers file modifications via visudo or direct editing
5. Review the user account for unauthorized privilege escalation
', '["https://attack.mitre.org/techniques/T1548/003/"]', '(contains("log.eventMessage", "sudoers") &&
 (contains("log.eventMessage", "modified") || contains("log.eventMessage", "syntax error") ||
  contains("log.eventMessage", "timestamp_timeout"))) ||
(contains("log.eventMessage", "sudo") && contains("log.eventMessage", "timestamp") &&
 (contains("log.eventMessage", "too far in the future") || contains("log.eventMessage", "reset"))) ||
(contains("log.eventMessage", "/var/db/sudo") &&
 (contains("log.eventMessage", "modified") || contains("log.eventMessage", "touch")))
', '2026-02-09 16:52:23.278181', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (473, 'System Integrity Protection (SIP) Bypass Attempt', 3, 3, 2, 'Defense Evasion', 'T1553.006 - Subvert Trust Controls: Code Signing Policy Modification', 'Detects attempts to bypass System Integrity Protection (SIP) through unauthorized modifications to protected locations or suspicious kernel extension loading with rootless entitlements. SIP is a critical security mechanism in macOS that protects system files and processes from modification, even by privileged users.

Next Steps:
1. Immediately isolate the affected macOS system to prevent further compromise
2. Check SIP status using ''csrutil status'' command to verify if it has been disabled
3. Review system logs for related process execution and file modifications
4. Examine running kernel extensions using ''kextstat'' command
5. Investigate the user account and process that attempted the SIP bypass
6. Check for persistence mechanisms and unauthorized modifications to system files
7. Review recent software installations and updates that might have triggered this alert
8. Consider reimaging the system if SIP has been successfully bypassed
', '["https://www.microsoft.com/en-us/security/blog/2025/01/13/analyzing-cve-2024-44243-a-macos-system-integrity-protection-bypass-through-kernel-extensions/","https://attack.mitre.org/techniques/T1553/006/"]', '(
  equals("log.process", "storagekitd") && 
  contains("log.eventMessage", "com.apple.rootless.install.heritable")
) ||
(
  regexMatch("log.processImagePath", ".*/System/Library/.*") && 
  regexMatch("log.eventMessage", ".*(csrutil|disable|rootless).*") &&
  equals("log.eventType", "logEvent")
) ||
(
  equals("log.subsystem", "com.apple.kernel") &&
  regexMatch("log.eventMessage", ".*(SIP|rootless).*bypass.*")
) ||
(
  regexMatch("log.process", ".*kext.*") &&
  contains("log.eventMessage", "rootless")
)
', '2026-02-09 16:52:23.422736', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (474, 'macOS System Log Clearing Detected', 1, 3, 2, 'Defense Evasion', 'T1070.002 - Indicator Removal: Clear Linux or Mac System Logs', 'Detects attempts to clear or delete macOS system logs using rm, unlink, or shred commands targeting /var/log or ~/Library/Logs directories. Attackers clear logs to remove evidence of their activities and hinder forensic investigation.

Next Steps:
1. Identify which log files were deleted and attempt to recover them from backups
2. Determine the user and process responsible for the log deletion
3. Review remaining logs and system activity before the deletion event
4. Check for other anti-forensic activity on the same system
5. Investigate the system for signs of compromise that the attacker tried to hide
6. Ensure centralized logging is in place to prevent future evidence destruction
', '["https://attack.mitre.org/techniques/T1070/002/","https://github.com/SigmaHQ/sigma/blob/master/rules/macos/process_creation/proc_creation_macos_clear_system_logs.yml"]', '(
  contains("log.eventMessage", ["rm ", "unlink ", "shred "]) &&
  contains("log.eventMessage", ["/var/log", "/Library/Logs", "system.log", "install.log", "asl/"])
) ||
(
  contains("log.eventMessage", "log erase") &&
  equals("log.process", "log")
)
', '2026-02-09 16:52:23.617278', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (475, 'TCC Database Manipulation Detected', 3, 3, 2, 'Privilege Escalation, Defense Evasion', 'T1548 - Abuse Elevation Control Mechanism', 'Detects unauthorized attempts to manipulate the Transparency, Consent, and Control (TCC) database to bypass privacy protections and gain access to protected resources. This detection identifies various methods of TCC database manipulation including direct database modifications, unauthorized access attempts, and privilege escalation through TCC bypass techniques.

Next Steps:
1. Investigate the process attempting to modify the TCC database
2. Check if the modification was authorized and expected
3. Review system logs for any suspicious activity around the time of detection
4. Verify the integrity of the TCC database
5. Check for any unauthorized applications that may have gained elevated privileges
6. Review recent software installations or system changes
7. Consider reimaging the affected system if unauthorized TCC manipulation is confirmed
', '["https://interpressecurity.com/resources/report/return-of-the-macos-transparency-consent-and-control-tcc-database-manipulation/","https://www.sentinelone.com/labs/bypassing-macos-tcc-user-privacy-protections-by-accident-and-design/","https://attack.mitre.org/techniques/T1548/"]', '(
  equals("log.process", "tccd") &&
  (
    regexMatch("log.eventMessage", ".*unauthorized.*access.*") ||
    contains("log.eventMessage", "bypass") ||
    contains("log.eventMessage", "CVE-2020-9934")
  )
) ||
(
  regexMatch("log.processImagePath", ".*/Library/Application Support/com\\.apple\\.TCC/TCC\\.db.*") &&
  regexMatch("log.eventMessage", ".*(write|modify|INSERT|UPDATE|DELETE).*") &&
  !equals("log.process", "tccd")
) ||
(
  contains("log.eventMessage", "TCC.db") &&
  (
    regexMatch("log.eventMessage", ".*(sqlite3|INSERT INTO|UPDATE|DELETE FROM).*") ||
    regexMatch("log.eventMessage", ".*(kTCCServiceDeveloperTool|kTCCServiceScreenCapture|kTCCServiceAccessibility).*")
  )
) ||
(
  equals("log.subsystem", "com.apple.TCC") &&
  (
    contains("log.eventMessage", "Full Disk Access") ||
    contains("log.eventMessage", "Screen Recording") ||
    contains("log.eventMessage", "Accessibility")
  ) &&
  regexMatch("log.eventMessage", ".*(grant|bypass|override).*")
) ||
(
  exists("log.process") &&
  regexMatch("log.eventMessage", ".*com\\.apple\\.private\\.tcc\\.manager.*") &&
  !equals("log.process", "tccd")
)
', '2026-02-09 16:52:23.744140', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (476, 'Time Machine Backup Deletion Detected', 1, 3, 3, 'Impact', 'T1490 - Inhibit System Recovery', 'Detects the use of tmutil to delete Time Machine backups on macOS. This is a common ransomware preparation technique where attackers delete backups to prevent recovery after encryption. Legitimate backup deletions are rare and should be closely monitored.

Next Steps:
1. Immediately verify if backup deletion was authorized
2. Identify the user and process that executed tmutil delete
3. Check for ransomware indicators on the system (file encryption, ransom notes)
4. Verify the integrity of remaining backups
5. Isolate the system from the network if ransomware is suspected
6. Ensure offsite or cloud backups are intact and accessible
', '["https://attack.mitre.org/techniques/T1490/","https://github.com/SigmaHQ/sigma/blob/master/rules/macos/process_creation/proc_creation_macos_tmutil_delete_backup.yml"]', 'contains("log.eventMessage", "tmutil") &&
contains("log.eventMessage", "delete")
', '2026-02-09 16:52:23.893341', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (477, 'WizardUpdate Malware Indicators Detected', 3, 3, 3, 'Malware Detection', 'T1059.002 - Command and Scripting Interpreter: AppleScript', 'Detects indicators of the WizardUpdate (UpdateAgent) macOS trojan. This malware uses curl piped to bash/eval patterns and references characteristic paths like _intermediate_agent_ for staging and execution. WizardUpdate is a known macOS trojan that downloads and executes additional payloads.

Next Steps:
1. Isolate the affected system from the network immediately
2. Search for the _intermediate_agent_ staging files
3. Check for persistence mechanisms (LaunchAgents, LaunchDaemons)
4. Review network connections for C2 communication
5. Identify the initial infection vector (adware bundle, fake installer)
6. Perform a full malware scan and consider reimaging the system
', '["https://attack.mitre.org/techniques/T1059/002/","https://github.com/SigmaHQ/sigma/blob/master/rules/macos/process_creation/proc_creation_macos_wizardupdate_malware_infection.yml","https://www.sentinelone.com/blog/from-the-front-lines-new-macos-covid-malware-wizardupdate-changes-infection-tactics/"]', '(
  contains("log.eventMessage", "curl") &&
  contains("log.eventMessage", ["eval", "bash", "sh "]) &&
  contains("log.eventMessage", ["pipe", "|"])
) ||
contains("log.eventMessage", "_intermediate_agent_") ||
contains("log.eventMessage", "UpdateAgent")
', '2026-02-09 16:52:24.027496', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (478, 'XCSSET Malware Indicators Detected', 3, 3, 3, 'Malware Detection', 'T1059.002 - Command and Scripting Interpreter: AppleScript', 'Detects indicators of XCSSET malware on macOS. XCSSET is a sophisticated malware that targets Xcode projects, steals browser data, and installs backdoors. Key indicators include curl requests to /sys/log.php C2 endpoints, osacompile commands in Library/Group Containers paths, and characteristic repl staging patterns.

Next Steps:
1. Isolate the affected system from the network immediately
2. Check all Xcode projects on the system for injected malicious build phases
3. Review Library/Group Containers directories for unauthorized files
4. Check browser data stores for signs of credential theft
5. Examine LaunchAgents for XCSSET persistence mechanisms
6. Perform a full malware scan and consider reimaging the system
7. Notify other developers who may have cloned affected Xcode projects
', '["https://attack.mitre.org/techniques/T1059/002/","https://github.com/SigmaHQ/sigma/blob/master/rules/macos/process_creation/proc_creation_macos_xcsset_malware_infection.yml","https://www.trendmicro.com/en_us/research/20/h/xcsset-mac-malware--infects-xcode-projects--uses-0-days.html"]', '(
  contains("log.eventMessage", "curl") &&
  contains("log.eventMessage", "/sys/log.php")
) ||
(
  contains("log.eventMessage", "osacompile") &&
  contains("log.eventMessage", "Library/Group Containers")
) ||
(
  contains("log.eventMessage", "repl") &&
  contains("log.eventMessage", "Pods") &&
  contains("log.eventMessage", "xcscheme")
)
', '2026-02-09 16:52:24.157689', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (788, 'Windows: Whoami Process Activity', 1, 1, 0, 'Discovery', 'T1033 - System Owner/User Discovery', 'Identifies suspicious use of whoami.exe which displays user, group, and privileges information for the user who is currently logged on to the local system.', '["https://attack.mitre.org/tactics/TA0007/","https://attack.mitre.org/techniques/T1033/"]', 'contains("log.eventDataProcessName", "whoami.exe")', '2026-02-09 16:57:43.692193', true, false, 'origin', '["adversary.user","adversary.ip"]', '[]', null);
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (479, 'XProtect Evasion or Tampering Detected', 3, 3, 2, 'Defense Evasion', 'T1562.001 - Impair Defenses: Disable or Modify Tools', 'Detects attempts to evade or tamper with XProtect malware detection including modification of XProtect files, databases, or YARA rules. XProtect is Apple''s built-in antimalware system, and attempts to bypass or disable it indicate potential malicious activity.

Next Steps:
1. Immediately investigate the affected system and user account for signs of compromise
2. Check for recently installed software or suspicious downloads that may have triggered the evasion attempt
3. Review system logs for other defense evasion activities around the same timeframe
4. Verify the integrity of XProtect files and configurations
5. Run a comprehensive malware scan using additional security tools
6. Consider isolating the affected system if malicious activity is confirmed
7. Review user privileges and access controls to prevent unauthorized system modifications
8. Document the incident and update security policies if necessary
', '["https://www.sentinelone.com/blog/macos-malware-researchers-how-to-bypass-xprotect-on-catalina/","https://attack.mitre.org/techniques/T1562/001/"]', '(
  equals("log.subsystem", "com.apple.XProtectFramework") &&
  (
    contains("log.eventMessage", "bypass") ||
    contains("log.eventMessage", "evasion") ||
    contains("log.eventMessage", "disable")
  )
) ||
