insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (480, 'DNS Cache Poisoning Attempt', 3, 3, 2, 'Resource Development', 'T1584.002 - Acquire Infrastructure: DNS Server', 'Detects potential DNS cache poisoning attempts where multiple DNS responses are received from different sources for the same domain in a short time window, which could indicate an attacker trying to inject malicious DNS records.

Next Steps:
1. Verify the legitimacy of the DNS responses by checking the source IP addresses
2. Review DNS query logs to identify the original query that triggered these responses
3. Check if the responding IP addresses match known legitimate DNS servers
4. Examine the timing patterns of the responses to identify potential spoofing
5. Verify DNS server configurations and check for unauthorized DNS server additions
6. Monitor for subsequent DNS queries to verify if poisoned cache entries are being used
7. Consider implementing DNS security measures like DNSSEC if not already in place
', '["https://help.mikrotik.com/docs/spaces/ROS/pages/37748767/DNS","https://attack.mitre.org/techniques/T1584/002/"]', 'equals("log.topics", "dns") && 
equals("target.port", 53) && 
exists("origin.ip") &&
contains("log.chain", "response")
', '2026-02-09 16:52:24.447716', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-mikrotik-*","with":[{"field":"target.ip","operator":"filter_term","value":"{{target.ip}}"},{"field":"log.topics","operator":"filter_term","value":"dns"}],"or":null,"within":"now-5m","count":10}]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (481, 'MikroTik DNS Static Entry Redirection', 3, 3, 1, 'Credential Access', 'T1584.002 - Compromise Infrastructure: DNS Server', 'Detects creation or modification of static DNS entries on MikroTik routers that could redirect traffic to attacker-controlled servers for credential harvesting or man-in-the-middle attacks.

Next Steps:
1. Review all static DNS entries for unauthorized additions
2. Verify the destination IP addresses of suspicious DNS entries
3. Check if DNS entries redirect to known legitimate services or suspicious IPs
4. Investigate if users may have been redirected to phishing sites
5. Remove unauthorized DNS entries immediately
6. Audit DNS server configuration for other anomalies
', '["https://help.mikrotik.com/docs/spaces/ROS/pages/328094/Log","https://attack.mitre.org/techniques/T1584/002/"]', 'contains("log.topics", "system") &&
(contains("log.message", "dns") || contains("log.message", "DNS")) &&
(contains("log.message", ["static", "added", "changed", "entry"]))
', '2026-02-09 16:52:24.587109', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (482, 'MikroTik SOCKS Proxy Enablement Detection', 3, 3, 2, 'Command and Control', 'T1090 - Proxy', 'Detects SOCKS proxy enablement on MikroTik routers, a common indicator of Meris botnet infection and other RouterOS-targeting malware. Attackers enable SOCKS proxy to route malicious traffic through compromised routers.

Next Steps:
1. Immediately check if the SOCKS proxy service is enabled on the router
2. Verify if the change was authorized by a legitimate administrator
3. Check for known Meris botnet indicators (scheduler scripts, unauthorized users)
4. Review firewall rules for any recently added NAT or port forwarding entries
5. If compromised, disable SOCKS proxy, remove unauthorized users and scripts
6. Update RouterOS to the latest firmware version
', '["https://help.mikrotik.com/docs/spaces/ROS/pages/328094/Log","https://attack.mitre.org/techniques/T1090/"]', 'contains("log.topics", "system") &&
(contains("log.message", "socks") || contains("log.message", "SOCKS")) &&
(contains("log.message", ["enabled", "changed", "added", "proxy"]))
', '2026-02-09 16:52:24.717823', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (483, 'MikroTik New Admin User Creation', 3, 3, 2, 'Persistence', 'T1136 - Create Account', 'Detects creation of new administrative users on MikroTik RouterOS devices. Attackers who gain access to MikroTik routers frequently create backdoor accounts for persistent access.

Next Steps:
1. Verify the new user account was created by an authorized administrator
2. Review the permissions and group assignment of the new account
3. Check if the user was created through known management channels (Winbox, SSH, web)
4. Audit all existing user accounts for unauthorized entries
5. If unauthorized, immediately delete the account and change all admin passwords
6. Check for other signs of compromise such as script modifications or scheduler tasks
', '["https://help.mikrotik.com/docs/spaces/ROS/pages/328094/Log","https://attack.mitre.org/techniques/T1136/"]', 'contains("log.topics", "system") &&
contains("log.topics", "info") &&
(contains("log.message", "user") && contains("log.message", ["added", "created", "changed group"])) &&
!contains("log.message", "logged in")
', '2026-02-09 16:52:24.852887', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (498, 'Baby Shark C2 Communication Pattern Detected', 3, 3, 2, 'Command and Control', 'T1071.001 - Application Layer Protocol: Web Protocols', 'Detects HTTP traffic matching the Baby Shark C2 framework URL pattern. Baby Shark is a reconnaissance tool and C2 framework used primarily by North Korean APT groups (Kimsuky/Thallium). The distinctive URL pattern ''momyshark?key='' is unique to this framework and has very low false positive rates.

Next Steps:
1. IMMEDIATELY escalate - potential nation-state attack (Kimsuky/DPRK)
2. Isolate the affected host without alerting the attacker
3. Engage specialized incident response with APT experience
4. Preserve all forensic evidence including network captures
5. Block the C2 domain/IP at the network perimeter
6. Search for other Baby Shark/Kimsuky indicators across the environment
7. Coordinate with relevant government agencies (CISA, FBI)
', '["https://attack.mitre.org/techniques/T1071/001/","https://github.com/SigmaHQ/sigma/blob/master/rules/web/proxy_generic/proxy_hktl_baby_shark_default_agent_url.yml","https://unit42.paloaltonetworks.com/new-babyshark-malware-targets-u-s-national-security-think-tanks/"]', 'equals("log.eventType", "http") &&
exists("origin.ip") &&
(
  contains("log.http.url", "momyshark?key=") ||
  contains("log.http.url", "momyshark%3Fkey%3D") ||
  (contains("log.http.url", "babyshark") && contains("log.http.url", "key="))
)
', '2026-02-09 16:52:27.277733', true, false, 'origin', null, '[]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (484, 'RouterOS Multiple Authentication Failures', 3, 3, 2, 'Credential Access', 'T1110.001 - Brute Force: Password Guessing', 'Detects multiple failed authentication attempts to RouterOS from the same source IP, which may indicate a brute force attack against the device. This rule monitors for login failures across all services including SSH, Telnet, Winbox, and web interface.

Next Steps:
1. Investigate the source IP address for legitimacy and geographic location
2. Check if the IP is from an expected network range or known administrator location
3. Review successful authentication attempts from the same IP before and after the failures
4. Examine other RouterOS logs for additional suspicious activities from this IP
5. Consider implementing IP blocking or rate limiting for the source IP
6. Verify RouterOS user accounts for any unauthorized changes or access
7. Check if default credentials are still in use on the device
', '["https://help.mikrotik.com/docs/spaces/ROS/pages/328094/Log","https://attack.mitre.org/techniques/T1110/001/"]', 'contains("log.topics", "system") && contains("log.topics", "error") && contains("log.topics", "critical") && contains("log.message", "login failure") && exists("origin.ip")', '2026-02-09 16:52:24.997509', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-mikrotik-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"log.message","operator":"filter_match","value":"login failure"}],"or":null,"within":"now-15m","count":10}]', '["adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (485, 'SSH Brute Force Attack on MikroTik Device', 3, 2, 2, 'Credential Access', 'T1110.001 - Brute Force: Password Guessing', 'Detects SSH brute force attempts against MikroTik devices. Monitors for multiple SSH connection attempts on port 22 from the same source IP within a short time window, which may indicate password guessing attacks.

Next Steps:
1. Verify the source IP address and check if it''s from a known legitimate administrator
2. Review SSH access logs on the MikroTik device for successful authentications
3. Check if the source IP has been involved in other suspicious activities
4. Consider implementing rate limiting or IP blocking for repeated failed attempts
5. Ensure SSH access is restricted to authorized management networks only
6. Review MikroTik firewall rules and consider disabling SSH access from untrusted networks
', '["https://help.mikrotik.com/docs/spaces/ROS/pages/132350014/SSH","https://attack.mitre.org/techniques/T1110/001/"]', 'equals("target.port", 22) && equals("protocol", "tcp") && exists("origin.ip") &&
