|| (contains("log.topics", "system") && contains("log.kvMessage", "ssh")))
', '2026-02-09 16:52:25.143279', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-mikrotik-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"target.port","operator":"filter_term","value":"22"},{"field":"protocol","operator":"filter_term","value":"tcp"}],"or":null,"within":"now-15m","count":10}]', '["adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (486, 'C2 Beaconing Behavior Detection', 2, 2, 1, 'Command and Control', 'T1071 - Application Layer Protocol', 'Detects potential command and control beaconing behavior based on periodic connections with consistent intervals and small data transfers. This rule identifies suspicious network patterns where an internal host makes repeated small connections to an external host, which may indicate C2 communication.

Next Steps:
1. Analyze the frequency and timing of connections between the source and destination
2. Investigate the destination IP for known malicious indicators or suspicious reputation
3. Examine the content of the communications if possible through packet capture
4. Check the source host for signs of compromise or malware
5. Review DNS queries made by the source host around the time of the connections
6. Correlate with other security events from the same source host
7. Consider isolating the source host if malicious activity is confirmed
', '["https://attack.mitre.org/techniques/T1071/","https://www.cisco.com/en/US/technologies/tk648/tk362/technologies_white_paper09186a00800a3db9.html"]', 'exists("origin.ip") && exists("target.ip") &&
