lessThan("origin.packagesSent", 50) &&
oneOf("target.port", [443, 80, 8080, 8443])
', '2026-02-09 16:52:25.287615', true, false, 'origin', null, '[{"indexPattern":"v11-log-netflow-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"target.ip","operator":"filter_term","value":"{{target.ip}}"},{"field":"dataType","operator":"filter_term","value":"netflow"}],"or":null,"within":"now-1h","count":30}]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (487, 'Data Exfiltration Detection', 3, 2, 1, 'Exfiltration', 'T1041 - Exfiltration Over C2 Channel', 'Detects potential data exfiltration based on unusually large outbound data transfers to external IP addresses. This rule identifies network flows where significant amounts of data (>10MB) are transferred from internal systems to external destinations in different countries, potentially indicating unauthorized data theft or exfiltration attempts.

Next Steps:
1. Verify the legitimacy of the large data transfer by checking if it corresponds to authorized business activities
2. Investigate the destination IP address for reputation and known threat indicators
3. Review the user and process responsible for initiating the connection
4. Check for any recently accessed sensitive files or databases on the source system
5. Examine network logs for any additional suspicious communications to the same destination
6. Consider implementing DLP policies if large data transfers to external destinations are not business justified
7. If confirmed malicious, isolate the affected system and conduct a full forensic investigation
', '["https://attack.mitre.org/techniques/T1041/","https://www.cisco.com/en/US/technologies/tk648/tk362/technologies_white_paper09186a00800a3db9.html"]', 'exists("origin.ip") && exists("target.ip") && greaterThan("origin.bytesSent", 10000000) && safe(origin.geolocation.country, "") != safe(target.geolocation.country, "") && greaterThan("origin.port", 1024)', '2026-02-09 16:52:25.702360', true, false, 'origin', null, '[{"indexPattern":"v11-log-netflow-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"dataType","operator":"filter_term","value":"netflow"}],"or":null,"within":"now-1h","count":10}]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (503, 'Command and Control Traffic Detection', 3, 3, 2, 'Command and Control', 'T1095 - Non-Application Layer Protocol', 'Detects command and control (C2) communication patterns including suspicious periodic connections, non-standard ports, encrypted channels on unusual ports, DNS tunneling, and known C2 infrastructure indicators. This rule identifies malicious communications between compromised systems and command and control servers through various techniques including signature-based detection, protocol analysis, and behavioral indicators.

Next Steps:
1. Immediately isolate the affected system (origin IP) from the network to prevent further C2 communication
2. Analyze network traffic logs for additional communications with the destination IP
3. Perform endpoint forensics on the compromised system to identify malware and persistence mechanisms
4. Check for lateral movement from the compromised system to other network assets
5. Review DNS logs for additional suspicious domain queries from the affected system
6. Update threat intelligence feeds and block the identified C2 infrastructure
7. Scan other systems for indicators of compromise (IoCs) related to the detected C2 activity
8. Review user activity and privilege escalation attempts from the compromised system
9. Consider reimaging the affected system after thorough forensic analysis
10. Implement additional monitoring for similar C2 patterns across the network
', '["https://attack.mitre.org/techniques/T1095/","https://attack.mitre.org/techniques/T1571/","https://www.snort.org/rule_docs/"]', '(contains("log.alert.signature", ["command and control", "c&c", "c2", "beacon", "cobalt strike", "metasploit"]) ||
 oneOf("log.alert.category", ["malware-cnc", "suspicious-traffic"]) ||
 (equals("protocol", "DNS") && equals("log.dns.type", "TXT") && greaterThan("log.dns.response_length", 200)) ||
 (regexMatch("log.http.uri", "^/[a-zA-Z0-9]{8,16}$") &&
 equals("log.http.method", "GET")) ||
 (greaterThan("log.flow.duration", 300) && lessThan("log.flow.packets", 100) && lessThan("log.flow.bytes", 10240)) ||
 oneOf("log.ja3.hash", ["3b5074b1b5d032e5620f69f9f700ff0e", "6734f37431670b3ab4292b8f60f29984"])) &&
exists("origin.ip") &&
exists("target.ip")
', '2026-02-09 16:52:27.987304', true, false, 'origin', null, '[{"indexPattern":"v11-log-suricata-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"target.ip","operator":"filter_term","value":"{{target.ip}}"}],"or":null,"within":"now-1h","count":5}]', '["adversary.ip","target.ip","target.port"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (488, 'DDoS Attack Pattern Detection', 1, 1, 3, 'Impact', 'T1498 - Network Denial of Service', 'Detects potential DDoS attack patterns based on high volume of network flows from multiple sources targeting a single destination within a short time window. This rule identifies suspicious traffic volumes that may indicate volumetric DDoS attacks such as UDP floods, TCP floods, or other amplification attacks.

Next Steps:
1. Verify the target IP address and check if it''s a critical service or server
2. Analyze the source IPs to determine if they are part of a botnet or coordinated attack
3. Review network traffic patterns and bandwidth utilization during the timeframe
4. Check firewall and DDoS mitigation system logs for related events
5. Implement rate limiting or blocking rules for attacking source IPs if confirmed malicious
6. Consider scaling up infrastructure or activating DDoS protection services if attack is ongoing
7. Document the attack pattern for future reference and threat intelligence
', '["https://attack.mitre.org/techniques/T1498/","https://www.cisco.com/en/US/technologies/tk648/tk362/technologies_white_paper09186a00800a3db9.html"]', 'exists("target.ip") && exists("origin.ip") && (greaterThan("origin.bytesSent", 10000000) || greaterThan("origin.packagesSent", 50000))', '2026-02-09 16:52:25.842391', true, false, 'origin', null, '[{"indexPattern":"v11-log-netflow-*","with":[{"field":"target.ip","operator":"filter_term","value":"{{target.ip}}"},{"field":"dataType","operator":"filter_term","value":"netflow"}],"or":null,"within":"now-5m","count":100}]', '["target.ip"]');
