 equals("target.ip", "185.228.168.168") || equals("target.ip", "185.228.169.168") ||
 equals("target.ip", "104.16.248.249") || equals("target.ip", "104.16.249.249"))
', '2026-02-09 16:52:26.108020', true, false, 'origin', null, '[{"indexPattern":"v11-log-netflow-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"target.port","operator":"filter_term","value":"443"}],"or":null,"within":"now-1h","count":20}]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (491, 'ICMP Tunneling Detection', 3, 2, 1, 'Command and Control', 'T1095 - Non-Application Layer Protocol', 'Detects potential ICMP tunneling by identifying ICMP traffic with unusually large packet sizes or high data volumes. Attackers use ICMP tunneling (tools like ptunnel, icmpsh) to exfiltrate data or establish covert C2 channels through protocols that are often allowed by firewalls.

Next Steps:
1. Investigate the internal host generating large ICMP traffic
2. Review the ICMP packet sizes - normal ping uses 64 bytes
3. Check for ICMP tunneling tools on the host (ptunnel, icmpsh, Hans)
4. Review the destination IP for known C2 infrastructure
5. Monitor ICMP traffic patterns for regular beaconing intervals
6. Consider rate-limiting or blocking ICMP to external destinations
', '["https://attack.mitre.org/techniques/T1095/","https://www.cisco.com/en/US/technologies/tk648/tk362/technologies_white_paper09186a00800a3db9.html"]', 'exists("origin.ip") &&
exists("target.ip") &&
