', '2026-02-09 16:52:26.847297', true, false, 'origin', '["adversary.ip","target.ip"]', '[{"indexPattern":"v11-log-netflow-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"target.ip","operator":"filter_term","value":"{{target.ip}}"}],"or":null,"within":"now-2m","count":25}]', null);
