 (oneOf("log.smb.command", ["SMB2_COMMAND_TREE_CONNECT", "SMB2_COMMAND_SESSION_SETUP"]) && !equals("log.smb.status", "STATUS_SUCCESS")) ||
 (equals("protocol", "RDP") && equals("log.rdp.event_type", "connection_attempt")) ||
 oneOf("log.service", ["wmi", "winrm", "psexec", "dcom"])) &&
