insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (509, 'DNS Tunneling Detection', 2, 2, 1, 'Command and Control', 'T1071.004 - Application Layer Protocol: DNS', 'Detects potential DNS tunneling activity based on abnormal DNS query patterns, including unusually long domain names, high frequency of DNS requests, or suspicious TXT record queries. DNS tunneling is a technique used by attackers to exfiltrate data or establish command and control channels by encoding data within DNS queries and responses.

Next Steps:
1. Analyze the DNS queries to identify the specific domains and query types involved
2. Check the frequency and volume of DNS requests from the source IP
3. Examine the content of TXT record queries for encoded data
4. Correlate with network traffic to identify potential data exfiltration
5. Block suspicious domains at the DNS level if confirmed malicious
6. Monitor the source host for other indicators of compromise
', '["https://attack.mitre.org/techniques/T1071/004/","https://www.sans.org/reading-room/whitepapers/dns/detecting-dns-tunneling-34152"]', 'equals("log.protocol", "DNS") && (
  greaterThan("log.query_length", 50) ||
  equals("log.query_type", "TXT") ||
  greaterThan("log.subdomain_levels", 4) ||
