insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (510, 'DNS TXT Record Contains Execution Strings', 3, 3, 2, 'Command and Control', 'T1071.004 - Application Layer Protocol: DNS', 'Detects DNS TXT record responses containing Windows command execution strings such as IEX, Invoke-Expression, cmd.exe, powershell, and other execution indicators. This technique is used for DNS-based C2 payload delivery where commands are encoded in DNS TXT records and executed by the compromised host.

Next Steps:
1. Capture and decode the full DNS TXT record content
2. Analyze the payload for specific commands being delivered
3. Isolate the host requesting these DNS records
4. Block the queried domain at the DNS resolver
5. Check for evidence of command execution on the endpoint
6. Review DNS logs for similar queries from other hosts
7. Perform endpoint forensics to identify the malware requesting these records
', '["https://attack.mitre.org/techniques/T1071/004/","https://github.com/SigmaHQ/sigma/blob/master/rules/network/dns/net_dns_susp_txt_exec_strings.yml"]', 'equals("log.eventType", "dns") &&
equals("log.dns.type", "answer") &&
