(
  contains("log.dns.answers", "IEX") ||
  contains("log.dns.answers", "Invoke-Expression") ||
  contains("log.dns.answers", "cmd.exe") ||
  contains("log.dns.answers", "powershell") ||
  contains("log.dns.answers", "cmd /c") ||
  contains("log.dns.answers", "Start-Process") ||
  contains("log.dns.answers", "DownloadString") ||
  contains("log.dns.answers", "DownloadFile") ||
  contains("log.dns.answers", "Net.WebClient") ||
  contains("log.dns.answers", "FromBase64String") ||
  contains("log.dns.answers", "/bin/bash") ||
  contains("log.dns.answers", "/bin/sh") ||
  contains("log.dns.answers", "wget ") ||
  contains("log.dns.answers", "curl ")
) &&
exists("origin.ip")
