  contains("log.http.http_user_agent", "Meterpreter") ||
  contains("log.http.http_user_agent", "Metasploit") ||
  regexMatch("log.http.http_user_agent", "(?i)^Mozilla/5\\.0 \\(Windows; U; MSIE 7\\.0; Windows NT 5\\.2\\) Java/") ||
