insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (513, 'Hack Tool User Agent Detected in HTTP Traffic', 2, 2, 1, 'Reconnaissance', 'T1595.002 - Active Scanning: Vulnerability Scanning', 'Detects HTTP traffic containing user agent strings from known offensive security and hacking tools including vulnerability scanners, brute force tools, SQL injection tools, and web application testing tools. These tools are commonly used during reconnaissance and exploitation phases of attacks.

Next Steps:
1. Determine if this is authorized penetration testing or security assessment
