insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (514, 'ICMP Tunneling Detection', 3, 2, 2, 'Command and Control', 'T1572 - Protocol Tunneling', 'Detects potential ICMP tunneling activity based on abnormal ICMP packet patterns, including oversized ICMP packets, unusual ICMP types, high payload entropy, or abnormal ICMP codes. ICMP tunneling is a covert channel technique used by attackers to bypass network security controls and establish command and control communications.

Next Steps:
1. Investigate the source IP address for other suspicious network activities
2. Analyze the ICMP packet payload for hidden data or commands
3. Check if the destination IP is a known external server or suspicious domain
4. Review network logs for patterns of regular ICMP traffic to the same destination
5. Examine endpoint logs on the source machine for signs of compromise
6. Consider blocking ICMP traffic to external destinations if not business-critical
7. Implement ICMP payload inspection rules to detect tunneling signatures
8. Monitor for other covert channel techniques from the same source
