insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (523, 'TLS Certificate Anomaly Detection', 3, 2, 1, 'Defense Evasion', 'T1573 - Encrypted Channel', 'Detects TLS certificate anomalies including self-signed certificates, expired certificates, certificate subject mismatches, and certificates from untrusted authorities. These anomalies are common indicators of C2 infrastructure, man-in-the-middle attacks, or phishing sites.

Next Steps:
1. Review the certificate details (issuer, subject, validity dates)
2. Check if the destination is a legitimate service with a known certificate issue
3. Investigate self-signed certificates connecting to external hosts
4. Review the internal host for malware communicating with C2 servers
5. Check if the certificate fingerprint matches known threat intelligence
6. Block connections to destinations with suspicious certificates
