insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (525, 'Port Scan Detection', 2, 1, 1, 'Discovery', 'T1046 - Network Service Scanning', 'Detects various port scanning techniques including TCP SYN scans, connect scans, UDP scans, NULL scans, FIN scans, and XMAS scans. Port scanning is a reconnaissance technique used by attackers to discover open ports and services on target systems, which can be used to identify potential attack vectors.

This rule detects port scans through multiple indicators:
- Suricata alert signatures containing scan-related keywords
- TCP SYN packets with short duration flows (SYN scan)
- TCP packets with unusual flag combinations (NULL, FIN, XMAS scans)
- Anomaly events indicating scan activity

Next Steps:
1. Investigate the source IP for legitimacy (internal security scanner vs external threat)
2. Analyze the target ports and services being scanned
3. Check for any successful connections following the scan activity
4. Review network segmentation and firewall rules for the affected systems
5. Consider blocking the source IP if confirmed malicious
6. Monitor for any privilege escalation or lateral movement attempts from the scanning source
', '["https://attack.mitre.org/techniques/T1046/","https://docs.suricata.io/en/latest/output/eve/eve-json-format.html"]', '(
  (equals("log.eventType", "alert") &&
   contains("log.alert.signature", ["scan", "SCAN", "portscan"])) ||
  (equals("protocol", "TCP") &&
   equals("log.tcp.flags", "S") &&
   equals("log.flow.state", "new") &&
   lessThan("log.flow.duration", 1)) ||
  (equals("protocol", "TCP") &&
   oneOf("log.tcp.flags", ["", "F", "FPU"])) ||
  (equals("log.eventType", "anomaly") &&
   contains("log.anomaly.event", "scan"))
)
', '2026-02-09 16:52:31.042713', true, false, 'origin', '["adversary.ip","target.ip"]', '[{"indexPattern":"v11-log-suricata-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-10m","count":50},{"indexPattern":"v11-log-suricata-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"target.ip","operator":"filter_term","value":"{{target.ip}}"}],"or":null,"within":"now-10m","count":20}]', null);
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (526, 'PwnDrop File Hosting Server Access Detected', 2, 3, 1, 'Command and Control', 'T1102 - Web Service', 'Detects HTTP access to PwnDrop file hosting servers. PwnDrop is a self-hosted file hosting tool designed for red teamers and attackers to serve payloads. The /pwndrop/ path in the URL is the default admin and API endpoint, and its presence in web traffic strongly indicates malicious file hosting or payload delivery.

Next Steps:
1. Identify what files were downloaded from the PwnDrop server
2. Analyze any downloaded files for malicious content
3. Block the PwnDrop server IP/domain at the network perimeter
4. Check if the access was part of authorized red team activity
5. Investigate the source host for signs of compromise
6. Search for other hosts that connected to the same PwnDrop server
7. Check email logs for phishing links pointing to the PwnDrop server
', '["https://attack.mitre.org/techniques/T1102/","https://github.com/SigmaHQ/sigma/blob/master/rules/web/proxy_generic/proxy_pwndrop.yml","https://github.com/kgretzky/pwndrop"]', 'equals("log.eventType", "http") &&
exists("origin.ip") &&
contains("log.http.url", "/pwndrop/")
', '2026-02-09 16:52:31.187655', true, false, 'origin', null, '[]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (527, 'Rclone Data Exfiltration Tool Detected', 3, 2, 1, 'Exfiltration', 'T1567.002 - Exfiltration Over Web Service: Exfiltration to Cloud Storage', 'Detects HTTP traffic with the rclone user agent string. Rclone is a command-line program to manage files on cloud storage and is the most commonly used data exfiltration tool in ransomware operations. Threat groups including Conti, BlackMatter, LockBit, and many others use rclone to exfiltrate data before deploying ransomware.

Next Steps:
1. Immediately investigate the source host for signs of ransomware staging
2. Determine what data is being transferred and to which cloud destination
3. Check if rclone is an authorized tool in the environment
4. Block the destination cloud storage endpoints if unauthorized
5. Preserve network capture data for forensic analysis of exfiltrated data
6. Search for ransomware deployment indicators on the same host
7. Initiate incident response - this may indicate imminent ransomware deployment
', '["https://attack.mitre.org/techniques/T1567/002/","https://github.com/SigmaHQ/sigma/blob/master/rules/web/proxy_generic/proxy_ua_rclone.yml","https://research.nccgroup.com/2021/05/27/detecting-rclone-an-effective-tool-for-exfiltration/"]', 'equals("log.eventType", "http") &&
exists("log.http.http_user_agent") &&
exists("origin.ip") &&
(
  startsWith("log.http.http_user_agent", "rclone/") ||
  contains("log.http.http_user_agent", "rclone/v")
)
', '2026-02-09 16:52:31.332661', true, false, 'origin', null, '[{"indexPattern":"v11-log-suricata-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"log.eventType","operator":"filter_term","value":"http"}],"or":null,"within":"now-30m","count":3}]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (528, 'Threat Intelligence IOC Match', 3, 2, 2, 'Command and Control', 'Command and Control', 'Detects network traffic matching known malicious indicators from threat intelligence feeds including malicious IPs, domains, and URLs. This rule triggers when Suricata identifies traffic involving known threat actors, command and control servers, botnet infrastructure, or other malicious network indicators based on threat intelligence data.

Next Steps:
1. Immediately isolate the affected system from the network to prevent lateral movement
2. Analyze the complete network session to understand the scope of communication
3. Check for other systems that may have communicated with the same malicious indicator
4. Review threat intelligence source details to understand the specific threat type and attribution
5. Examine system logs for signs of compromise or malicious activity
6. Run comprehensive malware scans on the affected endpoint
7. Review user activity and authentication logs for suspicious behavior
8. Consider blocking the malicious indicator at network perimeter devices
9. Document the incident and update threat hunting queries to detect similar activity
10. If confirmed malicious, initiate incident response procedures and consider threat hunting across the environment
', '["https://attack.mitre.org/techniques/T1071/","https://www.snort.org/faq/what-is-snort"]', 'equals("log.alert_category", "threat_intel") &&
exists("origin.ip") &&
oneOf("log.threat_type", ["malicious_ip", "c2_server", "known_malware", "botnet"])
', '2026-02-09 16:52:31.768258', true, false, 'origin', null, '[{"indexPattern":"v11-log-suricata-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-30m","count":3}]', '["lastEvent.log.threat_type","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (529, 'Tor Proxy/Gateway DNS Lookup Detected', 3, 2, 1, 'Command and Control', 'T1090.003 - Proxy: Multi-hop Proxy', 'Detects DNS lookups to known Tor proxy and gateway domains. These services allow web traffic to be routed through the Tor network without installing the Tor browser, commonly used by attackers to anonymize C2 traffic or access dark web resources from corporate networks.

Next Steps:
1. Investigate the source host for malware using Tor for C2 communications
2. Determine if the user has a legitimate reason to access Tor services
3. Block Tor proxy domains at the DNS resolver level
4. Check for data exfiltration through Tor-routed connections
5. Review the host for other indicators of compromise
6. Implement network controls to block Tor relay IPs at the firewall
7. Monitor for Tor bridge connections as an evasion technique
', '["https://attack.mitre.org/techniques/T1090/003/","https://github.com/SigmaHQ/sigma/blob/master/rules/network/zeek/zeek_dns_torproxy.yml"]', 'equals("log.eventType", "dns") &&
exists("log.dns.query") &&
exists("origin.ip") &&
(
  contains("log.dns.query", ".torproject.org") ||
  contains("log.dns.query", ".tor2web.") ||
  contains("log.dns.query", ".onion.to") ||
  contains("log.dns.query", ".onion.cab") ||
  contains("log.dns.query", ".onion.nu") ||
  contains("log.dns.query", ".onion.link") ||
  contains("log.dns.query", ".onion.it") ||
  contains("log.dns.query", ".onion.city") ||
  contains("log.dns.query", ".onion.direct") ||
  contains("log.dns.query", ".onion.top") ||
