  contains("log.dns.query", ".onion.lu") ||
  contains("log.dns.query", ".darknet.to") ||
  contains("log.dns.query", ".onion.foundation") ||
  endsWith("log.dns.query", ".torproxy.io") ||
  endsWith("log.dns.query", ".tor-gateways.de") ||
  endsWith("log.dns.query", ".torstorm.org") ||
  endsWith("log.dns.query", ".tor.taxi") ||
  endsWith("log.dns.query", ".tor.direct") ||
  endsWith("log.dns.query", ".torghost.com") ||
  endsWith("log.dns.query", ".tor.gs") ||
  endsWith("log.dns.query", ".tor.cat") ||
  endsWith("log.dns.query", ".tor.haus") ||
  endsWith("log.dns.query", ".tor.rocks") ||
  endsWith("log.dns.query", ".tor.lol") ||
  endsWith("log.dns.query", ".onion.in.net") ||
  endsWith("log.dns.query", ".onion.glass") ||
  endsWith("log.dns.query", ".onion.ms") ||
  endsWith("log.dns.query", ".onion.gg") ||
  endsWith("log.dns.query", ".tor.pm")
)
', '2026-02-09 16:52:31.922243', true, false, 'origin', null, '[]', '["lastEvent.log.dns.query","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (530, 'Tunneling Detection', 3, 2, 1, 'Command and Control', 'T1572 - Protocol Tunneling', 'Detects various tunneling techniques including SSH tunneling, HTTP tunneling, VPN over non-standard ports, and protocol mismatches. Tunneling is used by attackers to bypass network security controls and establish covert communication channels.

Next Steps:
1. Verify the legitimacy of the detected tunneling activity
2. Check if the source IP is authorized to establish tunneled connections
3. Analyze the destination and ports being used for tunneling
4. Review network traffic patterns for data exfiltration indicators
5. Investigate the purpose and content of the tunneled traffic
6. Consider blocking the source IP if activity is confirmed malicious
7. Review firewall rules to prevent unauthorized tunneling protocols
', '["https://attack.mitre.org/techniques/T1572/","https://docs.suricata.io/en/latest/output/eve/eve-json-format.html"]', '(
  (equals("log.eventType", "alert") &&
   (contains("log.alert.signature", "SSH") &&
    !equals("target.port", 22))) ||
  (equals("log.appProto", "ssh") &&
   !equals("target.port", 22)) ||
  (equals("protocol", "TCP") &&
   equals("target.port", 443) &&
   !equals("log.appProto", "tls")) ||
  (equals("log.eventType", "alert") &&
   contains("log.alert.signature", "tunnel")) ||
  (equals("target.port", 53) &&
   equals("protocol", "TCP") &&
   greaterThan("log.flow.bytes_toserver", 5000))
)
', '2026-02-09 16:52:32.048347', true, false, 'origin', null, '[{"indexPattern":"v11-log-suricata-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"target.port","operator":"filter_term","value":"{{target.port}}"}],"or":null,"within":"now-30m","count":5}]', '["adversary.ip","target.port"]');
