(equals("log.pa_subtype", "dns") ||
 (contains("log.message", "DNS") && contains("log.message", ["sinkhole", "DGA", "tunnel", "malicious"]))) &&
(oneOf("log.act", ["sinkhole", "block-url", "alert", "drop"]) ||
 exists("log.DNSSICategory")) &&
exists("origin.ip")
', '2026-02-09 16:53:32.531854', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-paloalto-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"log.pa_subtype","operator":"filter_term","value":"dns"}],"or":null,"within":"now-30m","count":3}]', '["adversary.ip","target.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (534, 'PAN-OS Spyware and Vulnerability Threat Detection', 3, 3, 2, 'Intrusion Detection', 'T1190 - Exploit Public-Facing Application', 'Detects spyware and vulnerability threat detections from PAN-OS threat prevention engine. These alerts indicate active exploitation attempts, spyware callbacks, or known vulnerability exploitation against protected hosts.

Next Steps:
1. Investigate the source and target of the detected threat
2. Review the specific threat ID and signature for vulnerability details
3. Check if the attack was blocked or only alerted
4. Verify the target system is patched against the exploited vulnerability
5. Scan the target system for signs of compromise if the threat was not blocked
6. Update threat prevention signatures and review security profiles
', '["https://docs.paloaltonetworks.com/pan-os/10-2/pan-os-admin/threat-prevention","https://attack.mitre.org/techniques/T1190/"]', 'equals("log.pa_type", "THREAT") &&
