insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (535, 'PAN-OS Malicious URL Category Block', 3, 2, 1, 'Command and Control', 'T1071.001 - Application Layer Protocol: Web Protocols', 'Detects URL filtering blocks for malicious, phishing, or command-and-control URL categories on Palo Alto firewalls. Repeated blocks from the same host may indicate malware infection or compromised credentials.

Next Steps:
1. Investigate the internal host that attempted to access the malicious URL
2. Review the URL category and specific blocked domain for threat context
3. Check if the user clicked a phishing link in email
4. Scan the host for malware if the URL was a C2 callback
5. Review other connections from the same host for additional IOCs
6. Block the destination domain at DNS level for defense in depth
', '["https://docs.paloaltonetworks.com/pan-os/10-2/pan-os-admin/url-filtering","https://attack.mitre.org/techniques/T1071/001/"]', 'equals("log.pa_type", "THREAT") &&
equals("log.pa_subtype", "url") &&
oneOf("log.act", ["block-url", "block-page", "block-override", "alert"]) &&
(oneOf("log.urlCategory", ["malware", "phishing", "command-and-control", "grayware", "hacking"]) ||
 contains("log.category", ["malware", "phishing", "command-and-control", "grayware", "hacking"]))
