insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (537, 'Zero-Day Exploit Prevention', 3, 3, 3, 'Execution', 'T1203 - Exploitation for Client Execution', 'Detects potential zero-day exploits blocked by Palo Alto''s threat prevention engine. This rule triggers on high-severity vulnerability attempts and unknown threat patterns that may indicate zero-day exploit attempts. The rule looks for THREAT type events with vulnerability or exploit subtypes that have high or critical severity, and either contain CVE references or are categorized as unknown threats.

Next Steps:
1. Investigate the source IP address and determine if it''s internal or external
2. Review the specific threat ID and vulnerability details in Palo Alto logs
3. Check if the exploit attempt was successful or blocked
4. Analyze network traffic patterns from the source IP for additional malicious activity
5. Update threat prevention signatures if a new zero-day is confirmed
6. Consider blocking the source IP if it shows persistent malicious behavior
7. Review and strengthen endpoint security on potentially targeted systems
', '["https://docs.paloaltonetworks.com/threat-prevention/administration/best-practices/best-practices-for-securing-your-network-from-layer-4-and-layer-7-evasions/evasion-signatures","https://attack.mitre.org/techniques/T1203/"]', 'equals("log.pa_type", "THREAT") && oneOf("log.pa_subtype", ["vulnerability", "exploit"]) && oneOf("log.severityLabel", ["high", "critical"]) && (contains("log.pa_threatid", "CVE") || equals("log.category", "unknown"))', '2026-02-09 16:53:33.232292', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-paloalto-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"log.pa_type","operator":"filter_term","value":"THREAT"}],"or":null,"within":"now-30m","count":2}]', '["adversary.ip","target.ip"]');
