 (exists("log.spypri") && !equals("log.spypri", "0"))) &&
(equals("action", "blocked") || equals("log.fw_action", "drop"))
', '2026-02-09 16:53:33.742351', true, false, 'origin', '["adversary.ip","target.host"]', '[{"indexPattern":"v11-log-firewall-sonicwall-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-1h","count":3}]', null);
