6. Document the incident and update threat intelligence feeds
', '["https://www.sonicwall.com/support/knowledge-base/capture-atp-overview/170503785055490","https://attack.mitre.org/techniques/T1204/"]', '(contains("log.msg", "Capture ATP") || contains("log.msg", "Gateway Anti-Virus") || contains("log.msg", "Sandbox") || equals("log.category", "Anti-Virus") || equals("log.af_type", "ATP")) && (contains("log.msg", "malicious") || contains("log.msg", "blocked") || contains("log.msg", "threat detected") || equals("log.result", "malicious") || equals("action", "blocked"))', '2026-02-09 16:53:33.947017', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-sonicwall-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-1h","count":2}]', '["adversary.host","adversary.ip"]');
