8. Document findings for threat intelligence and future prevention
', '["https://www.sonicwall.com/solutions/advanced-threats/encrypted-threats/","https://attack.mitre.org/techniques/T1573/"]', '(contains("log.eventName", "SSL") || contains("log.eventName", "TLS") || contains("log.eventName", "encrypted") || contains("log.eventName", "DPI-SSL") || contains("log.message", "SSL") || contains("log.message", "TLS") || contains("log.message", "encrypted") || contains("protocol", "SSL") || contains("protocol", "TLS")) &&
(contains("log.eventName", "threat") || contains("log.eventName", "malware") || contains("log.eventName", "blocked") || contains("log.eventName", "violation") || contains("log.message", "threat") || contains("log.message", "malware") || contains("log.message", "blocked") || equals("log.result", "blocked") || equals("action", "blocked") || exists("log.ipscat") || exists("log.spycat"))
', '2026-02-09 16:53:34.247577', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-sonicwall-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-30m","count":3}]', '["adversary.ip","target.ip"]');
