 contains("log.category", "Intrusion Prevention") ||
 (exists("log.ipspri") && !equals("log.ipspri", "0"))) &&
(equals("action", "blocked") || equals("log.fw_action", "drop"))
', '2026-02-09 16:53:34.517699', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-sonicwall-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-15m","count":3}]', '["adversary.ip","target.ip"]');
