6. Enable account lockout and two-factor authentication
', '["https://www.sonicwall.com/techdocs/pdf/sonicos-6-5-4-log-events-reference-guide.pdf","https://attack.mitre.org/techniques/T1110/"]', '((contains("log.message", ["admin", "management", "login"]) &&
  contains("log.message", ["fail", "denied", "invalid", "incorrect"])) ||
 contains("log.eventName", ["Administrator login failed", "Login failure"]) ||
 contains("log.category", "Authentication Access")) &&
exists("origin.ip")
', '2026-02-09 16:53:34.693327', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-sonicwall-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-15m","count":10}]', '["adversary.ip","adversary.user"]');
