insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (550, 'SonicWall SSL VPN Authentication Failures', 3, 2, 1, 'Credential Access', 'T1133 - External Remote Services', 'Detects multiple SSL VPN authentication failures from the same source IP on SonicWall firewalls, indicating brute force or credential stuffing attacks against remote access services.

Next Steps:
1. Investigate the source IP and check threat intelligence databases
2. Verify if the targeted user accounts exist and are active
