', '2026-02-09 16:53:35.281978', true, false, 'origin', null, '[{"indexPattern":"v11-log-syslog-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-15m","count":5}]', '["lastEvent.log.deviceVendor","adversary.ip"]');
