)
', '2026-02-09 16:53:35.732606', true, false, 'origin', null, '[]', '["adversary.hostname","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (555, 'ESXi Firewall Rule Modification Detection', 2, 3, 2, 'Defense Evasion', 'T1562.004 - Impair Defenses: Disable or Modify System Firewall', 'Detects modifications to ESXi firewall ruleset configurations using esxcli network firewall commands. Attackers modify firewall rules to enable outbound connections for C2 communication or to expose management interfaces.

Next Steps:
1. Review the specific firewall rule changes
2. Verify the changes were authorized maintenance operations
3. Check if new inbound or outbound rules were added
4. Restore default firewall rules if unauthorized
5. Investigate what traffic the rule changes would allow
6. Monitor network traffic for newly allowed connections
', '["https://kb.vmware.com/s/article/2008226","https://attack.mitre.org/techniques/T1562/004/"]', 'exists("log.message") &&
(
  contains("log.message", "esxcli network firewall") ||
  (contains("log.message", "firewall") && contains("log.message", "ruleset")) ||
  contains("log.message", "esxcli network firewall set --enabled false") ||
  (contains("log.message", "firewall") && (
    contains("log.message", "allowedip add") ||
