    regexMatch("log.winlog.event_data.TargetObject", "(?i)\\\\Environment\\\\UserInitMprLogonScript$")
  ) &&
  !regexMatch("log.winlog.event_data.Details", "(?i)^C:\\\\Windows\\\\system32\\\\userinit\\.exe,?\\s*$") &&
  !regexMatch("log.winlog.event_data.Details", "(?i)^explorer\\.exe\\s*$")
) ||
(
  (equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)reg(.exe)?\\s+add.*Winlogon.*(Userinit|Shell)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)reg(.exe)?\\s+add.*Winlogon.*(Userinit|Shell)") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)reg(.exe)?\\s+add.*UserInitMprLogonScript") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)reg(.exe)?\\s+add.*UserInitMprLogonScript")
  )
)
