Next Steps:
1. Investigate the certificate request details including the requesting user/machine
2. Verify if the certificate request was legitimate and authorized
3. Check for any recent changes to Certificate Authority policies or templates
4. Review Certificate Authority logs for other suspicious certificate issuance
5. Examine the requesting host for signs of compromise
6. Consider revoking any suspicious certificates issued
7. Validate Certificate Authority security configurations and access controls
', '["https://www.splunk.com/en_us/blog/security/breaking-the-chain-defending-against-certificate-services-abuse.html","https://attack.mitre.org/techniques/T1558/"]', '(equals("log.winlogEventId", "4886") || equals("log.winlogEventId", "4887")) && equals("log.winlogProviderName", "Microsoft-Windows-Security-Auditing") && (contains("log.winlogEventDataSubjectUserName", "$") || equals("log.winlogEventDataSubjectUserName", "ANONYMOUS LOGON"))', '2026-02-09 16:55:27.782041', true, false, 'origin', null, '[]', '["lastEvent.log.winlogEventDataSubjectUserName","adversary.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (577, 'Certutil LOLBIN Abuse Detection', 2, 3, 1, 'Defense Evasion', 'T1105 - Ingress Tool Transfer', 'Detects abuse of certutil.exe as a Living Off The Land Binary (LOLBIN) for downloading files from URLs,
encoding/decoding Base64 payloads, and NTLM coercion. Certutil is a legitimate Windows certificate
utility that is frequently abused by attackers for payload staging and defense evasion because it is
