insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (578, 'CMSTP UAC Bypass Detection', 2, 3, 1, 'Defense Evasion', 'T1218.003 - System Binary Proxy Execution: CMSTP', 'Detects CMSTP.exe (Microsoft Connection Manager Profile Installer) being used to bypass UAC
and AppLocker restrictions. Attackers use CMSTP with specially crafted .inf files containing
malicious commands in the RunPreSetupCommandsSection to execute arbitrary code with elevated
privileges. This is a well-known UAC bypass technique.

Next Steps:
