) &&
(
  regexMatch("log.winlog.event_data.CommandLine", "(?i)/s\\s+.*\\.inf") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)/ni\\s+/s\\s+") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)/au\\s+") ||
  regexMatch("log.winlogEventDataCommandLine", "(?i)/s\\s+.*\\.inf") ||
