)
', '2026-02-09 16:55:28.102454', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (579, 'Cobalt Strike Process Behavior Detection', 3, 3, 2, 'Execution', 'T1059 - Command and Scripting Interpreter', 'Detects Cobalt Strike beacon process creation patterns that are distinct from normal system behavior.
These include rundll32.exe spawned without command-line arguments, dllhost.exe or runonce.exe spawning
cmd.exe or powershell, and characteristic post-exploitation process injection patterns. Cobalt Strike
is the most widely used commercial adversary simulation tool and is frequently found in real attacks.

Next Steps:
1. Examine the parent-child process relationships for injection patterns
2. Check for rundll32 with no arguments (classic beacon default)
3. Review named pipe activity on the host for CS pipe names
4. Check for network beaconing behavior from the suspicious process
5. Memory scan the suspicious processes for CS beacon shellcode
6. Isolate the affected host immediately
7. Hunt for lateral movement from this host to other systems
8. Review the C2 infrastructure and block at network perimeter
', '["https://attack.mitre.org/software/S0154/","https://thedfirreport.com/2021/08/29/cobalt-strike-a-defenders-guide/","https://redcanary.com/threat-detection-report/threats/cobalt-strike/"]', '(equals("log.eventCode", "4688") || equals("log.winlogEventId", 4688)) &&
(
  (
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)rundll32\\.exe$") &&
    (
      !exists("log.winlog.event_data.CommandLine") ||
      regexMatch("log.winlog.event_data.CommandLine", "(?i)^\"?[A-Z]:\\\\Windows\\\\(System32|SysWOW64)\\\\rundll32\\.exe\"?\\s*$")
    )
  ) ||
  (
    regexMatch("log.winlog.event_data.ParentProcessName", "(?i)(dllhost\\.exe|runonce\\.exe|searchprotocolhost\\.exe)$") &&
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)(cmd\\.exe|powershell\\.exe|pwsh\\.exe)$")
  ) ||
  (
    regexMatch("log.winlog.event_data.ParentProcessName", "(?i)rundll32\\.exe$") &&
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)(cmd\\.exe|powershell\\.exe|pwsh\\.exe)$") &&
    !exists("log.winlog.event_data.ParentCommandLine")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(MSSE-\\d+-server|status_\\d+|postex_\\d+|msagent_\\d+)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)(MSSE-\\d+-server|status_\\d+|postex_\\d+|msagent_\\d+)")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)\\\\\\\\\\.\\\\.pipe\\\\(MSSE-|postex_|status_|msagent_)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)\\\\\\\\\\.\\\\.pipe\\\\(MSSE-|postex_|status_|msagent_)")
  )
)
', '2026-02-09 16:55:28.247505', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (657, 'Windows: Deleting Backup Catalogs with Wbadmin', 1, 2, 3, 'Impact', 'T1490 - Inhibit System Recovery', 'Identifies use of the wbadmin.exe to delete the backup catalog. Ransomware and other malware may do this to prevent system recovery.', '["https://attack.mitre.org/tactics/TA0040/","https://attack.mitre.org/techniques/T1490/"]', 'regexMatch("log.message", "(delete(.+)catalog|catalog(.+)delete)") && regexMatch("log.winlogEventDataProcessName", "(wbadmin.exe|WBADMIN.EXE)")', '2026-02-09 16:57:23.376637', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (683, 'Windows: Privilege Escalation via Named Pipe Impersonation', 3, 3, 2, 'Privilege Escalation', 'T1134 - Access Token Manipulation', 'Identifies a privilege escalation attempt via named pipe impersonation. An adversary may abuse this technique by utilizing a framework such Metasploit''s meterpreter getsystem command.', '["https://attack.mitre.org/tactics/TA0004/","https://attack.mitre.org/techniques/T1134/"]', 'regexMatch("log.winlogEventDataProcessName", "(Cmd.Exe|PowerShell.EXE|powershell.exe|cmd.exe)") && contains("log.message", ">") && regexMatch("log.message", "(\\\\.\\pipe\\)")', '2026-02-09 16:57:27.032450', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (580, 'COM Hijacking Persistence Detection', 2, 3, 1, 'Persistence', 'T1546.015 - Event Triggered Execution: Component Object Model Hijacking', 'Detects COM (Component Object Model) hijacking used for persistence by modifying InProcServer32
or LocalServer32 registry values. Attackers replace legitimate COM object DLLs with malicious ones
to achieve persistence, as the malicious DLL will be loaded whenever the COM object is instantiated.
This is a stealthy persistence mechanism that is difficult to detect without registry monitoring.

Next Steps:
1. Examine the modified InProcServer32/LocalServer32 value to identify the malicious DLL
2. Verify if the new DLL path points to a legitimate or suspicious location
3. Check the original COM object registration for comparison
4. Analyze the replacement DLL in a sandbox
5. Identify the CLSID being hijacked and what software uses it
6. Restore the original COM registration
7. Search for similar COM hijacking across other endpoints
', '["https://attack.mitre.org/techniques/T1546/015/","https://pentestlab.blog/2020/05/20/persistence-com-hijacking/","https://bohops.com/2018/08/18/abusing-the-com-registry-structure-clsid-localserver32-inprocserver32/"]', 'equals("log.eventCode", "4657") &&
equals("log.winlogChannel", "Security") &&
regexMatch("log.winlog.event_data.ObjectName", "(?i)(InProcServer32|LocalServer32)") &&
(
  regexMatch("log.winlog.event_data.NewValue", "(?i)(\\\\Temp\\\\|\\\\Downloads\\\\|\\\\AppData\\\\|\\\\ProgramData\\\\|\\\\Users\\\\Public\\\\|\\\\Desktop\\\\)") ||
  regexMatch("log.winlog.event_data.NewValue", "(?i)(rundll32|regsvr32|mshta|powershell|cmd\\.exe|wscript|cscript)") ||
  regexMatch("log.winlog.event_data.NewValue", "(?i)scrobj\\.dll") ||
  regexMatch("log.winlog.event_data.NewValue", "(?i)(http://|https://)") ||
  !regexMatch("log.winlog.event_data.NewValue", "(?i)^(C:\\\\Windows\\\\|C:\\\\Program Files)")
) &&
!regexMatch("log.winlogEventDataSubjectUserName", "(?i)^(SYSTEM|TrustedInstaller)$")
', '2026-02-09 16:55:28.402474', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (581, 'Credential Dump via Registry Export', 3, 2, 1, 'Credential Access', 'T1003.004 - OS Credential Dumping: LSA Secrets', 'Detects credential dumping via registry export of SAM, SYSTEM, and SECURITY hives using
reg.exe save commands. Attackers export these hives to extract password hashes offline using
tools like secretsdump.py or samdump2. This technique is commonly used after gaining local
administrator privileges.

Next Steps:
1. Identify the user account executing the reg save commands
2. Check if SAM, SYSTEM, and SECURITY hives were all exported (indicates deliberate extraction)
3. Search for the output files on disk and check if they were exfiltrated
4. Review for follow-up pass-the-hash or credential reuse activity
5. Reset all local account passwords on the affected system
6. Investigate how the attacker obtained local administrator privileges
7. Check for domain credential exposure if SECURITY hive was exported
', '["https://attack.mitre.org/techniques/T1003/004/","https://www.sans.org/blog/protecting-privileged-domain-accounts-safeguarding-password-hashes/","https://pentestlab.blog/2018/07/04/dumping-domain-password-hashes/"]', '(equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
(
