insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (588, 'ETW Patching and Tampering Detection', 3, 3, 2, 'Defense Evasion', 'T1562.006 - Impair Defenses: Indicator Blocking', 'Detects attempts to tamper with Event Tracing for Windows (ETW) to blind security tools.
Attackers patch ETW functions in memory (NtTraceEvent, EtwEventWrite) or use PowerShell
Reflection to disable .NET ETW providers, preventing security tools from receiving telemetry.
This technique is frequently used before executing post-exploitation tools to evade detection.

Next Steps:
1. Investigate the process that attempted ETW tampering
2. Check what malicious activity followed the ETW patching
3. Review PowerShell script block logs for ETW manipulation code
4. Examine if the .NET ETW provider was targeted (common for AMSI bypass chains)
5. Verify that ETW providers are functioning correctly after remediation
6. Search for additional evasion techniques on the same host
7. Isolate the host and investigate the full attack chain
', '["https://attack.mitre.org/techniques/T1562/006/","https://blog.xpnsec.com/hiding-your-dotnet-etw/","https://www.mdsec.co.uk/2020/03/hiding-your-net-etw/"]', '(
  (equals("log.eventCode", "4104") || equals("log.eventCode", "4103")) &&
  equals("log.winlogProviderName", "Microsoft-Windows-PowerShell") &&
  (
    contains("log.winlog.event_data.ScriptBlockText", "EtwEventWrite") ||
    contains("log.winlog.event_data.ScriptBlockText", "NtTraceEvent") ||
    contains("log.winlog.event_data.ScriptBlockText", "NtTraceControl") ||
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)\\[Reflection\\.Assembly\\].*ETW") ||
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)Patch.*ETW|ETW.*Patch") ||
    contains("log.winlog.event_data.ScriptBlockText", "EventProvider") ||
    contains("log.winlogEventDataScriptBlockText", "EtwEventWrite") ||
    contains("log.winlogEventDataScriptBlockText", "NtTraceEvent")
  )
) ||
(
  (equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)logman.*stop.*EventLog") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)logman.*stop.*EventLog") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)auditpol.*/clear") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)auditpol.*/clear") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)Set-EtwTraceProvider.*0x0") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)Set-EtwTraceProvider.*0x0")
  )
)
', '2026-02-09 16:55:29.686961', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (589, 'DPAPI Domain Backup Key Extraction', 3, 3, 1, 'Credential Access', 'T1003.004 - OS Credential Dumping: LSA Secrets', 'Detects extraction of the DPAPI domain backup key from a domain controller. The BCKUPKEY secret
object contains the domain''s DPAPI backup key which can be used to decrypt any DPAPI-protected
data for all domain users, including passwords, certificates, and other sensitive data. This is
a high-severity credential access technique that indicates an attacker has domain admin access.

Next Steps:
1. Verify the account accessing the BCKUPKEY object is authorized (should only be DC replication)
2. Check if the source host is a legitimate domain controller
3. Review the user account for signs of compromise
4. Investigate for related DCSync or NTDS.dit extraction attempts
5. Assume all DPAPI-protected secrets are compromised if unauthorized
6. Rotate the DPAPI domain backup key (requires careful planning)
7. Reset credentials for all privileged accounts
', '["https://attack.mitre.org/techniques/T1003/004/","https://www.dsinternals.com/en/retrieving-dpapi-backup-keys-from-active-directory/","https://adsecurity.org/?p=1785"]', 'equals("log.eventCode", "4662") &&
equals("log.winlogChannel", "Security") &&
contains("log.winlog.event_data.Properties", "BCKUPKEY") &&
contains("log.winlog.event_data.ObjectServer", "DS") &&
!regexMatch("log.winlogEventDataSubjectUserName", "(?i)\\$$")
', '2026-02-09 16:55:29.911876', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (607, 'Network Sniffer and Packet Capture Detection', 3, 1, 0, 'Discovery', 'T1040 - Network Sniffing', 'Detects execution of network sniffing and packet capture tools that could be used to
intercept network traffic, capture credentials, or perform man-in-the-middle attacks.
Monitors for known sniffer binaries, raw socket creation, and promiscuous mode indicators.

Next Steps:
1. Verify if the packet capture tool usage was authorized (IT/security staff)
2. Check which user account executed the tool and validate their role
3. Determine what network interfaces were targeted for capture
4. Review if any sensitive data (credentials, tokens) may have been captured
5. Check for data exfiltration - captured packets being sent to external destinations
6. Look for lateral movement from the host running the sniffer
7. Investigate if the sniffer was installed recently or is part of standard tooling
', '["https://attack.mitre.org/techniques/T1040/","https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/event-4688","https://www.sans.org/reading-room/whitepapers/detection/detecting-network-sniffers-1180"]', '(
  (equals("log.eventCode", "4688") || equals("log.winlogEventId", 4688)) &&
  (
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)(wireshark|tshark|dumpcap|windump|tcpdump|rawcap|netsh\\.exe|pktmon\\.exe)\\.exe$") ||
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)(ettercap|NetworkMiner|Microsoft Network Monitor|nmcap)\\.exe$") ||
    regexMatch("log.winlogEventDataProcessName", "(?i)(wireshark|tshark|dumpcap|windump|tcpdump|rawcap)\\.exe$") ||
    (
      regexMatch("log.winlog.event_data.NewProcessName", "(?i)netsh\\.exe$") &&
      regexMatch("log.winlog.event_data.CommandLine", "(?i)(trace\\s+start|capture\\s+start)")
