insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (590, 'Event Log Clearing Detection', 3, 3, 2, 'Defense Evasion', 'T1070.001 - Indicator Removal on Host: Clear Windows Event Logs', 'Detects when Windows event logs are cleared, which is often done by attackers to cover their tracks and remove evidence of malicious activities. This rule monitors for Event ID 1102 (Security log cleared), Event ID 104 (System log cleared), and command-line activities using wevtutil or PowerShell cmdlets to clear event logs.

Next Steps:
1. Identify the user account that performed the log clearing operation
2. Review the timeline of events before the log clearing to identify potential malicious activities
3. Check for any remaining forensic artifacts in other log sources (network logs, endpoint logs, etc.)
4. Investigate if this was authorized maintenance or potential malicious activity
5. Review user privileges and access patterns for the account involved
6. Consider implementing additional logging and monitoring for critical systems
', '["https://attack.mitre.org/techniques/T1070/001/","https://www.ultimatewindowssecurity.com/securitylog/encyclopedia/event.aspx?eventid=1102"]', 'equals("log.winlogEventId", "1102") ||
equals("log.eventCode", "1102") ||
