 contains("log.winlogChannel", "System")) ||
(equals("log.winlogEventId", "4688") &&
 ((contains("log.winlogEventDataCommandLine", "wevtutil") &&
   contains("log.winlogEventDataCommandLine", " cl ")) ||
  contains("log.winlogEventDataCommandLine", "Clear-EventLog") ||
  contains("log.winlogEventDataCommandLine", "Remove-EventLog") ||
  contains("log.winlogEventDataCommandLine", "Limit-EventLog")))
', '2026-02-09 16:55:30.057015', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (591, 'Golden Ticket Attack Detection', 3, 3, 3, 'Credential Access', 'T1558.001 - Steal or Forge Kerberos Tickets: Golden Ticket', 'Detects Golden Ticket attacks where adversaries forge Kerberos TGTs using the KRBTGT account
hash, granting unlimited domain access. The rule detects anomalous TGT usage patterns including
TGS requests with unusual encryption types, tickets with abnormally long lifetimes, and Kerberos
authentication from non-domain-controller sources for the KRBTGT service.

Next Steps:
1. Immediately verify if the KRBTGT account password has been compromised
2. Reset the KRBTGT password TWICE to invalidate all existing tickets
3. Identify the source host and investigate for full domain compromise
4. Review all domain admin activity from the suspected timeframe
5. Check for DCSync or NTDS.dit extraction as precursor activities
6. Audit all privileged account access across the domain
7. Consider rebuilding the domain if compromise is confirmed
8. Implement Kerberos armoring and constrained delegation
', '["https://attack.mitre.org/techniques/T1558/001/","https://adsecurity.org/?p=1640","https://www.ultimatewindowssecurity.com/securitylog/encyclopedia/event.aspx?eventID=4769"]', '(
  equals("log.eventCode", "4769") &&
  equals("log.winlogChannel", "Security") &&
  equals("log.winlog.event_data.ServiceName", "krbtgt") &&
  !equals("log.winlog.event_data.Status", "0x0") &&
  exists("log.winlog.event_data.IpAddress")
) ||
(
  equals("log.eventCode", "4768") &&
  equals("log.winlogChannel", "Security") &&
  !oneOf("log.winlog.event_data.TicketEncryptionType", ["0x12", "0x11"]) &&
  exists("log.winlog.event_data.TargetUserName") &&
  !regexMatch("log.winlog.event_data.TargetUserName", "(?i)\\$$")
) ||
(
  equals("log.eventCode", "4672") &&
  equals("log.winlogChannel", "Security") &&
  contains("log.winlog.event_data.PrivilegeList", "SeTcbPrivilege") &&
  !regexMatch("log.winlogEventDataSubjectUserName", "(?i)^(SYSTEM|LOCAL SERVICE|NETWORK SERVICE)$") &&
  !regexMatch("log.winlogEventDataSubjectUserName", "(?i)\\$$")
)
', '2026-02-09 16:55:30.207385', true, false, 'origin', null, '[{"indexPattern":"v11-log-wineventlog-*","with":[{"field":"origin.host","operator":"filter_term","value":"{{origin.host}}"}],"or":null,"within":"now-30m","count":3}]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (592, 'GPO Tampering Detection', 2, 3, 2, 'Defense Evasion, Privilege Escalation', 'T1484.001 - Domain Policy Modification: Group Policy Modification', 'Detects modifications to Group Policy Objects (GPOs) which could indicate an adversary attempting to escalate privileges, deploy malware across the domain, or establish persistence. GPO tampering is a common technique used by attackers to enforce malicious configurations or deploy payloads to multiple systems simultaneously.

**Next Steps:**
1. Immediately review the specific GPO that was modified and identify what changes were made
2. Verify if the modification was authorized by checking with the responsible administrator
3. Examine the user account that made the changes for signs of compromise
4. Review recent authentication logs for the user account to identify potential lateral movement
5. Check domain controllers for additional suspicious activities around the same timeframe
6. If unauthorized, immediately revert the GPO changes and investigate the compromise vector
7. Consider temporarily disabling the affected user account pending investigation
', '["https://learn.microsoft.com/en-us/windows-server/identity/ad-ds/manage/component-updates/command-line-process-auditing","https://attack.mitre.org/techniques/T1484/001/"]', 'equals("log.winlogEventId", "5136") && equals("log.winlogProviderName", "Microsoft-Windows-Security-Auditing") && contains("log.winlogEventDataObjectDN", "CN=Policies,CN=System")', '2026-02-09 16:55:30.352267', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (593, 'Image File Execution Options Debugger Persistence', 3, 3, 2, 'Persistence', 'T1546.012 - Event Triggered Execution: Image File Execution Options Injection', 'Detects abuse of Image File Execution Options (IFEO) registry keys to establish persistence
or redirect program execution. Attackers set the Debugger value under IFEO to hijack
execution of legitimate programs (like accessibility tools sethc.exe, utilman.exe, narrator.exe)
and redirect them to cmd.exe or other malicious payloads. This technique is also used for
persistence through GlobalFlag and SilentProcessExit monitoring.

Next Steps:
1. Check which program''s IFEO key was modified and what debugger was set
2. Verify if accessibility tool hijacking was used (sethc, utilman, narrator, magnify, osk)
3. Remove the malicious Debugger registry value
4. Check for RDP access if accessibility tools were hijacked (sticky keys attack)
5. Investigate the user account that made the registry modification
6. Search for additional persistence mechanisms
7. Review recent RDP login activity on the affected host
', '["https://attack.mitre.org/techniques/T1546/012/","https://blog.malwarebytes.com/101/2015/12/an-introduction-to-image-file-execution-options/","https://oddvar.moe/2018/04/10/persistence-using-globalflags-in-image-file-execution-options/"]', '(
  equals("log.eventCode", "13") &&
  equals("log.winlog.provider_name", "Microsoft-Windows-Sysmon") &&
  regexMatch("log.winlog.event_data.TargetObject", "(?i)\\\\Image File Execution Options\\\\.*\\\\(Debugger|GlobalFlag|MonitorProcess)$") &&
  !regexMatch("log.winlog.event_data.Details", "(?i)(werfault|drwtsn32|vsjitdebugger|windbg)")
) ||
(
  (equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)reg(.exe)?\\s+add.*Image File Execution Options.*Debugger") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)reg(.exe)?\\s+add.*Image File Execution Options.*Debugger")
  )
)
', '2026-02-09 16:55:30.512604', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
