insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (594, 'Impacket Lateral Movement Detection', 3, 3, 2, 'Lateral Movement', 'T1021.002 - Remote Services: SMB/Windows Admin Shares', 'Detects Impacket framework lateral movement patterns including wmiexec, smbexec, dcomexec, and atexec.
Impacket is the most commonly used lateral movement framework in real-world attacks. The characteristic
pattern involves cmd.exe /Q /c with output redirection to 127.0.0.1 via named pipes or ADMIN$ share,
as well as specific command-line patterns unique to each Impacket module.

Next Steps:
1. Identify the source of the lateral movement and the compromised credentials used
2. Examine the full command line for data exfiltration or payload delivery
3. Check for Impacket artifacts in the ADMIN$ share or temp directories
4. Review authentication logs for the credential source
5. Isolate affected hosts and block lateral movement paths
6. Reset credentials for all accounts used in the lateral movement
7. Hunt for Impacket usage across all domain-joined systems
8. Review network logs for SMB traffic patterns consistent with Impacket
', '["https://attack.mitre.org/techniques/T1021/002/","https://github.com/fortra/impacket","https://www.13cubed.com/downloads/impacket_exec_commands_cheat_sheet.pdf"]', '(equals("log.eventCode", "4688") || equals("log.winlogEventId", 4688)) &&
(
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)cmd\\.exe\\s+/Q\\s+/c\\s+.+\\s+1>\\s*\\\\\\\\127\\.0\\.0\\.1\\\\") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)cmd\\.exe\\s+/Q\\s+/c\\s+.+\\s+1>\\s*\\\\\\\\127\\.0\\.0\\.1\\\\")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)cmd\\.exe\\s+/Q\\s+/c\\s+.+\\s+2>&1") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)cmd\\.exe\\s+/Q\\s+/c\\s+.+\\s+2>&1")
  ) ||
  (
    regexMatch("log.winlog.event_data.ParentProcessName", "(?i)wmiprvse\\.exe$") &&
    regexMatch("log.winlog.event_data.CommandLine", "(?i)cmd\\.exe\\s+/Q\\s+/c")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)\\\\__output\\s") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)\\\\__output\\s")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)cmd\\.exe\\s+/C\\s+.+\\\\ADMIN\\$\\\\__\\d+\\.\\d+") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)cmd\\.exe\\s+/C\\s+.+\\\\ADMIN\\$\\\\__\\d+\\.\\d+")
  )
)
', '2026-02-09 16:55:30.672382', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
