    regexMatch("log.winlog.event_data.CommandLine", "(?i)(GetAsyncKeyState|GetKeyState|GetKeyboardState|SetWindowsHookEx|SetWindowsHookExW|SetWindowsHookExA)") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(keylog|key.?log|key.?stroke|key.?capture|keystroke.?log)") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(Get-Clipboard|Set-Clipboard|clipboard.?monitor|ClipboardChanged)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)(GetAsyncKeyState|GetKeyState|SetWindowsHookEx)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)(keylog|key.?log|key.?stroke|key.?capture)")
  )
) ||
(
  (equals("log.eventCode", "4104") || equals("log.winlogEventId", 4104)) &&
