  (
    contains("log.winlog.event_data.ScriptBlockText", "GetAsyncKeyState") ||
    contains("log.winlog.event_data.ScriptBlockText", "GetKeyboardState") ||
    contains("log.winlog.event_data.ScriptBlockText", "SetWindowsHookEx") ||
