    contains("log.winlog.event_data.ScriptBlockText", "MapVirtualKey") ||
    contains("log.winlog.event_data.ScriptBlockText", "Get-Keystrokes") ||
    contains("log.winlog.event_data.ScriptBlockText", "Invoke-Keylogger") ||
    (
      contains("log.winlog.event_data.ScriptBlockText", "user32.dll") &&
