insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (598, 'Regsvr32 LOLBIN Abuse Detection', 3, 3, 2, 'Defense Evasion', 'T1218.010 - System Binary Proxy Execution: Regsvr32', 'Detects suspicious regsvr32.exe usage including Squiblydoo attacks (loading remote SCT files),
AppLocker bypass techniques, and execution of DLLs from suspicious locations. Regsvr32 is a
signed Microsoft binary that can be abused to proxy execution of malicious code, bypassing
application whitelisting controls.

Next Steps:
1. Examine the DLL or SCT file being loaded by regsvr32
2. Check if a remote URL was used (Squiblydoo attack indicator)
3. Analyze the parent process that launched regsvr32
4. Review network connections made by the regsvr32 process
5. Check if the loaded DLL is from a suspicious location (Temp, AppData, etc.)
6. Block the remote URL if a network-based attack was used
7. Investigate what payload was delivered through the proxy execution
', '["https://attack.mitre.org/techniques/T1218/010/","https://pentestlab.blog/2017/05/11/applocker-bypass-regsvr32/","https://lolbas-project.github.io/lolbas/Binaries/Regsvr32/"]', '(equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
(
  regexMatch("log.winlog.event_data.NewProcessName", "(?i)regsvr32\\.exe$") ||
  regexMatch("log.winlogEventDataProcessName", "(?i)regsvr32\\.exe$")
) &&
(
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)/s.*/u.*/i:") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)/s.*/u.*/i:")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)/i:(http|https|ftp)://") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)/i:(http|https|ftp)://")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)\\.sct") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)\\.sct")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)(\\\\Temp\\\\|\\\\Downloads\\\\|\\\\AppData\\\\|\\\\ProgramData\\\\|\\\\Users\\\\Public\\\\)") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)(\\\\Temp\\\\|\\\\Downloads\\\\|\\\\AppData\\\\|\\\\ProgramData\\\\|\\\\Users\\\\Public\\\\)")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)scrobj\\.dll") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)scrobj\\.dll"))
)
', '2026-02-09 16:55:31.317477', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (599, 'LSASS Credential Dumping Detection', 3, 3, 1, 'Credential Access', 'T1003.001 - OS Credential Dumping: LSASS Memory', 'Detects multiple LSASS credential dumping techniques beyond Mimikatz, including comsvcs.dll MiniDump,
procdump, nanodump, pypykatz, Task Manager dump, rundll32 with comsvcs.dll, and direct NT API calls.
LSASS holds credentials for all authenticated users and is a primary target for credential theft.
This rule complements the existing Mimikatz detection by covering alternative dumping methods.

Next Steps:
1. Immediately isolate the affected host to prevent lateral movement
2. Identify the dumping technique used and the resulting dump file location
3. Check if the dump file has been exfiltrated to an external destination
4. Review the process tree to understand how the dumping tool was executed
5. Reset passwords for all accounts that were logged into the compromised system
6. Enable Credential Guard or RunAsPPL to protect LSASS
7. Search for the same dumping technique across other endpoints
8. Investigate the initial compromise vector
', '["https://attack.mitre.org/techniques/T1003/001/","https://www.microsoft.com/en-us/security/blog/2022/10/05/detecting-and-preventing-lsass-credential-dumping-attacks/","https://redcanary.com/threat-detection-report/techniques/lsass-memory/"]', '(equals("log.eventCode", "4688") || equals("log.winlogEventId", 4688)) &&
(
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)comsvcs\\.dll[,\\s]+(MiniDump|#24)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)comsvcs\\.dll[,\\s]+(MiniDump|#24)")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)procdump.*-ma\\s+(lsass|\\d+)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)procdump.*-ma\\s+(lsass|\\d+)")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)rundll32\\.exe.*comsvcs") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)rundll32\\.exe.*comsvcs")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(nanodump|handlekatz|physmem2profit|dumpert)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)(nanodump|handlekatz|physmem2profit|dumpert)")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)taskmgr.*lsass") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)taskmgr.*lsass")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(Out-Minidump|Get-Process.*lsass.*\\.DumpProcess)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)(Out-Minidump|Get-Process.*lsass.*\\.DumpProcess)")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)sqldumper\\.exe.*lsass") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)sqldumper\\.exe.*lsass")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)createdump\\.exe.*(-f|--full)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)createdump\\.exe.*(-f|--full)")
  )
)
', '2026-02-09 16:55:31.677305', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (600, 'LSASS Memory Dump Alternatives', 3, 3, 1, 'Credential Access', 'T1003.001 - OS Credential Dumping: LSASS Memory', 'Detects alternatives to Mimikatz for dumping LSASS process memory, including procdump.exe,
comsvcs.dll MiniDump via rundll32, Task Manager LSASS dump, and direct process access to LSASS.
These tools are commonly used by attackers who avoid Mimikatz to extract credentials from memory.

Next Steps:
1. Isolate the affected host immediately to prevent lateral movement
2. Identify the user account and parent process that initiated the dump
3. Check if procdump or comsvcs.dll was used and from what directory
4. Review for any exfiltration of the dump file to external destinations
5. Reset all credentials that were potentially exposed on the affected host
6. Investigate how the attacker obtained the privileges needed for LSASS access
7. Search for evidence of credential reuse across the environment
', '["https://attack.mitre.org/techniques/T1003/001/","https://www.microsoft.com/en-us/security/blog/2022/10/05/detecting-and-preventing-lsass-credential-dumping-attacks/","https://redcanary.com/threat-detection-report/techniques/lsass-memory/"]', '(
  (equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
  (
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)procdump.*lsass") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)procdump.*lsass")) ||
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)rundll32.*comsvcs\\.dll.*MiniDump") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)rundll32.*comsvcs\\.dll.*MiniDump")) ||
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)Out-Minidump.*lsass") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)Out-Minidump.*lsass")) ||
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)taskmgr.*lsass") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)taskmgr.*lsass")) ||
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)sqldumper\\.exe.*lsass") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)sqldumper\\.exe.*lsass")) ||
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)createdump\\.exe.*lsass") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)createdump\\.exe.*lsass")) ||
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)rdrleakdiag\\.exe.*lsass") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)rdrleakdiag\\.exe.*lsass"))
  )
) ||
(
  equals("log.eventCode", "10") &&
  regexMatch("log.winlog.event_data.TargetImage", "(?i)lsass\\.exe$") &&
  oneOf("log.winlog.event_data.GrantedAccess", ["0x1010", "0x1038", "0x1fffff", "0x1410", "0x143a"])
)
', '2026-02-09 16:55:31.787234', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (601, 'Malicious PowerShell Execution', 3, 3, 2, 'Execution', 'T1059.001 - Command and Scripting Interpreter: PowerShell', 'Detects malicious PowerShell execution patterns including encoded commands, download cradles,
AMSI bypass attempts, execution policy bypasses, and common offensive PowerShell techniques.
These patterns are frequently used by attackers for initial access, lateral movement, and
payload delivery.

Next Steps:
1. Isolate the affected host immediately
2. Decode any Base64-encoded command content for analysis
3. Check parent process - unexpected parents (e.g., Word, Excel) indicate macro-based attacks
4. Review network connections for download cradle destinations
5. Examine PowerShell transcription and script block logs for full command content
6. Search for persistence mechanisms created by the script
7. Check if AMSI was successfully bypassed and what payload was executed
8. Correlate with any recent phishing emails received by the user
', '["https://attack.mitre.org/techniques/T1059/001/","https://docs.microsoft.com/en-us/powershell/module/microsoft.powershell.core/about/about_logging","https://www.fireeye.com/blog/threat-research/2016/02/greater_visibility_t.html"]', '(
  (equals("log.eventCode", "4688") || equals("log.winlogEventId", 4688)) &&
  (
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)powershell\\.exe$|pwsh\\.exe$") ||
    regexMatch("log.winlogEventDataProcessName", "(?i)powershell\\.exe$|pwsh\\.exe$")
  ) &&
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)-[eE][nN][cC]\\s+[A-Za-z0-9+/=]{50,}") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(-nop|-noni|-w\\s+hidden|-ep\\s+bypass|-exec\\s+bypass)") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(DownloadString|DownloadFile|DownloadData|WebClient|Invoke-WebRequest|wget|curl|Start-BitsTransfer)") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(Invoke-Expression|IEX|Invoke-Command)\\s*[\\(\\{]") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(Net\\.WebClient|IO\\.MemoryStream|IO\\.StreamReader|IO\\.Compression)") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(FromBase64String|ToBase64String|\\[Convert\\]::)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)-[eE][nN][cC]\\s+[A-Za-z0-9+/=]{50,}") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)(-nop|-noni|-w\\s+hidden|-ep\\s+bypass|-exec\\s+bypass)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)(DownloadString|DownloadFile|DownloadData|WebClient|Invoke-WebRequest)")
  )
) ||
(
  (equals("log.eventCode", "4104") || equals("log.winlogEventId", 4104)) &&
  equals("log.winlogProviderName", "Microsoft-Windows-PowerShell") &&
  (
    contains("log.winlog.event_data.ScriptBlockText", "AmsiInitFailed") ||
    contains("log.winlog.event_data.ScriptBlockText", "amsiContext") ||
    contains("log.winlog.event_data.ScriptBlockText", "AmsiUtils") ||
    contains("log.winlog.event_data.ScriptBlockText", "amsi.dll") ||
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)(Invoke-Obfuscation|Invoke-CradleCrafter|Out-EncodedCommand)") ||
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)(New-Object\\s+Net\\.Sockets\\.TCPClient|Net\\.WebClient\\)?\\.DownloadString)") ||
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)(\\$env:COMSPEC|cmd\\.exe.*/c)") ||
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)(Add-Type.*DllImport|\\[DllImport)") ||
    contains("log.winlog.event_data.ScriptBlockText", "Reflection.Assembly") ||
    contains("log.winlog.event_data.ScriptBlockText", "Invoke-Shellcode") ||
    contains("log.winlogEventDataScriptBlockText", "AmsiInitFailed") ||
    contains("log.winlogEventDataScriptBlockText", "AmsiUtils") ||
    regexMatch("log.winlogEventDataScriptBlockText", "(?i)(Invoke-Obfuscation|Invoke-CradleCrafter|Out-EncodedCommand)")
  )
)
', '2026-02-09 16:55:31.922465', true, false, 'origin', null, '[{"indexPattern":"v11-log-wineventlog-*","with":[{"field":"origin.host","operator":"filter_term","value":"{{origin.host}}"}],"or":null,"within":"now-10m","count":2}]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (602, 'Process Masquerading Detection', 2, 3, 2, 'Defense Evasion', 'T1036.005 - Masquerading: Match Legitimate Name or Location', 'Detects executables masquerading as legitimate Windows system processes but running from
incorrect locations. For example, svchost.exe should only run from C:\Windows\System32,
and explorer.exe should only run from C:\Windows. Malware commonly uses legitimate process
names to avoid detection by analysts and automated tools.

Next Steps:
1. Identify the actual file path of the masquerading process
2. Compare the file hash against known good versions of the legitimate binary
3. Check the digital signature of the suspicious executable
4. Analyze the executable in a sandbox environment
5. Review the parent process that launched the masquerading binary
6. Kill the suspicious process and quarantine the file
7. Search for other instances of the same file across the environment
', '["https://attack.mitre.org/techniques/T1036/005/","https://www.elastic.co/blog/how-hunt-masquerade-ball","https://redcanary.com/threat-detection-report/techniques/masquerading/"]', '(equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
(
  (
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)\\\\svchost\\.exe$") &&
    !regexMatch("log.winlog.event_data.NewProcessName", "(?i)^C:\\\\Windows\\\\(System32|SysWOW64)\\\\svchost\\.exe$")
  ) ||
  (
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)\\\\csrss\\.exe$") &&
    !regexMatch("log.winlog.event_data.NewProcessName", "(?i)^C:\\\\Windows\\\\(System32|SysWOW64)\\\\csrss\\.exe$")
  ) ||
  (
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)\\\\lsass\\.exe$") &&
    !regexMatch("log.winlog.event_data.NewProcessName", "(?i)^C:\\\\Windows\\\\System32\\\\lsass\\.exe$")
  ) ||
  (
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)\\\\services\\.exe$") &&
    !regexMatch("log.winlog.event_data.NewProcessName", "(?i)^C:\\\\Windows\\\\System32\\\\services\\.exe$")
  ) ||
  (
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)\\\\smss\\.exe$") &&
    !regexMatch("log.winlog.event_data.NewProcessName", "(?i)^C:\\\\Windows\\\\System32\\\\smss\\.exe$")
  ) ||
  (
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)\\\\wininit\\.exe$") &&
    !regexMatch("log.winlog.event_data.NewProcessName", "(?i)^C:\\\\Windows\\\\System32\\\\wininit\\.exe$")
  ) ||
  (
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)\\\\explorer\\.exe$") &&
    !regexMatch("log.winlog.event_data.NewProcessName", "(?i)^C:\\\\Windows\\\\explorer\\.exe$")
  ) ||
  (
    regexMatch("log.winlogEventDataProcessName", "(?i)\\\\svchost\\.exe$") &&
    !regexMatch("log.winlogEventDataProcessName", "(?i)^C:\\\\Windows\\\\(System32|SysWOW64)\\\\svchost\\.exe$")
  ) ||
  (
    regexMatch("log.winlogEventDataProcessName", "(?i)\\\\lsass\\.exe$") &&
    !regexMatch("log.winlogEventDataProcessName", "(?i)^C:\\\\Windows\\\\System32\\\\lsass\\.exe$")
  )
)
', '2026-02-09 16:55:32.057137', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (603, 'Mimikatz Tool Usage Detection', 3, 3, 1, 'Credential Access', 'T1003.001 - OS Credential Dumping: LSASS Memory', 'Detects potential Mimikatz credential dumping tool usage through various indicators including characteristic command patterns, LSASS access, and known Mimikatz modules. Mimikatz is a well-known post-exploitation tool used to extract plaintext passwords, hash, PIN code and kerberos tickets from memory.

Next Steps:
1. Immediately isolate the affected host to prevent lateral movement
2. Review the full command line and process execution details
3. Check for any credential theft or privilege escalation activities
4. Examine recent logon events and account usage patterns
5. Scan for additional persistence mechanisms or backdoors
6. Reset passwords for all potentially compromised accounts
7. Review security logs for signs of lateral movement to other systems
8. Conduct forensic analysis of memory dumps and system artifacts
', '["https://attack.mitre.org/techniques/T1003/001/","https://github.com/gentilkiwi/mimikatz","https://docs.microsoft.com/en-us/windows/security/threat-protection/auditing/event-4688"]', '(
  (equals("log.eventCode", "4688") || equals("log.winlogEventId", 4688)) &&
  (
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)mimikatz") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(sekurlsa|kerberos|crypto|vault|lsadump|dpapi)::") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(logonpasswords|pth|golden|silver|ticket)") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)privilege::debug") ||
    contains("log.winlog.event_data.CommandLine", "coffee") ||
    contains("log.winlog.event_data.CommandLine", "kirbi")
  )
) ||
(
  (equals("log.eventCode", "4104") || equals("log.winlogEventId", 4104)) &&
  equals("log.winlogProviderName", "Microsoft-Windows-PowerShell") &&
  (
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)invoke-mimikatz") ||
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)mimikatz\\.ps1") ||
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)DumpCreds|DumpCerts") ||
    contains("log.winlog.event_data.ScriptBlockText", "Win32_ShadowCopy")
  )
) ||
(
  equals("log.eventCode", "10") &&
  regexMatch("log.winlog.event_data.TargetImage", "(?i)lsass\\.exe") &&
  oneOf("log.winlog.event_data.GrantedAccess", ["0x1010", "0x1038", "0x1418", "0x1438"])
)
', '2026-02-09 16:55:32.206941', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (604, 'MSHTA Suspicious Execution Detection', 2, 3, 2, 'Defense Evasion', 'T1218.005 - System Binary Proxy Execution: Mshta', 'Detects suspicious mshta.exe execution patterns including remote HTA file execution, inline
VBScript/JavaScript execution, and COM scriptlet execution. MSHTA is a signed Microsoft binary
that executes Microsoft HTML Applications (HTA) and is frequently abused for initial access,
defense evasion, and payload delivery because it bypasses application whitelisting.

Next Steps:
1. Examine the full command line for remote URLs or inline script content
2. Identify the parent process to determine the initial delivery mechanism
3. Check for downloaded HTA files and analyze their contents
4. Review network connections made by the mshta.exe process
5. Block identified malicious URLs at the proxy/firewall
