  regexMatch("log.winlog.event_data.ObjectName", "(?i)\\\\CurrentControlSet\\\\Control\\\\Lsa\\\\MSV1_0\\\\NtlmMinServerSec") ||
  regexMatch("log.winlog.event_data.ObjectName", "(?i)\\\\CurrentControlSet\\\\Control\\\\Lsa\\\\MSV1_0\\\\RestrictSendingNTLMTraffic") ||
  regexMatch("log.winlog.event_data.ObjectName", "(?i)\\\\CurrentControlSet\\\\Control\\\\Lsa\\\\MSV1_0\\\\AuditReceivingNTLMTraffic") ||
  regexMatch("log.winlog.event_data.ObjectName", "(?i)\\\\CurrentControlSet\\\\Services\\\\Netlogon\\\\Parameters\\\\RequireSignOrSeal")
) &&
!regexMatch("log.winlogEventDataSubjectUserName", "(?i)^(SYSTEM|TrustedInstaller)$")
', '2026-02-09 16:55:33.052802', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (610, 'Pass-the-Hash Attack Detection', 3, 3, 2, 'Lateral Movement', 'T1550.002 - Use Alternate Authentication Material: Pass the Hash', 'Detects Pass-the-Hash attacks by monitoring for NTLM authentication (Event ID 4624) with
LogonType 9 (NewCredentials) or LogonType 3 (Network) from unusual sources, combined with
the use of Seclogon service. Attackers use stolen NTLM hashes to authenticate without
knowing the plaintext password, commonly through tools like Mimikatz sekurlsa::pth,
Impacket, or CrackMapExec.

Next Steps:
1. Identify the source IP and user account used for the NTLM authentication
2. Verify if the source host should be authenticating with NTLM to this target
3. Check for prior credential dumping activity on the source host
4. Review if the authentication was followed by lateral movement or data access
5. Reset the compromised account password and any related accounts
6. Implement NTLM restrictions via Group Policy where possible
7. Enable Windows Defender Credential Guard to protect NTLM hashes
', '["https://attack.mitre.org/techniques/T1550/002/","https://www.sans.org/blog/pass-the-hash-attack-detection/","https://stealthbits.com/blog/how-to-detect-pass-the-hash-attacks/"]', '(
  equals("log.eventCode", "4624") &&
  equals("log.winlogChannel", "Security") &&
  equals("log.winlog.event_data.LogonType", "9") &&
  equals("log.winlog.event_data.AuthenticationPackageName", "Negotiate") &&
  !regexMatch("log.winlogEventDataSubjectUserName", "(?i)^(SYSTEM|LOCAL SERVICE|NETWORK SERVICE|ANONYMOUS LOGON|-|\\$)") &&
  exists("log.winlog.event_data.TargetUserName") &&
  !regexMatch("log.winlog.event_data.TargetUserName", "(?i)\\$$")
) ||
(
