  equals("log.winlogChannel", "Security") &&
  equals("log.winlog.event_data.LogonType", "3") &&
  equals("log.winlog.event_data.LmPackageName", "NTLM V1") &&
  exists("log.winlog.event_data.IpAddress") &&
  !equals("log.winlog.event_data.IpAddress", "-") &&
  !equals("log.winlog.event_data.IpAddress", "::1") &&
  !equals("log.winlog.event_data.IpAddress", "127.0.0.1")
)
', '2026-02-09 16:55:33.207633', true, false, 'origin', null, '[{"indexPattern":"v11-log-wineventlog-*","with":[{"field":"log.winlogEventDataIpAddress","operator":"filter_term","value":"{{log.winlogEventDataIpAddress}}"},{"field":"log.eventCode","operator":"filter_term","value":"4624"}],"or":null,"within":"now-30m","count":3}]', '["lastEvent.log.winlogEventDataIpAddress","adversary.host","adversary.user"]');
