  regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)\\[System\\.Convert\\]::FromBase64String") ||
  regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)IEX\\s*\\(\\s*New-Object") ||
  regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)-enc\\s+[A-Za-z0-9+/=]{100,}") ||
  regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)\\$DoIt\\s*=\\s*@") ||
  regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)\\[System\\.Text\\.Encoding\\]::Unicode\\.GetString") ||
  contains("log.winlog.event_data.ScriptBlockText", "Invoke-Shellcode") ||
  contains("log.winlog.event_data.ScriptBlockText", "Invoke-ReflectivePEInjection") ||
  contains("log.winlog.event_data.ScriptBlockText", "Invoke-Mimikatz")
)
', '2026-02-09 16:55:33.596740', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (614, 'Print Spooler Exploitation Detection', 3, 3, 2, 'Privilege Escalation', 'T1068 - Exploitation for Privilege Escalation', 'Detects potential PrintNightmare exploitation attempts through suspicious print spooler activity including DLL loading and driver installation. This rule identifies suspicious activity related to the Print Spooler service that could indicate CVE-2021-34527 (PrintNightmare) exploitation attempts.

Next Steps:
1. Investigate the affected host for unauthorized driver installations
2. Check for recent DLL files placed in the print spooler drivers directory
3. Review print spooler service logs for unusual activity
4. Examine process execution context and parent processes
5. Verify if print driver installations were authorized
6. Check for lateral movement from the affected system
7. Consider isolating the affected host if exploitation is confirmed
', '["https://msrc.microsoft.com/update-guide/vulnerability/CVE-2021-34527","https://attack.mitre.org/techniques/T1068/"]', '(equals("log.winlogProviderName", "Microsoft-Windows-PrintService") && equals("log.winlogEventId", "316") && contains("log.message", "kernelbase.dll")) || (equals("log.winlogEventDataProcessName", "spoolsv.exe") && contains("log.winlogEventDataTargetFilename", "\\spool\\drivers\\x64\\") && endsWith("log.winlogEventDataTargetFilename", ".dll"))', '2026-02-09 16:55:33.682568', true, false, 'origin', null, '[]', '["lastEvent.log.winlogEventDataTargetFilename","adversary.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (615, 'Process Injection Techniques Detection', 3, 3, 2, 'Defense Evasion, Privilege Escalation', 'T1055 - Process Injection', 'Detects various process injection techniques including CreateRemoteThread, SetWindowsHookEx, and other methods used by malware to inject code into legitimate processes. This rule monitors for suspicious cross-process activities targeting critical Windows processes and detects PowerShell/command line usage of injection APIs.

Next Steps:
1. Investigate the source process and command line arguments for suspicious activity
2. Examine the target process for signs of compromise or abnormal behavior
3. Review process tree and parent-child relationships for the involved processes
4. Check for additional suspicious network connections or file system activities from the same host
5. Analyze memory dumps of target processes if available to confirm injection
6. Review system logs for privilege escalation attempts around the same timeframe
7. Correlate with threat intelligence to identify known malware families using similar techniques
8. Consider isolating the affected system if malicious activity is confirmed
', '["https://attack.mitre.org/techniques/T1055/","https://docs.microsoft.com/en-us/sysinternals/downloads/sysmon","https://www.elastic.co/blog/ten-process-injection-techniques-technical-survey-common-and-trending-process"]', '(
  equals("log.eventCode", "8") &&
  (
    regexMatch("log.winlog.event_data.TargetImage", "(?i)(lsass\\.exe|csrss\\.exe|services\\.exe|winlogon\\.exe|svchost\\.exe|explorer\\.exe)") ||
