  oneOf("log.winlog.event_data.GrantedAccess", ["0x1F0FFF", "0x1F1FFF", "0x1FFFFF", "0x1F3FFF"]) &&
  !regexMatch("log.winlog.event_data.SourceImage", "(?i)(taskmgr\\.exe|procexp\\.exe|procmon\\.exe|svchost\\.exe)")
) ||
(
  (equals("log.eventCode", "4688") || equals("log.winlogEventId", 4688)) &&
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)VirtualAllocEx") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)WriteProcessMemory") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)CreateRemoteThread") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)NtQueueApcThread") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)SetWindowsHookEx") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)RtlCreateUserThread")
  )
) ||
