insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (617, 'RDP Brute Force Attack', 3, 2, 2, 'Credential Access', 'T1110.001 - Brute Force: Password Guessing', 'Detects multiple failed RDP login attempts from the same source IP address, indicating a potential brute force attack. This rule monitors Windows Event ID 4625 (failed logon) with focus on network logon types (type 3) which are commonly used for RDP connections. The rule triggers when 10 or more failed attempts occur from the same IP within 15 minutes.

Next Steps:
1. Investigate the source IP address for malicious indicators and geolocation
2. Check if the targeted user accounts are legitimate and active
3. Review successful logons from the same IP after failed attempts
4. Implement IP blocking or rate limiting for the source address
5. Enable account lockout policies if not already configured
6. Consider implementing multi-factor authentication for RDP access
7. Review RDP access logs for any successful connections during the attack timeframe
', '["https://www.ultimatewindowssecurity.com/securitylog/encyclopedia/event.aspx?eventID=4625","https://attack.mitre.org/techniques/T1110/001/"]', 'equals("log.eventCode", "4625") && equals("log.winlogEventDataLogonType", "3") && exists("log.winlogEventDataIpAddress") && !equals("log.winlogEventDataIpAddress", "-") && !equals("log.winlogEventDataIpAddress", "::1") && !equals("log.winlogEventDataIpAddress", "127.0.0.1")', '2026-02-09 16:55:34.177974', true, false, 'origin', null, '[{"indexPattern":"v11-log-wineventlog-*","with":[{"field":"log.winlogEventDataIpAddress","operator":"filter_term","value":"{{log.winlogEventDataIpAddress}}"},{"field":"log.eventCode","operator":"filter_term","value":"4625"},{"field":"log.winlogEventDataLogonType","operator":"filter_term","value":"3"}],"or":null,"within":"now-15m","count":10}]', '["adversary.ip","target.host"]');
