) &&
(
  regexMatch("log.winlog.event_data.CommandLine", "(?i)comsvcs\\.dll.*(MiniDump|#24)") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)(javascript:|vbscript:)") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)(\\\\Temp\\\\|\\\\Downloads\\\\|\\\\AppData\\\\|\\\\ProgramData\\\\|\\\\Users\\\\Public\\\\).*\\.dll") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)shell32\\.dll.*ShellExec_RunDLL") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)advpack\\.dll.*RegisterOCX") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)url\\.dll.*FileProtocolHandler") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)zipfldr\\.dll.*RouteTheCall") ||
  regexMatch("log.winlogEventDataCommandLine", "(?i)comsvcs\\.dll.*(MiniDump|#24)") ||
  regexMatch("log.winlogEventDataCommandLine", "(?i)(javascript:|vbscript:)") ||
  regexMatch("log.winlogEventDataCommandLine", "(?i)(\\\\Temp\\\\|\\\\Downloads\\\\|\\\\AppData\\\\).*\\.dll")
)
', '2026-02-09 16:55:34.607663', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (621, 'SAM Database Access Attempt', 3, 3, 1, 'Credential Access', 'T1003.002 - OS Credential Dumping: Security Account Manager', 'Detects attempts to access the Security Account Manager (SAM) database, which contains local user account hashes. This activity may indicate credential dumping attempts by attackers trying to extract password hashes for offline cracking or lateral movement.

Next Steps:
1. Immediately investigate the user account and process that accessed the SAM database
2. Check for any unusual processes running on the affected system
3. Review recent logon events and privilege escalation activities
4. Examine network connections from the affected host for lateral movement
5. Consider isolating the affected system if malicious activity is confirmed
6. Review security policies for SAM database access permissions
7. Check for presence of credential dumping tools or suspicious files
', '["https://attack.mitre.org/techniques/T1003/002/","https://learn.microsoft.com/en-us/previous-versions/windows/it-pro/windows-10/security/threat-protection/auditing/event-4661"]', 'equals("log.eventCode", "4663") && 
equals("log.winlogChannel", "Security") &&
(
  endsWith("log.winlog.event_data.ObjectName", "\\SAM") ||
  endsWith("log.winlog.event_data.ObjectName", "\\SECURITY") ||
  endsWith("log.winlog.event_data.ObjectName", "\\SYSTEM")
) &&
oneOf("log.winlog.event_data.AccessMask", ["0x20019", "0x1f01ff", "0x40", "0x20", "0x1"])
', '2026-02-09 16:55:34.738110', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (664, 'Windows: Remote Desktop Enabled in Windows Firewall by Netsh', 3, 3, 1, 'Defense Evasion', 'T1562.004 - Impair Defenses: Disable or Modify System Firewall', 'Identifies use of the network shell utility (netsh.exe) to enable inbound Remote Desktop Protocol (RDP) connections in the Windows Firewall.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1562/004/"]', 'regexMatch("log.winlogEventDataProcessName", "netsh.exe") && regexMatch("log.message", "(action=allow|enable=Yes|enable)") && regexMatch("log.message", "(localport=3389|RemoteDesktop|group=(.+)remote desktop(.+))")', '2026-02-09 16:57:24.361323', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
