insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (622, 'Suspicious Scheduled Task Persistence', 2, 3, 2, 'Persistence', 'T1053.005 - Scheduled Task/Job: Scheduled Task', 'Detects creation of scheduled tasks from suspicious locations or executing suspicious binaries,
which is one of the most common persistence mechanisms used by attackers. The rule monitors
Event ID 4698 (scheduled task creation) for tasks that reference suspicious paths such as
Temp, Downloads, AppData, or ProgramData directories, or execute known LOLBINs like
PowerShell, certutil, rundll32, mshta, regsvr32, or cmd.exe with suspicious arguments.

Next Steps:
1. Examine the full TaskContent XML to understand what the scheduled task executes
2. Identify the user account that created the task and verify authorization
3. Check the task execution path for malicious payloads or scripts
4. Review the trigger schedule for persistence timing patterns
5. Remove the suspicious scheduled task immediately
6. Search for additional persistence mechanisms on the same host
7. Investigate the initial access vector that led to task creation
', '["https://attack.mitre.org/techniques/T1053/005/","https://www.ultimatewindowssecurity.com/securitylog/encyclopedia/event.aspx?eventID=4698","https://posts.specterops.io/abstracting-scheduled-task-creation-6d22febc27e7"]', 'equals("log.eventCode", "4698") &&
equals("log.winlogChannel", "Security") &&
(
  regexMatch("log.winlog.event_data.TaskContent", "(?i)(\\\\Temp\\\\|\\\\Downloads\\\\|\\\\AppData\\\\|\\\\ProgramData\\\\|\\\\Public\\\\|\\\\Users\\\\Public\\\\)") ||
  regexMatch("log.winlog.event_data.TaskContent", "(?i)(powershell|pwsh|cmd\\.exe|certutil|mshta|rundll32|regsvr32|cscript|wscript|msiexec|bitsadmin)") ||
  regexMatch("log.winlog.event_data.TaskContent", "(?i)(-enc\\s|-encodedcommand|-nop|-w\\s+hidden|downloadstring|invoke-expression|iex)") ||
  regexMatch("log.winlog.event_data.TaskContent", "(?i)(http://|https://|ftp://|\\\\\\\\[0-9]+\\.[0-9]+\\.[0-9]+\\.[0-9]+\\\\)")
) &&
!regexMatch("log.winlogEventDataSubjectUserName", "(?i)^(SYSTEM|LOCAL SERVICE|NETWORK SERVICE)$")
', '2026-02-09 16:55:34.877531', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (625, 'Silver Ticket Attack Detection', 3, 3, 2, 'Credential Access', 'T1558.002 - Steal or Forge Kerberos Tickets: Silver Ticket', 'Detects Silver Ticket attacks where adversaries forge Kerberos TGS tickets using a service
account''s NTLM hash, bypassing the KDC entirely. Unlike Golden Tickets, Silver Tickets target
specific services. The rule detects TGS tickets presented without corresponding TGT requests,
and service access events with anomalous Kerberos authentication patterns.

Next Steps:
1. Identify the targeted service and its associated service account
2. Verify if the service account hash has been compromised via Kerberoasting
3. Reset the targeted service account password immediately
4. Review access logs for the targeted service for unauthorized activity
5. Check for prior Kerberoasting activity targeting the same service SPN
6. Investigate the source host for compromise indicators
7. Implement AES-only encryption for service accounts
8. Enable Kerberos PAC validation on the targeted services
', '["https://attack.mitre.org/techniques/T1558/002/","https://adsecurity.org/?p=2011","https://www.sans.org/blog/kerberos-in-the-crosshairs-golden-tickets-silver-tickets-mitm-and-more/"]', 'equals("log.eventCode", "4769") &&
equals("log.winlogChannel", "Security") &&
(
  equals("log.winlog.event_data.TicketEncryptionType", "0x17") &&
  !regexMatch("log.winlog.event_data.ServiceName", "(?i)(krbtgt|\\$$)") &&
  !oneOf("log.winlog.event_data.Status", ["0x0", "0x6"]) &&
  exists("log.winlog.event_data.IpAddress")
)
', '2026-02-09 16:55:35.318520', true, false, 'origin', null, '[{"indexPattern":"v11-log-wineventlog-*","with":[{"field":"log.winlogEventDataIpAddress","operator":"filter_term","value":"{{log.winlogEventDataIpAddress}}"}],"or":null,"within":"now-15m","count":5}]', '["lastEvent.log.winlogEventDataIpAddress","adversary.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (626, 'Sliver C2 Framework Detection', 3, 3, 2, 'Execution', 'T1059 - Command and Scripting Interpreter', 'Detects Sliver C2 framework execution patterns and artifacts. Sliver is an increasingly popular
open-source C2 framework replacing Cobalt Strike in many threat actor toolkits. The rule monitors
for characteristic Sliver implant patterns including specific PowerShell stager patterns,
named pipe names, and executable naming conventions.

Next Steps:
1. Identify the Sliver implant type (HTTP, HTTPS, mTLS, DNS, WireGuard)
2. Check for network beaconing to C2 infrastructure
3. Review the process tree for injection and post-exploitation activity
4. Memory scan affected processes for Sliver implant shellcode
5. Isolate the compromised host immediately
6. Block identified C2 domains and IPs at the network perimeter
7. Hunt for Sliver artifacts across all endpoints
8. Review initial access vector (phishing, exploitation, etc.)
', '["https://github.com/BishopFox/sliver","https://www.microsoft.com/en-us/security/blog/2022/08/24/looking-for-the-sliver-lining-hunting-for-emerging-command-and-control-frameworks/","https://www.cybereason.com/blog/sliver-c2-leveraged-by-many-threat-actors"]', '(
  (equals("log.eventCode", "4688") || equals("log.winlogEventId", 4688)) &&
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(sliver|sliverpb|silver-implant)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)(sliver|sliverpb|silver-implant)") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)\\\\\\\\.\\\\pipe\\\\(sliverpb|sliver-)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)\\\\\\\\.\\\\pipe\\\\(sliverpb|sliver-)") ||
    regexMatch("log.winlog.event_data.NewProcessName", "(?i)(DECISIVE_|MANAGING_|IMPRESSED_|LITERARY_|ENORMOUS_)") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)\\$s=New-Object\\s+IO\\.MemoryStream.*FromBase64String.*IO\\.Compression\\.GzipStream.*IO\\.Compression\\.CompressionMode.*ReadToEnd") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)\\$s=New-Object\\s+IO\\.MemoryStream.*FromBase64String.*IO\\.Compression\\.GzipStream")
  )
) ||
(
  (equals("log.eventCode", "4104") || equals("log.winlogEventId", 4104)) &&
  equals("log.winlogProviderName", "Microsoft-Windows-PowerShell") &&
  (
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)\\$s=New-Object\\s+IO\\.MemoryStream.*IO\\.Compression\\.GzipStream.*IO\\.Compression\\.CompressionMode.*ReadToEnd") ||
    contains("log.winlog.event_data.ScriptBlockText", "sliverpb") ||
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)New-Object\\s+System\\.Net\\.Sockets\\.TCPClient.*IO\\.StreamReader.*IO\\.StreamWriter.*GetStream")
  )
)
', '2026-02-09 16:55:35.462027', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (627, 'SMBv1 Usage Detection', 3, 2, 2, 'Lateral Movement', 'T1210 - Exploitation of Remote Services', 'Detects usage of the deprecated and vulnerable SMBv1 protocol which could be exploited for lateral movement or ransomware propagation. SMBv1 is susceptible to numerous security vulnerabilities including EternalBlue and should be disabled in favor of SMBv2/SMBv3.

Next Steps:
1. Immediately investigate the source system using SMBv1 and identify which service or application is still dependent on this protocol
2. Review network traffic logs to determine if this is internal communication or external access attempts
3. Check for any signs of exploitation attempts or successful compromises on the affected system
4. Identify all systems in the environment that may still have SMBv1 enabled
5. Plan migration to SMBv2/SMBv3 and disable SMBv1 on all systems where possible
6. Monitor for any lateral movement patterns that may indicate ongoing compromise
7. Consider implementing network segmentation to limit exposure if SMBv1 cannot be immediately disabled
', '["https://learn.microsoft.com/en-us/windows-server/storage/file-server/troubleshoot/detect-enable-and-disable-smbv1-v2-v3","https://attack.mitre.org/techniques/T1210/"]', 'equals("log.winlogEventId", "3000") && equals("log.winlogProviderName", "Microsoft-Windows-SMBServer") && contains("log.message", "SMB1")', '2026-02-09 16:55:35.601918', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
