  ) &&
  regexMatch("log.winlog.event_data.TargetFilename", "(?i)\\.(exe|dll|bat|cmd|vbs|vbe|js|jse|wsf|wsh|ps1|hta|lnk|scr|pif)$")
) ||
(
  (equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
  (
