     regexMatch("log.winlogEventDataCommandLine", "(?i)copy.*\\\\Start Menu\\\\Programs\\\\Startup")) ||
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)move.*\\\\Start Menu\\\\Programs\\\\Startup") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)move.*\\\\Start Menu\\\\Programs\\\\Startup"))
  )
)
', '2026-02-09 16:55:35.727202', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (629, 'Suspicious Service Installation Detection', 3, 3, 2, 'Persistence', 'T1543.003 - Create or Modify System Process: Windows Service', 'Detects installation of suspicious Windows services matching patterns from Cobalt Strike, Metasploit,
Impacket PSExec, and Meterpreter payloads. Attackers commonly install malicious services for persistence,
privilege escalation (getsystem), and lateral movement. The rule monitors Event ID 4697 for service
installations with characteristic names, binary paths, or command-line patterns used by offensive frameworks.

Next Steps:
1. Examine the service binary path for malicious executables or scripts
2. Check if the service name matches known offensive tool patterns
3. Verify the installing user account and their authorization level
4. Review the service configuration for suspicious startup types
5. Stop and disable the suspicious service immediately
6. Analyze the service binary in a sandbox environment
7. Search for lateral movement indicators from the source host
8. Check for other persistence mechanisms installed by the same actor
', '["https://attack.mitre.org/techniques/T1543/003/","https://www.ultimatewindowssecurity.com/securitylog/encyclopedia/event.aspx?eventID=4697","https://www.sans.org/blog/red-team-tactics-hiding-windows-services/"]', 'equals("log.eventCode", "4697") &&
equals("log.winlogChannel", "Security") &&
(
  regexMatch("log.winlog.event_data.ServiceFileName", "(?i)(cmd\\.exe\\s*/c|powershell|pwsh|%COMSPEC%)") ||
  regexMatch("log.winlog.event_data.ServiceFileName", "(?i)(\\\\ADMIN\\$|\\\\C\\$|127\\.0\\.0\\.1)") ||
  regexMatch("log.winlog.event_data.ServiceFileName", "(?i)(rundll32|msiexec|regsvr32|mshta|certutil|bitsadmin)") ||
  regexMatch("log.winlog.event_data.ServiceName", "(?i)^[a-zA-Z]{4,8}$") ||
  regexMatch("log.winlog.event_data.ServiceFileName", "(?i)(\\\\Temp\\\\|\\\\Downloads\\\\|\\\\AppData\\\\|\\\\ProgramData\\\\|\\\\Users\\\\Public\\\\)") ||
  regexMatch("log.winlog.event_data.ServiceFileName", "(?i)\\.exe\\s+[a-zA-Z0-9+/=]{50,}") ||
  regexMatch("log.winlog.event_data.ServiceName", "(?i)(BTOBTO|meterpreter|msf|payload|beacon|cobalt)") ||
  regexMatch("log.winlog.event_data.ServiceFileName", "(?i)(comsvcs\\.dll|MiniDump|procdump|lsass)")
)
', '2026-02-09 16:55:35.872431', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (630, 'Sysmon Service Tampering Detection', 3, 3, 3, 'Defense Evasion', 'T1562.001 - Impair Defenses: Disable or Modify Tools', 'Detects attempts to tamper with the Sysmon monitoring service including unloading the Sysmon
driver, stopping or deleting the Sysmon service, modifying Sysmon configuration, or renaming
the Sysmon binary. Attackers target Sysmon specifically because it provides rich endpoint
telemetry that enables threat detection. Disabling Sysmon is a critical defense evasion step.

Next Steps:
1. Immediately investigate the process and user that tampered with Sysmon
2. Restore Sysmon service and verify it is running correctly
3. Check if the Sysmon driver is still loaded in the kernel
4. Review what malicious activity occurred during the Sysmon outage
5. Re-apply the Sysmon configuration from a known good backup
6. Investigate the full attack chain that led to Sysmon tampering
7. Consider implementing tamper protection for Sysmon
', '["https://attack.mitre.org/techniques/T1562/001/","https://docs.microsoft.com/en-us/sysinternals/downloads/sysmon","https://undev.ninja/sysmon-evasion-techniques/"]', '(
  (equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
  (
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)sysmon.*-u") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)sysmon.*-u")) ||
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)sc(.exe)?\\s+(stop|delete|config)\\s+sysmon") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)sc(.exe)?\\s+(stop|delete|config)\\s+sysmon")) ||
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)net(.exe)?\\s+stop\\s+sysmon") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)net(.exe)?\\s+stop\\s+sysmon")) ||
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)fltMC(.exe)?\\s+unload\\s+sysmon") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)fltMC(.exe)?\\s+unload\\s+sysmon")) ||
    (regexMatch("log.winlog.event_data.CommandLine", "(?i)taskkill.*/f.*/im\\s+sysmon") ||
     regexMatch("log.winlogEventDataCommandLine", "(?i)taskkill.*/f.*/im\\s+sysmon"))
  )
) ||
(
  equals("log.eventCode", "7045") &&
  regexMatch("log.winlog.event_data.ServiceName", "(?i)sysmon") &&
  !equals("log.winlog.event_data.ServiceType", "kernel mode driver")
)
', '2026-02-09 16:55:36.022480', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (631, 'File Timestomping Detection', 1, 3, 1, 'Defense Evasion', 'T1070.006 - Indicator Removal: Timestomp', 'Detects timestomping activities where attackers modify file creation or modification timestamps
to blend malicious files with legitimate system files. Common tools include PowerShell
Set-ItemProperty, timestomp.exe, NirCmd, and direct API calls to SetFileTime. This technique
is used to evade forensic timeline analysis and make malicious files appear older.

Next Steps:
1. Identify which files had their timestamps modified
2. Check if the modified timestamps match legitimate system file dates (common pattern)
3. Analyze the files with modified timestamps for malicious content
4. Review the process and user that performed the timestamp modification
5. Investigate what the attacker was trying to hide with timestomping
6. Use $MFT analysis to detect original timestamps vs modified ones
7. Search for additional anti-forensic techniques on the same host
', '["https://attack.mitre.org/techniques/T1070/006/","https://www.inversecos.com/2022/04/defence-evasion-technique-timestomping.html","https://andreafortuna.org/2017/10/06/timestomping-what-it-is-and-how-to-detect-it/"]', '(
  equals("log.eventCode", "2") &&
  equals("log.winlog.provider_name", "Microsoft-Windows-Sysmon") &&
  exists("log.winlog.event_data.PreviousCreationUtcTime") &&
  exists("log.winlog.event_data.CreationUtcTime") &&
  !regexMatch("log.winlog.event_data.Image", "(?i)(setup|install|update|patch|msiexec|TiWorker|TrustedInstaller|svchost)\\.exe$")
) ||
(
  (equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)Set-ItemProperty.*CreationTime|Set-ItemProperty.*LastWriteTime|Set-ItemProperty.*LastAccessTime") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)Set-ItemProperty.*CreationTime|Set-ItemProperty.*LastWriteTime|Set-ItemProperty.*LastAccessTime") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)timestomp|SetFileTime|NirCmd.*setfiletime") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)timestomp|SetFileTime|NirCmd.*setfiletime") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)\\[IO\\.File\\]::SetCreationTime|\\[IO\\.File\\]::SetLastWriteTime") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)\\[IO\\.File\\]::SetCreationTime|\\[IO\\.File\\]::SetLastWriteTime")
  )
)
', '2026-02-09 16:55:36.173045', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (632, 'Windows Token Manipulation', 3, 3, 3, 'Defense Evasion, Privilege Escalation', 'Access Token Manipulation', 'Detects potential token manipulation attacks used for privilege escalation. Monitors for suspicious combinations of privileged service calls (4673) and operations on privileged objects (4674) along with special privilege assignments (4672) that include sensitive privileges like SeDebugPrivilege, SeImpersonatePrivilege, or SeTcbPrivilege commonly abused for token manipulation.', '["https://medium.com/palantir/windows-privilege-abuse-auditing-detection-and-defense-3078a403d74e","https://attack.mitre.org/techniques/T1134/"]', 'equals("log.eventCode", "4672") && exists("log.winlogEventDataPrivilegeList") && (contains("log.winlogEventDataPrivilegeList", "SeDebugPrivilege") || contains("log.winlogEventDataPrivilegeList", "SeImpersonatePrivilege") || contains("log.winlogEventDataPrivilegeList", "SeTcbPrivilege") || contains("log.winlogEventDataPrivilegeList", "SeAssignPrimaryTokenPrivilege") || contains("log.winlogEventDataPrivilegeList", "SeLoadDriverPrivilege") || contains("log.winlogEventDataPrivilegeList", "SeRestorePrivilege"))', '2026-02-09 16:55:36.322285', true, false, 'origin', null, '[{"indexPattern":"v11-log-wineventlog-*","with":[{"field":"origin.host","operator":"filter_term","value":"{{origin.host}}"},{"field":"log.winlogEventDataTargetLogonId","operator":"filter_term","value":"{{log.winlogEventDataTargetLogonId}}"},{"field":"log.eventCode","operator":"should_terms","value":"4673,4674"}],"or":null,"within":"now-10m","count":3}]', '["lastEvent.log.winlogEventDataTargetLogonId","lastEvent.log.winlogEventDataTargetUserName","adversary.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (666, 'Windows: Microsoft Build Engine Started by an Office Application', 3, 3, 1, 'Defense Evasion', 'T1127.001 - Trusted Developer Utilities Proxy Execution: MSBuild', 'An instance of MSBuild, the Microsoft Build Engine, was started by Excel or Word. This is unusual behavior for the Build Engine and could have been caused by an Excel or Word document executing a malicious script payload.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1127/001/"]', 'regexMatch("log.winlogEventDataProcessName", "MSBuild.exe") && regexMatch("log.winlogEventDataParentProcessName", "(eqnedt32.exe|excel.exe|fltldr.exe|msaccess.exe|mspub.exe|outlook.exe|powerpnt.exe|winword.exe)")', '2026-02-09 16:57:24.601846', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (633, 'Tunneling Service C2 Detection', 3, 2, 2, 'Command and Control', 'T1572 - Protocol Tunneling', 'Detects execution of tunneling services (ngrok, cloudflared, devtunnels, localtonet, bore, chisel)
that create reverse tunnels for command and control or to expose internal services to the internet.
These tools are increasingly abused by threat actors for persistent C2 channels that bypass
network security controls because traffic appears as legitimate HTTPS connections.

Next Steps:
1. Identify the tunneling tool being used and its configuration
2. Determine what internal service or port is being exposed
3. Check if this is authorized usage (dev/test) or malicious
4. Review the tunnel endpoint for C2 activity
5. Block the tunneling tool and its associated domains at the firewall
6. Terminate the tunnel process and remove the tool
7. Check for data exfiltration through the tunnel
8. Hunt for the same tunneling tool across other endpoints
', '["https://attack.mitre.org/techniques/T1572/","https://www.microsoft.com/en-us/security/blog/2023/05/24/volt-typhoon-targets-us-critical-infrastructure-with-living-off-the-land-techniques/","https://ngrok.com/abuse"]', '(equals("log.eventCode", "4688") || equals("log.winlogEventId", 4688)) &&
(
  regexMatch("log.winlog.event_data.NewProcessName", "(?i)(ngrok|cloudflared|devtunnels|localtonet|bore|chisel|frpc|rathole)\\.exe$") ||
  regexMatch("log.winlogEventDataProcessName", "(?i)(ngrok|cloudflared|devtunnels|localtonet|bore|chisel|frpc|rathole)\\.exe$") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)ngrok\\s+(http|tcp|tls|start)") ||
  regexMatch("log.winlogEventDataCommandLine", "(?i)ngrok\\s+(http|tcp|tls|start)") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)cloudflared\\s+tunnel\\s+(run|--url)") ||
  regexMatch("log.winlogEventDataCommandLine", "(?i)cloudflared\\s+tunnel\\s+(run|--url)") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)devtunnels\\s+(host|create|port)") ||
  regexMatch("log.winlogEventDataCommandLine", "(?i)devtunnels\\s+(host|create|port)") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)chisel\\s+(client|server)") ||
  regexMatch("log.winlogEventDataCommandLine", "(?i)chisel\\s+(client|server)") ||
  regexMatch("log.winlog.event_data.CommandLine", "(?i)frpc\\.exe.*-c") ||
  regexMatch("log.winlogEventDataCommandLine", "(?i)frpc\\.exe.*-c")
)
', '2026-02-09 16:55:36.471975', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (634, 'UAC Bypass Attempt Detection', 3, 3, 2, 'Privilege Escalation, Defense Evasion', 'T1548.002 - Abuse Elevation Control Mechanism: Bypass User Account Control', 'Detects potential UAC bypass attempts by monitoring for processes with elevated privileges that were not launched through the proper UAC consent mechanism. This rule identifies processes running with elevated token types (TokenElevationTypeVirtual) without proper UAC consent flow, which may indicate an attempt to bypass User Account Control security measures.

Next Steps:
1. Investigate the process that triggered the alert - examine the process name, command line arguments, and parent process
2. Check if the process is known legitimate software that should have elevated privileges
3. Verify the user account that launched the process and their normal privilege level
4. Look for other suspicious activities on the same host around the same time
5. Check for known UAC bypass techniques such as DLL hijacking, registry manipulation, or abuse of auto-elevated processes
6. Examine the process execution chain to identify the attack vector
7. Consider isolating the affected system if malicious activity is confirmed
8. Review security policies and UAC settings to prevent similar bypasses
', '["https://attack.mitre.org/techniques/T1548/002/","https://www.ultimatewindowssecurity.com/securitylog/encyclopedia/event.aspx?eventid=4688"]', 'equals("log.winlogEventId", "4688") &&
equals("log.winlogEventDataTokenElevationType", "2") &&
!contains("log.winlogEventDataParentProcessName", "consent.exe") &&
!contains("log.winlogEventDataProcessName", "TrustedInstaller.exe") &&
!contains("log.winlogEventDataSubjectUserName", "SYSTEM") &&
(contains("log.winlogEventDataParentProcessName", "fodhelper.exe") ||
 contains("log.winlogEventDataParentProcessName", "computerdefaults.exe") ||
 contains("log.winlogEventDataParentProcessName", "sdclt.exe") ||
 contains("log.winlogEventDataParentProcessName", "slui.exe") ||
 contains("log.winlogEventDataParentProcessName", "eventvwr.exe") ||
 contains("log.winlogEventDataParentProcessName", "cmstp.exe") ||
 contains("log.winlogEventDataParentProcessName", "msconfig.exe") ||
 contains("log.winlogEventDataParentProcessName", "dccw.exe") ||
 (contains("log.winlogEventDataProcessName", "cmd.exe") || contains("log.winlogEventDataProcessName", "powershell.exe") || contains("log.winlogEventDataProcessName", "pwsh.exe")))
', '2026-02-09 16:55:36.612209', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (635, 'Volume Shadow Copy Deletion', 2, 3, 3, 'Impact', 'T1490 - Inhibit System Recovery', 'Detects deletion of Volume Shadow Copies which is commonly performed by ransomware to prevent recovery of encrypted files. This rule identifies various methods attackers use to delete shadow copies including vssadmin, wmic, PowerShell, wbadmin, and bcdedit commands.

Next Steps:
1. Immediately investigate the affected host for signs of ransomware activity
2. Check for recent file encryption or unusual file modifications
3. Review process execution timeline around the shadow copy deletion
4. Verify if this was legitimate administrative activity or malicious
5. Examine network connections and lateral movement indicators
6. Check backup integrity and consider isolating the system if ransomware is confirmed
7. Review user accounts and privileges involved in the activity
', '["https://attack.mitre.org/techniques/T1490/","https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/vssadmin"]', 'equals("log.winlogEventId", "4688") &&
((endsWith("log.winlogEventDataProcessName", "vssadmin.exe") &&
  (contains("log.winlogEventDataCommandLine", "delete shadows") ||
   (contains("log.winlogEventDataCommandLine", "resize shadowstorage") &&
    contains("log.winlogEventDataCommandLine", "maxsize=")))) ||
 (endsWith("log.winlogEventDataProcessName", "wmic.exe") &&
  contains("log.winlogEventDataCommandLine", "shadowcopy") &&
  contains("log.winlogEventDataCommandLine", "delete")) ||
 (endsWith("log.winlogEventDataProcessName", "powershell.exe") &&
  (contains("log.winlogEventDataCommandLine", "Get-WmiObject") ||
   contains("log.winlogEventDataCommandLine", "gwmi")) &&
  contains("log.winlogEventDataCommandLine", "Win32_ShadowCopy") &&
  contains("log.winlogEventDataCommandLine", "Delete()")) ||
 (endsWith("log.winlogEventDataProcessName", "wbadmin.exe") &&
  contains("log.winlogEventDataCommandLine", "delete") &&
  (contains("log.winlogEventDataCommandLine", "catalog") ||
   contains("log.winlogEventDataCommandLine", "backup"))) ||
 (endsWith("log.winlogEventDataProcessName", "bcdedit.exe") &&
  contains("log.winlogEventDataCommandLine", "recoveryenabled") &&
  contains("log.winlogEventDataCommandLine", "no")))
', '2026-02-09 16:55:36.752335', true, false, 'origin', null, '[]', '["lastEvent.log.winlogEventDataProcessName","adversary.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (636, 'Vulnerable Driver Loading Detection (BYOVD)', 3, 3, 3, 'Privilege Escalation', 'T1068 - Exploitation for Privilege Escalation', 'Detects Bring Your Own Vulnerable Driver (BYOVD) attacks where adversaries load known vulnerable
kernel drivers to disable security tools, escalate privileges, or gain kernel-level access.
This technique is increasingly used by ransomware groups and APTs to bypass endpoint protection.
The rule monitors for service installations loading known vulnerable drivers and suspicious
driver-related command patterns.

Next Steps:
1. Identify the loaded driver and check against known vulnerable driver lists (loldrivers.io)
2. Examine the service installation that loaded the driver
3. Check if endpoint security tools were disabled after driver loading
4. Review the process that installed the vulnerable driver
5. Remove the vulnerable driver and restore security tools
6. Block the driver hash via WDAC or application control policies
7. Check for privilege escalation or security tool tampering after driver load
8. Search for the same driver across other endpoints
', '["https://attack.mitre.org/techniques/T1068/","https://www.loldrivers.io/","https://github.com/magicsword-io/LOLDrivers"]', '(
  equals("log.eventCode", "4697") &&
  equals("log.winlogChannel", "Security") &&
  (
    regexMatch("log.winlog.event_data.ServiceFileName", "(?i)(dbutil_2_3|dbutildrv2|rtcore64|gdrv|asio|ene\\.sys|procexp|viragt64|aswarpot|hw64|cpuz|gmer64|mhyprot2|kdmapper|iqvw64e|echo_driver|winio|amifldrv64|elby|vboxdrv|gpu_temp|nicm|phymemx64|micio64|directio64|blacklotus|irec|zemana)") ||
    regexMatch("log.winlog.event_data.ServiceFileName", "(?i)\\.sys\\s*$")
  )
) ||
(
  (equals("log.eventCode", "4688") || equals("log.winlogEventId", 4688)) &&
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(sc\\.exe|sc)\\s+(create|start)\\s+.*type=\\s*kernel") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)(sc\\.exe|sc)\\s+(create|start)\\s+.*type=\\s*kernel") ||
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(sc\\.exe|sc)\\s+create\\s+.*binPath=.*\\.sys") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)(sc\\.exe|sc)\\s+create\\s+.*binPath=.*\\.sys")
  )
)
', '2026-02-09 16:55:36.887600', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (667, 'Windows: Microsoft Build Engine Started by a Script Process', 3, 3, 2, 'Defense Evasion', 'T1127.001 - Trusted Developer Utilities Proxy Execution: MSBuild', 'An instance of MSBuild, the Microsoft Build Engine, was started by a script or the Windows command interpreter. This behavior is unusual and is sometimes used by malicious payloads.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1127/001/"]', 'regexMatch("log.winlogEventDataProcessName", "MSBuild.exe") && regexMatch("log.winlogEventDataParentProcessName", "(cmd.exe|powershell.exe|wscript.exe|cscript.exe)")', '2026-02-09 16:57:24.742855', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (637, 'Suspicious Admin Share Access Detection', 3, 3, 2, 'Lateral Movement', 'T1021.002 - Remote Services: SMB/Windows Admin Shares', 'Detects suspicious access to Windows administrative shares (C$, ADMIN$, IPC$) which is
commonly used for lateral movement. While admin share access can be legitimate, attackers
use these shares to copy payloads, execute remote commands, and move laterally across the
network. The rule monitors Event ID 5140 (network share access) and Event ID 5145 (detailed
share access) for admin share connections from non-standard sources.

Next Steps:
1. Identify the source IP and user account accessing the admin share
2. Verify if this is authorized administrative access or IT operations
3. Check what files were read or written to the admin share
4. Review if tools or malware were copied via the share
5. Check for service creation or scheduled task creation on the target
6. Correlate with authentication events from the same source IP
7. Block unauthorized admin share access via Group Policy
', '["https://attack.mitre.org/techniques/T1021/002/","https://www.ultimatewindowssecurity.com/securitylog/encyclopedia/event.aspx?eventID=5140","https://www.sans.org/blog/detecting-lateral-movement-using-windows-admin-shares/"]', '(
  equals("log.eventCode", "5140") &&
  equals("log.winlogChannel", "Security") &&
  regexMatch("log.winlog.event_data.ShareName", "(?i)\\\\\\*(C\\$|ADMIN\\$)$") &&
  exists("log.winlog.event_data.IpAddress") &&
  !equals("log.winlog.event_data.IpAddress", "::1") &&
  !equals("log.winlog.event_data.IpAddress", "127.0.0.1") &&
  !regexMatch("log.winlogEventDataSubjectUserName", "(?i)^(SYSTEM|LOCAL SERVICE|NETWORK SERVICE|\\$)") &&
  !regexMatch("log.winlogEventDataSubjectUserName", "(?i)\\$$")
) ||
(
  equals("log.eventCode", "5145") &&
  equals("log.winlogChannel", "Security") &&
  regexMatch("log.winlog.event_data.ShareName", "(?i)\\\\\\*(C\\$|ADMIN\\$)$") &&
  regexMatch("log.winlog.event_data.RelativeTargetName", "(?i)\\.(exe|dll|bat|cmd|ps1|vbs|hta)$") &&
  exists("log.winlog.event_data.IpAddress")
)
', '2026-02-09 16:55:37.037874', true, false, 'origin', null, '[{"indexPattern":"v11-log-wineventlog-*","with":[{"field":"log.winlogEventDataIpAddress","operator":"filter_term","value":"{{log.winlogEventDataIpAddress}}"}],"or":null,"within":"now-30m","count":3}]', '["lastEvent.log.winlogEventDataIpAddress","target.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (638, 'Windows Remote Management (WinRM) Abuse', 3, 3, 2, 'Lateral Movement', 'T1021.006 - Remote Services: Windows Remote Management', 'Detects potential abuse of Windows Remote Management (WinRM) for lateral movement. Monitors for successful logon events (4624) with network logon type 3 combined with privilege escalation (4672) and WinRM-related process activity, indicating remote command execution via WinRM.

Next Steps:
1. Investigate the source IP address and verify if it''s an authorized administrative workstation
2. Review the target user account for any signs of compromise or unusual privilege usage
3. Examine recent PowerShell execution logs and command history on the target system
4. Check for concurrent suspicious activities from the same source IP across other systems
5. Verify if the WinRM connection aligns with scheduled maintenance or authorized administrative tasks
6. Review network traffic patterns between source and target systems for data exfiltration indicators
7. Validate the legitimacy of any processes spawned through the WinRM session
8. Consider implementing additional monitoring for WinRM usage if this represents unexpected activity
', '["https://jpcertcc.github.io/ToolAnalysisResultSheet/details/WinRM.htm","https://attack.mitre.org/techniques/T1021/006/"]', 'equals("log.eventCode", "4624") && equals("log.winlogEventDataLogonType", "3") && exists("log.winlogEventDataProcessName") && (contains("log.winlogEventDataProcessName", "wsmprovhost.exe") || contains("log.winlogEventDataProcessName", "winrshost.exe") || contains("log.winlogEventDataProcessName", "powershell.exe"))', '2026-02-09 16:55:37.177609', true, false, 'origin', null, '[]', '["lastEvent.log.winlogEventDataTargetUserName","adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (639, 'Windows Defender Tampering Detection', 2, 3, 3, 'Defense Evasion', 'T1562.001 - Impair Defenses: Disable or Modify Tools', 'Detects attempts to disable or tamper with Windows Defender components through registry modifications, service stops, or exclusion additions. This includes registry changes to disable antivirus features, stopping Windows Defender services, or using PowerShell commands to modify protection settings.

Next Steps:
1. Investigate the user account and process responsible for the tampering attempt
2. Check if this is part of authorized maintenance or if it''s malicious activity
3. Review recent logon events and process execution history on the affected host
4. Verify Windows Defender configuration and ensure it''s properly restored
5. Scan the system for malware that may have disabled protection
6. Check for other security tool tampering attempts across the environment
', '["https://attack.mitre.org/techniques/T1562/001/","https://docs.microsoft.com/en-us/windows/security/threat-protection/windows-defender-antivirus/troubleshoot-windows-defender-antivirus"]', '(equals("log.winlogEventId", "4657") && 
 contains("log.winlogEventDataObjectName", "\\Windows Defender\\") &&
 (contains("log.winlogEventDataObjectValueName", "DisableAntiSpyware") ||
  contains("log.winlogEventDataObjectValueName", "DisableAntiVirus") ||
  contains("log.winlogEventDataObjectValueName", "DisableRealtimeMonitoring"))) ||
(equals("log.winlogEventId", "7040") && 
 contains("log.winlogEventDataServiceName", "WinDefend") &&
 equals("log.winlogEventDataNewState", "disabled")) ||
(equals("log.winlogEventId", "4688") &&
 contains("log.winlogEventDataCommandLine", "Set-MpPreference") &&
 (contains("log.winlogEventDataCommandLine", "DisableRealtimeMonitoring") ||
  contains("log.winlogEventDataCommandLine", "DisableIOAVProtection") ||
  contains("log.winlogEventDataCommandLine", "DisableBehaviorMonitoring")))
', '2026-02-09 16:55:37.322188', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (640, 'Windows Script Host Suspicious Execution', 3, 3, 2, 'Execution', 'T1059.005 - Command and Scripting Interpreter: Visual Basic', 'Detects suspicious execution of wscript.exe and cscript.exe with potentially malicious script
files or command-line arguments. Attackers commonly use Windows Script Host to execute VBScript
and JScript payloads delivered via phishing emails, drive-by downloads, or as secondary
payloads during an intrusion. The rule focuses on scripts executed from suspicious locations
and with suspicious arguments.

Next Steps:
1. Identify the script file being executed and analyze its contents
2. Check the parent process (e.g., Outlook, Word, browser) for phishing indicators
3. Review the script file location for legitimacy
4. Analyze any network connections made by the script
5. Check if the script downloads or executes additional payloads
6. Search for the same script across other endpoints
7. Block the script and remove any persistence mechanisms it created
', '["https://attack.mitre.org/techniques/T1059/005/","https://lolbas-project.github.io/lolbas/Binaries/Wscript/","https://lolbas-project.github.io/lolbas/Binaries/Cscript/"]', '(equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
(
  regexMatch("log.winlog.event_data.NewProcessName", "(?i)\\\\(wscript|cscript)\\.exe$") ||
  regexMatch("log.winlogEventDataProcessName", "(?i)\\\\(wscript|cscript)\\.exe$")
) &&
(
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)(\\\\Temp\\\\|\\\\Downloads\\\\|\\\\AppData\\\\|\\\\ProgramData\\\\|\\\\Users\\\\Public\\\\)") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)(\\\\Temp\\\\|\\\\Downloads\\\\|\\\\AppData\\\\|\\\\ProgramData\\\\|\\\\Users\\\\Public\\\\)")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)//[eE]:(vbscript|jscript)") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)//[eE]:(vbscript|jscript)")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)(http://|https://|ftp://|\\\\\\\\[0-9])") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)(http://|https://|ftp://|\\\\\\\\[0-9])")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)\\.(vbs|vbe|js|jse|wsf|wsh)\\s+(//B|//nologo)") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)\\.(vbs|vbe|js|jse|wsf|wsh)\\s+(//B|//nologo)")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)(CreateObject|WScript\\.Shell|Scripting\\.FileSystemObject|ADODB\\.Stream)") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)(CreateObject|WScript\\.Shell|Scripting\\.FileSystemObject|ADODB\\.Stream)"))
)
', '2026-02-09 16:55:37.722818', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (668, 'Windows: Microsoft Build Engine Started by a System Process', 3, 3, 2, 'Defense Evasion', 'T1127.001 - Trusted Developer Utilities Proxy Execution: MSBuild', 'An instance of MSBuild, the Microsoft Build Engine, was started by Explorer or the WMI (Windows Management Instrumentation) subsystem. This behavior is unusual and is sometimes used by malicious payloads.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1127/001/"]', 'regexMatch("log.winlogEventDataProcessName", "MSBuild.exe") && regexMatch("log.winlogEventDataParentProcessName", "(explorer.exe|wmiprvse.exe)")', '2026-02-09 16:57:24.877528', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (641, 'WMI Event Subscription Persistence Detection', 2, 3, 2, 'Persistence', 'T1546.003 - Event Triggered Execution: Windows Management Instrumentation Event Subscription', 'Detects creation of WMI event subscriptions used for stealthy persistence. Attackers create
WMI event filters and consumers that execute commands when specific system events occur.
This is a highly effective persistence mechanism because it survives reboots and is difficult
to detect without specific monitoring. The rule monitors for wmic.exe commands creating
event subscriptions and PowerShell WMI subscription creation patterns.

Next Steps:
1. Enumerate all WMI event subscriptions using Get-WMIObject or wmic
2. Examine the event filter conditions and consumer actions
3. Identify the command or script executed by the consumer
4. Remove malicious WMI subscriptions immediately
5. Check for related persistence mechanisms on the same host
6. Review the timeline to identify the initial compromise
7. Search for similar WMI persistence across other endpoints
', '["https://attack.mitre.org/techniques/T1546/003/","https://www.fireeye.com/blog/threat-research/2016/08/wmi_vs_wmi_monitor.html","https://pentestlab.blog/2020/01/21/persistence-wmi-event-subscription/"]', '(equals("log.eventCode", "4688") || equals("log.winlogEventId", 4688)) &&
(
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)wmic.*(/namespace|__EventFilter|__EventConsumer|__FilterToConsumerBinding)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)wmic.*(/namespace|__EventFilter|__EventConsumer|__FilterToConsumerBinding)")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)(Set-WmiInstance|New-CimInstance).*(__EventFilter|__EventConsumer|CommandLineEventConsumer|ActiveScriptEventConsumer)") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)(Set-WmiInstance|New-CimInstance).*(__EventFilter|__EventConsumer|CommandLineEventConsumer|ActiveScriptEventConsumer)")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)Register-WmiEvent") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)Register-WmiEvent")
  ) ||
  (
    regexMatch("log.winlog.event_data.CommandLine", "(?i)mofcomp\\.exe") ||
    regexMatch("log.winlogEventDataCommandLine", "(?i)mofcomp\\.exe")
  )
) ||
(
  (equals("log.eventCode", "4104") || equals("log.winlogEventId", 4104)) &&
  equals("log.winlogProviderName", "Microsoft-Windows-PowerShell") &&
  (
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)(__EventFilter|__EventConsumer|__FilterToConsumerBinding)") ||
    regexMatch("log.winlog.event_data.ScriptBlockText", "(?i)(CommandLineEventConsumer|ActiveScriptEventConsumer)") ||
    contains("log.winlog.event_data.ScriptBlockText", "Register-WmiEvent")
  )
)
', '2026-02-09 16:55:37.832631', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (642, 'WMI Remote Command Execution Detection', 3, 3, 2, 'Lateral Movement', 'T1047 - Windows Management Instrumentation', 'Detects WMI-based remote command execution using wmic.exe /node: parameter or PowerShell
Invoke-WmiMethod / Invoke-CimMethod for lateral movement. Attackers use WMI to execute
commands on remote systems without dropping files to disk, making it a stealthy lateral
movement technique that leverages built-in Windows functionality.

Next Steps:
1. Identify the target host specified in the /node: parameter
2. Verify if this is authorized administrative WMI usage
3. Check what process or command was executed on the remote host
4. Review the credentials used for the WMI connection
5. Search for WMI execution evidence on the target host
6. Check for additional lateral movement from the same source
7. Monitor for process creation events on the target system
', '["https://attack.mitre.org/techniques/T1047/","https://www.fireeye.com/content/dam/fireeye-www/global/en/current-threats/pdfs/wp-windows-management-instrumentation.pdf","https://www.sans.org/blog/wmi-for-detection-and-response/"]', '(equals("log.eventCode", "4688") || equals("log.eventCode", "1")) &&
(
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)wmic(.exe)?\\s+/node:") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)wmic(.exe)?\\s+/node:")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)Invoke-WmiMethod.*-ComputerName") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)Invoke-WmiMethod.*-ComputerName")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)Invoke-CimMethod.*-ComputerName") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)Invoke-CimMethod.*-ComputerName")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)Get-WmiObject.*-ComputerName.*Win32_Process") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)Get-WmiObject.*-ComputerName.*Win32_Process")) ||
  (regexMatch("log.winlog.event_data.CommandLine", "(?i)wmic(.exe)?.*process\\s+call\\s+create") ||
   regexMatch("log.winlogEventDataCommandLine", "(?i)wmic(.exe)?.*process\\s+call\\s+create"))
)
', '2026-02-09 16:55:37.932344', true, false, 'origin', null, '[]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (643, 'Windows: Changes to AdminSDHolder', 1, 2, 3, 'Privilege Escalation', 'T1087 - Account Discovery', 'This rule detects changes to the AdminSDHolder object within the Active Directory.  The AdminSDHolder object is critical to maintaining the ACLs of highly privileged accounts and groups in the domain.  Any unexpected modification to this object could indicate a privilege escalation attempt or malicious action.', '["https://attack.mitre.org/tactics/TA0004/","https://attack.mitre.org/techniques/T1069/"]', 'regexMatch("log.action", "Directory Service Changes") && equals("log.eventCode", 5136) && regexMatch("log.eventDataObjectName", "AdminSDHolder")', '2026-02-09 16:57:21.592824', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (644, 'Windows: Hiding files with attrib.exe', 1, 2, 3, 'Defense Evasion', 'T1564 - Hide Artifacts', 'This correlation rule detects events where the attrib.exe tool is used to hide files on the system.  Cloaking files using this tool can be an indicator of suspicious or malicious activity,  as it could be used by malicious actors to evade detection and hide their presence on the system.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1564/"]', 'regexMatch("log.message", "(attrib +h|attrib.exe +h)")', '2026-02-09 16:57:21.731588', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (645, 'Windows: An attempt was made to set the Directory Services Restore Mode', 1, 2, 3, 'Collection', 'T1005 - Data from Local System', 'This event generates on every attempt made to set the Directory Services Restore Mode. Is a function on Active Directory Domain Controllers to take the server offline for emergency maintenance,  particularly restoring backups of AD objects. It is accessed on Windows Server via the advanced startup menu,  similarly to safe mode.', '["https://attack.mitre.org/tactics/TA0009/","https://attack.mitre.org/techniques/T1005"]', 'equals("log.eventCode", 4794)', '2026-02-09 16:57:21.857127', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (646, 'Windows Defender: Antimalware engine found malware or other potentially unwanted software', 1, 2, 3, 'Execution', 'T1546 - Event Triggered Execution', 'This rule is triggered when the antimalware engine detects malware or potentially unwanted software on the system. This alert is critical to identify the presence of threats and unwanted software that may compromise system security and performance.', '["https://attack.mitre.org/tactics/TA0002/","https://attack.mitre.org/techniques/T1546/"]', 'oneOf("log.eventCode", [1006, 1015, 1116]) && equals("log.winlogProviderName", "SecurityCenter")', '2026-02-09 16:57:22.002605', true, false, 'target', null, '[]', '["target.host","target.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (647, 'Windows: Possible Brute Force Attack', 2, 2, 3, 'Credential Access', 'T1110 - Brute Force', 'This rule is triggered when a pattern of repeated and rapid login attempts from the same IP address or source is detected. These login attempts may target specific user accounts or services in an attempt to crack passwords through automated brute force. The purpose of this rule is to identify possible malicious unauthorized access attempts and prevent a brute force attack against the system.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1110/"]', 'equals("log.eventCode", 4625)', '2026-02-09 16:57:22.123001', true, false, 'origin', null, '[{"indexPattern":"v11-log-wineventlog-*","with":[{"field":"log.eventCode","operator":"filter_term","value":"{{log.eventCode}}"},{"field":"target.user","operator":"filter_term","value":"{{target.user}}"}],"or":null,"within":"now-5m","count":10}]', '["adversary.host","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (648, 'Windows Defender: Protection Disabled', 1, 2, 3, 'Defense Evasion', 'T1562 - Impair Defenses', 'This rule is triggered when it detects that Windows Defender protection has been turned off or disabled on the system. The alert is crucial to identify any unauthorized or malicious actions that may leave the system vulnerable to security threats.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1562/"]', 'oneOf("log.eventCode", [5001, 5012])', '2026-02-09 16:57:22.271978', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (649, 'Windows audit log was cleared', 1, 2, 3, 'Defense Evasion', 'T1070.001 - Indicator Removal: Clear Windows Event Logs', 'Detects when the Windows audit log (Security event log) has been cleared. Adversaries may clear event logs to remove evidence of an intrusion.', '["https://attack.mitre.org/techniques/T1070/001/"]', 'equals("log.eventCode", 1102)', '2026-02-09 16:57:22.382079', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (672, 'Windows: Possible sideloading of DLL via Microsoft antimalware service executable with MsMpEng process', 3, 3, 3, 'Defense Evasion', 'T1574 - Hijack Execution Flow', 'Identifies a Windows trusted program that is known to be vulnerable to DLL Search Order Hijacking starting after being renamed or from a non-standard path. This is uncommon behavior and may indicate an attempt to evade defenses via side-loading a malicious DLL within the memory space of one of those processes.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1574/"]', 'contains("log.winlogEventDataProcessName", "MsMpEng.exe") && !regexMatch("log.winlogEventDataProcessPath", "(:\\ProgramData\\Microsoft\\Windows Defender\\(.+).exe|:\\Program Files\\Windows Defender\\(.+).exe|:\\Program Files (x86)\\Windows Defender\\(.+).exe|:\\Program Files\\Microsoft Security Client\\(.+).exe|:\\Program Files (x86)\\Microsoft Security Client\\(.+).exe)")', '2026-02-09 16:57:25.447540', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (673, 'Windows: Microsoft IIS Service Account Password Dumped', 3, 2, 2, 'Credential Access', 'T1003 - OS Credential Dumping', 'Identifies the Internet Information Services (IIS) command-line tool, AppCmd, being used to list passwords. An attacker with IIS web server access via a web shell can decrypt and dump the IIS AppPool service account password using AppCmd.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1003/"]', 'regexMatch("log.winlogEventDataProcessName", "appcmd.exe") && regexMatch("log.message", "(/list)") && regexMatch("log.message", "(/text(.+)password)")', '2026-02-09 16:57:25.592264', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (674, 'Windows: Microsoft IIS Connection Strings Decryption', 2, 3, 1, 'Credential Access', 'T1003 - OS Credential Dumping', 'Identifies use of aspnet_regiis to decrypt Microsoft IIS connection strings. An attacker with Microsoft IIS web server access via a webshell or alike can decrypt and dump any hardcoded connection strings, such as the MSSQL service account password using aspnet_regiis command.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1003/"]', 'regexMatch("log.winlogEventDataProcessName", "aspnet_regiis.exe") && regexMatch("log.message", "(connectionStrings)") && regexMatch("log.message", "(-pdf)")', '2026-02-09 16:57:25.727013', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (675, 'Windows: IIS HTTP Logging Disabled', 3, 2, 3, 'Defense Evasion', 'T1562.002 - Impair Defenses: Disable Windows Event Logging', 'Identifies when Internet Information Services (IIS) HTTP Logging is disabled on a server. An attacker with IIS server access via a webshell or other mechanism can disable HTTP Logging as an effective anti-forensics measure.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1562/002/"]', 'contains("log.winlogEventDataProcessName", "appcmd.exe") && regexMatch("log.message", "(/dontLog(.+):(.+)True)") && !(contains("log.winlogEventDataParentProcessName", "iissetup.exe"))', '2026-02-09 16:57:25.872866', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (676, 'Windows: LSASS Memory Dump Handle Access', 2, 3, 3, 'Credential Access', 'T1003.001 - OS Credential Dumping: LSASS Memory', 'Identifies handle requests for the Local Security Authority Subsystem Service (LSASS) object access with specific access masks that many tools with a capability to dump memory to disk use (0x1fffff, 0x1010, 0x120089). This rule is tool agnostic as it has been validated against a host of various LSASS dump tools such as SharpDump, Procdump, Mimikatz, Comsvcs etc. It detects this behavior at a low level and does not depend on a specific tool or dump file name.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1003/","https://attack.mitre.org/techniques/T1003/001/"]', 'equals("log.eventCode", 4656) && regexMatch("log.winlogEventDataObjectName", "(:\\Windows\\System32\\lsass.exe|\\Device\\HarddiskVolume[A-Za-z?:\\]([A-Za-z?])?\\Windows\\System32\\lsass.exe)") && !regexMatch("log.winlogEventDataProcessName", "(:\\Program Files\\(.+).exe|:\\Program Files (x86)\\(.+).exe|:\\Windows\\system32\\wbem\\WmiPrvSE.exe|:\\Windows\\System32\\dllhost.exe|:\\Windows\\System32\\svchost.exe|:\\Windows\\System32\\msiexec.exe|:\\ProgramData\\Microsoft\\Windows Defender\\(.+).exe|:\\Windows\\explorer.exe)") && oneOf("log.winlogEventDataAccessMask", ["0x1fffff", "0x1010", "0x120089", "0x1F3FFF"])', '2026-02-09 16:57:26.037623', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (677, 'Windows: Microsoft security essentials - Virus detected', 3, 3, 2, 'Privilege Escalation', 'T1055 - Process Injection', 'Detect the presence of a virus or malware on the system using Microsoft Security Essentials.  The rule correlates different threat detection events, represented by various Event IDs, to identify virus detection on the system.', '["https://attack.mitre.org/tactics/TA0004/","https://attack.mitre.org/techniques/T1055/"]', 'oneOf("log.eventCode", [1107, 1117, 1116, 1118, 1119]) && equals("log.winlogProviderName", "Microsoft Antimalware")', '2026-02-09 16:57:26.177754', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (678, 'Windows: Potential Invoke-Mimikatz PowerShell Script', 3, 3, 2, 'Credential Access', 'T1003.001 - OS Credential Dumping: LSASS Memory', 'Mimikatz is a credential dumper capable of obtaining plaintext Windows account logins and passwords, along with many other features that make it useful for testing the security of networks. This rule detects Invoke-Mimikatz PowerShell script and alike.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1003/","https://attack.mitre.org/techniques/T1003/001/"]', 'regexMatch("log.message", "(DumpCreds(.+)DumpCerts|DumpCerts(.+)DumpCreds|sekurlsa::logonpasswords|crypto::certificates(.+)CERT_SYSTEM_STORE_LOCAL_MACHINE|CERT_SYSTEM_STORE_LOCAL_MACHINE(.+)crypto::certificates)")', '2026-02-09 16:57:26.312528', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (679, 'Windows: Mounting Hidden or WebDav Remote Shares', 3, 2, 1, 'Lateral Movement', 'T1021.002 - Remote Services: SMB/Windows Admin Shares', 'Identifies the use of net.exe to mount a WebDav or hidden remote share. This may indicate lateral movement or preparation for data exfiltration.', '["https://attack.mitre.org/tactics/TA0008/","https://attack.mitre.org/techniques/T1021/002/"]', 'regexMatch("log.winlogEventDataProcessName", "(net.exe|net1.exe)") && regexMatch("log.message", "(\\\\(.+)\\(.+)$|\\\\(.+)@SSL\\|http)") && contains("log.message", "/d") && contains("log.message", "use") && !(contains("log.winlogEventDataParentProcessName", "net.exe"))', '2026-02-09 16:57:26.462534', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (680, 'Windows: Multiple failed attempts to perform a privileged operation by the same user', 1, 2, 3, 'Privilege Escalation', 'T1110 - Brute Force', 'Adversaries may use brute force techniques to gain access to accounts when passwords are unknown or when password hashes are obtained.', '["https://attack.mitre.org/techniques/T1110/"]', 'equals("log.eventCode", 577) || equals("log.eventCode", 4673)', '2026-02-09 16:57:26.607244', true, false, 'origin', null, '[{"indexPattern":"v11-log-wineventlog-*","with":[{"field":"log.eventDataTargetUserName","operator":"filter_term","value":"{{log.eventDataTargetUserName}}"}],"or":null,"within":"now-10m","count":10}]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (686, 'Windows: Persistence via BITS Job Notify Cmdline', 2, 3, 2, 'Persistence', 'T1197 - BITS Jobs', 'An adversary can use the Background Intelligent Transfer Service (BITS) SetNotifyCmdLine method to execute a program that runs after a job finishes transferring data or after a job enters a specified state in order to persist on a system.', '["https://attack.mitre.org/tactics/TA0003/","https://attack.mitre.org/techniques/T1197/"]', 'contains("log.message", "BITS") && contains("log.eventDataParentProcessName", "svchost.exe") && !(regexMatch("log.winlogEventDataProcessName", "(:\\Windows\\System32\\WerFaultSecure.exe|:\\Windows\\System32\\WerFault.exe|:\\Windows\\System32\\wermgr.exe|:\\WINDOWS\\system32\\directxdatabaseupdater.exe)"))', '2026-02-09 16:57:27.643149', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (687, 'Windows: Persistence via TelemetryController Scheduled Task Hijack', 2, 3, 2, 'Persistence', 'T1053.005 - Scheduled Task', 'Detects the successful hijack of Microsoft Compatibility Appraiser scheduled task to establish persistence with an integrity level of system.', '["https://attack.mitre.org/tactics/TA0003/","https://attack.mitre.org/techniques/T1053/005/"]', 'contains("log.message", "-cv") && contains("log.eventDataParentProcessName", "CompatTelRunner.exe") && !(regexMatch("log.winlogEventDataProcessName", "(conhost.exe|DeviceCensus.exe|CompatTelRunner.exe|DismHost.exe|rundll32.exe|powershell.exe)"))', '2026-02-09 16:57:27.782175', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (688, 'Windows: Persistence via Update Orchestrator Service Hijack', 2, 3, 2, 'Persistence', 'T1543.003 - Create or Modify System Process: Windows Service', 'Identifies potential hijacking of the Microsoft Update Orchestrator Service to establish persistence with an integrity level of SYSTEM.', '["https://attack.mitre.org/tactics/TA0003/","https://attack.mitre.org/techniques/T1543/003/"]', 'contains("log.message", "UsoSvc") && 
 regexMatch("log.eventDataParentProcessName", "C:\\\\Windows\\\\System32\\\\svchost\\.exe") && 
 !regexMatch("log.winlogEventDataProcessName", "MoUsoCoreWorker\\.exe|OfficeC2RClient\\.exe") && 
 !regexMatch("log.winlogEventDataProcessName", "ProgramData\\\\Microsoft\\\\Windows\\\\UUS\\\\Packages\\\\.*\\\\amd64\\\\MoUsoCoreWorker\\.exe|Windows\\\\System32\\\\UsoClient\\.exe|Windows\\\\System32\\\\MusNotification\\.exe|Windows\\\\System32\\\\MusNotificationUx\\.exe|Windows\\\\System32\\\\MusNotifyIcon\\.exe|Windows\\\\System32\\\\WerFault\\.exe|Windows\\\\System32\\\\WerMgr\\.exe|Windows\\\\UUS\\\\amd64\\\\MoUsoCoreWorker\\.exe|Windows\\\\System32\\\\MoUsoCoreWorker\\.exe|Windows\\\\UUS\\\\amd64\\\\UsoCoreWorker\\.exe|Windows\\\\System32\\\\UsoCoreWorker\\.exe|Program Files\\\\Common Files\\\\microsoft shared\\\\ClickToRun\\\\OfficeC2RClient\\.exe")
', '2026-02-09 16:57:27.916875', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (689, 'Windows: Suspicious .NET Reflection via PowerShell', 3, 2, 1, 'Defense Evasion', 'T1055 - Process Injection', 'Detects the use of Reflection.Assembly to load PEs and DLLs in memory in PowerShell scripts. Attackers use this method to load executables and DLLs without writing to the disk, bypassing security solutions.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1055/"]', 'regexMatch("log.message", "(\\[Reflection.Assembly\\]::Load)")', '2026-02-09 16:57:28.062391', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (690, 'Windows: Persistence via WMI Event Subscription', 2, 3, 2, 'Persistence', 'T1546.003 - Event Triggered Execution: WMI Event Subscription', 'An adversary can use Windows Management Instrumentation (WMI) to install event filters, providers, consumers, and bindings that execute code when a defined event occurs. Adversaries may use the capabilities of WMI to subscribe to an event and execute arbitrary code when that event occurs, providing persistence on a system.', '["https://attack.mitre.org/tactics/TA0003/","https://attack.mitre.org/techniques/T1546/003/"]', 'contains("log.message", "create") && regexMatch("log.message", "(ActiveScriptEventConsumer|CommandLineEventConsumer)") && contains("log.winlogEventDataProcessName", "wmic.exe")', '2026-02-09 16:57:28.217145', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (691, 'Windows: PowerShell Suspicious Payload Encoded and Compressed', 2, 3, 1, 'Defense Evasion', 'T1027 - Obfuscated Files or Information', 'Identifies the use of .NET functionality for decompression and base64 decoding combined in PowerShell scripts, which malware and security tools heavily use to deobfuscate payloads and load them directly in memory to bypass defenses.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1027/"]', 'regexMatch("log.message", "(FromBase64String)") && regexMatch("log.message", "(System.IO.Compression.DeflateStream|System.IO.Compression.GzipStream|IO.Compression.DeflateStream|IO.Compression.GzipStream)")', '2026-02-09 16:57:28.352028', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (692, 'Windows: PowerShell Share Enumeration Script', 3, 2, 1, 'Discovery', 'T1135 - Network Share Discovery', 'Detects scripts that contain PowerShell functions, structures, or Windows API functions related to windows share enumeration activities. Attackers, mainly ransomware groups, commonly identify and inspect network shares, looking for critical information for encryption and/or exfiltration.', '["https://attack.mitre.org/tactics/TA0007/","https://attack.mitre.org/techniques/T1135/"]', 'regexMatch("log.message", "(Invoke-ShareFinder|Invoke-ShareFinderThreaded|(shi1_netname(.+)shi1_remark)|shi1_remark(.+)shi1_netname|(NetShareEnum(.+)NetApiBufferFree)|(NetApiBufferFree(.+)NetShareEnum))")', '2026-02-09 16:57:28.487359', true, false, 'origin', '["adversary.user","adversary.ip"]', '[]', null);
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (693, 'Windows: PowerShell MiniDump Script', 3, 3, 2, 'Credential Access', 'T1059.001 - Command and Scripting Interpreter: PowerShell', 'This rule detects PowerShell scripts capable of dumping process memory using WindowsErrorReporting or Dbghelp.dll MiniDumpWriteDump. Attackers can use this tooling to dump LSASS and get access to credentials.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1059/001/"]', 'regexMatch("log.message", "(MiniDumpWriteDump|MiniDumpWithFullMemory|pmuDetirWpmuDiniM)")', '2026-02-09 16:57:28.632435', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (694, 'Windows: Suspicious Portable Executable Encoded in Powershell Script', 2, 3, 1, 'Execution', 'T1059 - Command and Scripting Interpreter', 'Detects the presence of a portable executable (PE) in a PowerShell script by looking for its encoded header. Attackers embed PEs into PowerShell scripts to inject them into memory, avoiding defences by not writing to disk.', '["https://attack.mitre.org/tactics/TA0002/","https://attack.mitre.org/techniques/T1059/"]', 'contains("log.message", "TVqQAAMAAAAEAAAA")', '2026-02-09 16:57:28.772158', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (695, 'Windows: Potential Process Injection via PowerShell', 3, 3, 2, 'Defense Evasion', 'T1055 - Process Injection', 'Detects the use of Windows API functions that are commonly abused by malware and security tools to load malicious code or inject it into remote processes.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1055/"]', 'regexMatch("log.message", "(WriteProcessMemory|CreateRemoteThread|NtCreateThreadEx|CreateThread|QueueUserAPC|SuspendThread|ResumeThread|GetDelegateForFunctionPointer)") && regexMatch("log.message", "(VirtualAlloc|VirtualAllocEx|VirtualProtect|LdrLoadDll|LoadLibrary|LoadLibraryA|LoadLibraryEx|GetProcAddress|OpenProcess|OpenProcessToken|AdjustTokenPrivileges)")', '2026-02-09 16:57:28.912487', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (698, 'Windows: PowerShell Suspicious Discovery Related Windows API Functions', 2, 1, 3, 'Discovery', 'T1069 - Permission Groups Discovery', 'This rule detects the use of discovery-related Windows API functions in PowerShell Scripts. Attackers can use these functions to perform various situational awareness related activities, like enumerating users, shares, sessions, domain trusts, groups, etc.', '["https://attack.mitre.org/tactics/TA0007/","https://attack.mitre.org/techniques/T1069/"]', 'contains("log.message", ["NetShareEnum", "NetWkstaUserEnum", "NetSessionEnum", "NetLocalGroupEnum", "NetLocalGroupGetMembers", "DsGetSiteName", "DsEnumerateDomainTrusts", "WTSEnumerateSessionsEx", "WTSQuerySessionInformation", "LsaGetLogonSessionData", "QueryServiceObjectSecurity"])
', '2026-02-09 16:57:29.362698', true, false, 'origin', '["adversary.user","adversary.ip"]', '[]', null);
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (699, 'Windows: PowerShell Script with Token Impersonation Capabilities', 3, 3, 2, 'Privilege Escalation', 'Token Impersonation/Theft', 'Detects scripts that contain PowerShell functions, structures, or Windows API functions related to token impersonation/theft. Attackers may duplicate then impersonate another user''s token to escalate privileges and bypass access controls.', '["https://attack.mitre.org/tactics/TA0004/","https://attack.mitre.org/techniques/T1134/001/"]', 'oneOf("log.message", ["Invoke-TokenManipulation", "ImpersonateNamedPipeClient", "NtImpersonateThread"]) ||
(regexMatch("log.message", "(UpdateProcThreadAttribute(.+)STARTUPINFOEX|STARTUPINFOEX(.+)UpdateProcThreadAttribute)") &&
regexMatch("log.message", "(AdjustTokenPrivileges(.+)SeDebugPrivilege|SeDebugPrivilege(.+)AdjustTokenPrivileges)")) ||
