insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (784, 'Windows: Volume Shadow Copy Deleted or Resized via VssAdmin', 1, 2, 3, 'Impact', 'T1490 - Inhibit System Recovery', 'Identifies use of vssadmin.exe for shadow copy deletion or resizing on endpoints. This commonly occurs in tandem with ransomware or other destructive attacks.', '["https://attack.mitre.org/tactics/TA0040/","https://attack.mitre.org/techniques/T1490/"]', 'regexMatch("log.message", "((delete|resize)(.+)shadows|shadows(.+)(delete|resize))") && contains("log.eventDataProcessName", "vssadmin.exe")', '2026-02-09 16:57:43.142024', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (789, 'Windows Service Installed via an Unusual Client', 3, 3, 2, 'Privilege Escalation', 'T1543.003 - Create or Modify System Process: Windows Service', 'Identifies the creation of a Windows service by an unusual client process. Services may be created with administrator privileges but are executed under SYSTEM privileges, so an adversary may also use a service to escalate privileges from administrator to SYSTEM.', '["https://attack.mitre.org/tactics/TA0004/","https://attack.mitre.org/techniques/T1543/003/"]', 'equals("action", "service-installed") && equals("clientProcessId", "0") && equals("parentProcessId", "0")', '2026-02-09 16:57:43.842017', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (790, 'Windows: Wireless Credential Dumping using Netsh Command', 3, 3, 2, 'Credential Access', 'T1003 - OS Credential Dumping', 'Identifies attempts to dump Wireless saved access keys in clear text using the Windows built-in utility Netsh.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1003/"]', 'contains("log.message", "wlan") && regexMatch("log.message", "(key(.+)clear)") && contains("log.winlogEventDataProcessName", "netsh.exe")', '2026-02-09 16:57:43.986689', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (791, 'Windows: Signed Proxy Execution via MS Work Folders', 1, 2, 3, 'Defense Evasion', 'T1218 - System Binary Proxy Execution', 'Identifies the use of Windows Work Folders to execute a potentially masqueraded control.exe file in the current working directory. Misuse of Windows Work Folders could indicate malicious activity.', '["https://attack.mitre.org/tactics/TA0005/","https://attack.mitre.org/techniques/T1218/"]', 'contains("log.winlogEventDataProcessName", "control.exe") && contains("log.winlogEventDataParentProcessName", "workfolders.exe") && !regexMatch("log.winlogEventDataProcessName", "(:\\Windows\\(System32|SysWOW64)\\control.exe)")', '2026-02-09 16:57:44.131829', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (792, 'Office 365 Anti-Phishing Policy Bypass Detected', 3, 3, 1, 'Defense Evasion', 'T1562.001 - Impair Defenses: Disable or Modify Tools', 'Detects potential bypasses or modifications to anti-phishing policies including changes to safe sender lists, domain exclusions, or policy disabling that could allow phishing emails to reach users. This rule identifies successful administrative actions on anti-phishing configurations that could weaken email security defenses.

Next Steps:
1. Review the specific anti-phishing policy changes made by the user
2. Verify if the changes were authorized and documented in change management
3. Check if the user has legitimate administrative privileges for email security policies
4. Examine the timing and context of the changes (e.g., during business hours vs. off-hours)
5. Look for any subsequent phishing emails that may have bypassed detection
6. Consider rolling back unauthorized changes and implementing additional approval workflows
7. Monitor for any unusual email activity following the policy modifications
', '["https://learn.microsoft.com/en-us/defender-office-365/anti-phishing-policies-about","https://attack.mitre.org/techniques/T1562/001/"]', 'oneOf("log.Operation", ["Set-AntiPhishPolicy", "Remove-AntiPhishPolicy", "New-AntiPhishPolicy", "Disable-AntiPhishRule"]) &&
equals("log.ResultStatus", "Success")
', '2026-02-09 16:58:33.807960', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"log.Operation","operator":"filter_match","value":"AntiPhish"}],"or":null,"within":"now-4h","count":2}]', '["lastEvent.log.Operation","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (793, 'Office 365 App Consent Grants Detected', 3, 3, 1, 'Persistence', 'T1098.003 - Account Manipulation: Additional Cloud Credentials', 'Detects when OAuth consent is granted to an application in Office 365. Attackers may use malicious OAuth apps to gain persistent access to user data without requiring credentials. This technique allows attackers to maintain access even after password changes.

Next Steps:
1. Review the application that received consent and verify its legitimacy
2. Check the permissions granted to the application
3. Investigate the user who granted consent for suspicious activity
4. Review application audit logs for any unauthorized data access
5. If malicious, revoke the application consent and remove the app registration
6. Consider implementing application consent policies to prevent unauthorized app installations
', '["https://learn.microsoft.com/en-us/defender-office-365/detect-and-remediate-illicit-consent-grants","https://attack.mitre.org/techniques/T1098/003/"]', 'equals("action", "Consent to application") && equals("actionResult", "Success")
', '2026-02-09 16:58:33.937499', true, false, 'origin', null, '[]', '["lastEvent.log.appAccessContextClientAppId","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (794, 'Audit Log Tampering Detection', 3, 3, 2, 'Defense Evasion', 'T1070.001 - Indicator Removal: Clear Windows Event Logs', 'Detects attempts to tamper with audit logs by disabling auditing, modifying audit configurations, or clearing audit data. This could indicate an attempt to hide malicious activities.

Next Steps:
1. Investigate the user account that performed the audit configuration changes
2. Review recent activities by this user to identify potential malicious actions
3. Check if the audit configuration was restored after being disabled
4. Correlate with other security events around the same timeframe
5. Verify if this was an authorized administrative action
6. Review any recent privilege escalation or account compromise indicators
', '["https://learn.microsoft.com/en-us/purview/audit-log-enable-disable","https://attack.mitre.org/techniques/T1070/001/"]', '(oneOf("action", ["Set-AdminAuditLogConfig", "Remove-AdminAuditLogConfig", "Disable-OrganizationCustomization", "Set-OrganizationConfig"]) ||
(equals("log.Workload", "Exchange") && contains("log.ObjectId", "AdminAuditLog")) ||
(contains("log.Parameters", "UnifiedAuditLogIngestionEnabled") && contains("log.Parameters", "false"))) &&
exists("origin.user") &&
