insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (810, 'Microsoft 365 Exchange Transport Rule Modification', 3, 2, 1, 'Exfiltration', 'T1537 - Transfer Data to Cloud Account', 'Exfiltration consists of techniques that adversaries may use to steal data from your network. Once they’ve collected data, adversaries often package it to avoid detection while removing it. This can include compression and encryption. Techniques for getting data out of a target network typically include transferring it over their command and control channel or an alternate channel and may also include putting size limits on the transmission.<br> Identifies when a transport rule has been disabled or deleted in Microsoft 365. Mail flow rules (also known as transport rules) are used to identify and take action on messages that flow through your organization. An adversary or insider threat may modify a transport rule to exfiltrate data or evade defenses.', '["https://docs.microsoft.com/en-us/exchange/security-and-compliance/mail-flow-rules/mail-flow-rules","https://attack.mitre.org/techniques/T1537/","https://attack.mitre.org/tactics/TA0010/"]', 'equals("log.Workload", "Exchange") && oneOf("action", ["Remove-TransportRule","Disable-TransportRule"]) && oneOf("actionResult", ["Success","PartiallySucceeded","True"])
', '2026-02-09 16:58:36.458058', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (811, 'Suspicious External Sharing Activity', 3, 2, 1, 'Data Loss Prevention', 'T1567 - Exfiltration Over Web Service', 'Detects unauthorized or suspicious external sharing activities in SharePoint and OneDrive that could indicate data exfiltration attempts or policy violations when sharing sensitive content with external parties.

Next Steps:
1. Review the shared content and assess its sensitivity level
2. Verify if the external sharing was authorized by data owners
3. Check if the recipient has legitimate business need for access
4. Validate against organizational data sharing policies
5. Examine user''s recent activity for other suspicious sharing patterns
6. Consider revoking access if sharing was unauthorized
7. Update DLP policies if needed to prevent future violations
8. Document findings and coordinate with data protection team
', '["https://learn.microsoft.com/en-us/purview/audit-log-activities","https://attack.mitre.org/techniques/T1567/"]', '(equals("log.Workload", "SharePoint") || equals("log.Workload", "OneDrive")) &&
(
  equals("action", "SharingInvitationCreated") ||
  equals("action", "AnonymousLinkCreated") ||
  equals("action", "AnonymousLinkUsed") ||
  equals("action", "SecureLinkCreated") ||
  equals("action", "SharingSet") ||
  equals("action", "CompanyLinkCreated") ||
  equals("action", "AddedToSecureLink")
) &&
equals("actionResult", "Success") &&
(
  equals("log.TargetUserOrGroupType", "Guest") ||
  contains("log.SiteUrl", "external") ||
  contains("log.EventData", "AllowExternalSharing")
)
', '2026-02-09 16:58:36.636964', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"}],"or":null,"within":"now-1h","count":5}]', '["lastEvent.log.ObjectId","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (812, 'Office 365 Forms and Sway Phishing Detection', 2, 2, 1, 'Initial Access', 'T1566 - Phishing', 'Detects suspicious usage of Microsoft Forms and Sway for phishing page creation. Attackers leverage these legitimate Microsoft services to host phishing pages that bypass email security controls and appear trustworthy to victims due to the microsoft.com domain.

Next Steps:
1. Review the Form or Sway content for phishing indicators (credential harvesting, fake login pages)
2. Check the creator account for signs of compromise
3. Review the Form''s collection settings for password or sensitive data collection
4. Check if the Form or Sway was shared externally
5. Review response submissions for harvested credentials
6. If malicious, delete the Form/Sway and reset the creator''s credentials
7. Implement DLP policies to detect credential harvesting forms
8. Enable Microsoft Defender for Office 365 Forms protection
', '["https://learn.microsoft.com/en-us/microsoft-365/security/office-365-security/anti-phishing-policies-about","https://attack.mitre.org/techniques/T1566/"]', '(oneOf("action", ["FormCreated", "FormUpdated", "FormShared"]) ||
 contains("action", "Sway")) &&
equals("actionResult", "Success") &&
(contains("log.Parameters", "password") ||
 contains("log.Parameters", "credential") ||
 contains("log.Parameters", "login") ||
 contains("log.Parameters", "external"))
', '2026-02-09 16:58:36.762359', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_match","value":"Form"}],"or":null,"within":"now-1h","count":3}]', '["adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (813, 'Abnormal Guest User Invitation Activity', 3, 2, 1, 'Identity and Access Management', 'Account Creation', 'Detects unusual spikes in guest user invitations which could indicate an attempt to establish persistence through external accounts or potential data exfiltration preparation by adding unauthorized external collaborators.

Next Steps:
1. Review the user account initiating the invitations for any signs of compromise
2. Verify the legitimacy of the invited external users and their business justification
3. Check if the inviting user has appropriate permissions for guest invitations
4. Examine the invited users'' email domains for suspicious or unexpected organizations
5. Review any subsequent activity by the invited guest users
6. Validate that the invitation frequency aligns with normal business processes
7. Consider implementing additional approval workflows for guest user invitations
', '["https://learn.microsoft.com/en-us/purview/audit-log-activities","https://attack.mitre.org/techniques/T1136/"]', 'equals("log.Workload", "AzureActiveDirectory") && 
(
  equals("action", "Invite external user") ||
  equals("action", "InviteGuest") ||
  equals("action", "Add guest to group") ||
  equals("action", "Guest user invite redeemed")
) &&
equals("actionResult", "Success")
', '2026-02-09 16:58:36.897486', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"Invite external user"}],"or":null,"within":"now-1h","count":10}]', '["adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (814, 'Information Barriers Policy Violation', 3, 2, 1, 'Privilege Escalation', 'Valid Accounts', 'Detects violations of information barrier policies designed to prevent conflicts of interest by restricting communications and collaborations between specific groups or individuals within the organization. Information barriers are critical security controls that prevent unauthorized information sharing between different business units or roles.

Next Steps:
1. Review the specific information barrier policy that was violated and the users involved
2. Investigate whether the violation was intentional or accidental
3. Check if there are patterns of repeated violations by the same user or group
4. Review and update information barrier policies if necessary
5. Provide additional training to users if violations appear to be due to lack of awareness
6. Consider implementing additional technical controls to prevent future violations
', '["https://learn.microsoft.com/en-us/purview/information-barriers","https://attack.mitre.org/techniques/T1078/"]', 'equals("action", "InformationBarrierPolicyViolation") || (equals("log.PolicyType", "InformationBarrier") && equals("actionResult", "Blocked")) || (equals("log.ViolationType", "InformationBarrier") && equals("action", "CommunicationBlocked"))
', '2026-02-09 16:58:37.027385', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"log.PolicyType","operator":"filter_term","value":"InformationBarrier"}],"or":null,"within":"now-12h","count":3}]', '["lastEvent.log.TargetUser","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (815, 'Microsoft 365 Exchange Anti-Phish Policy Deletion', 2, 3, 2, 'Initial Access', 'T1566 - Phishing', 'Adversaries may send phishing messages to gain access to victim systems. All forms of phishing are electronically delivered social engineering. Phishing can be targeted, known as spearphishing. In spearphishing, a specific individual, company, or industry will be targeted by the adversary. More generally, adversaries can conduct non-targeted phishing, such as in mass malware spam campaigns.<br> Adversaries may send victims emails containsing malicious attachments or links, typically to execute malicious code on victim systems. Phishing may also be conducted via third-party services, like social media platforms. Phishing may also involve social engineering techniques, such as posing as a trusted source.<br> Identifies the deletion of an anti-phishing policy in Microsoft 365. By default, Microsoft 365 includes built-in features that help protect users from phishing attacks. Anti-phishing polices increase this protection by refining settings to better detect and prevent attacks.', '["https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/set-up-anti-phishing-policies?view=o365-worldwide","https://attack.mitre.org/techniques/T1566/","https://attack.mitre.org/tactics/TA0001/"]', 'equals("log.Workload", "Exchange") && equals("action", "Remove-AntiPhishPolicy") && oneOf("actionResult", ["Success","PartiallySucceeded","True"])
', '2026-02-09 16:58:37.187287', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (816, 'Microsoft 365 Exchange Safe Link Policy Disabled', 3, 2, 2, 'Initial Access', 'T1566 - Phishing', 'When it comes to protecting its users, Microsoft takes the threat of phishing seriously. Spoofing is a common technique that''s  used by attackers. Spoofed messages appear to originate from someone or somewhere other than the actual source. This technique is often  used in phishing campaigns that are designed to obtain user credentials. The anti-spoofing technology in EOP specifically examines forgery of the From header in the message body (used to display the message sender in email clients). When EOP has high confidence that the From header is forged, the message is identified as spoofed.<br> Identifies when a Safe Link policy is disabled in Microsoft 365. Safe Link policies for Office applications extend phishing protection to documents that contains hyperlinks, even after they have been delivered to a user.', '["https://docs.microsoft.com/en-us/microsoft-365/security/office-365-security/atp-safe-links?view=o365-worldwide","https://attack.mitre.org/techniques/T1566/"]', 'equals("log.Workload", "Exchange") && equals("action", "Disable-SafeLinksRule") && oneOf("actionResult", ["Success","PartiallySucceeded","True"])
', '2026-02-09 16:58:37.321893', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (817, 'Insider Risk Indicator Detection', 3, 3, 2, 'Collection', 'Data from Local System', 'Detects insider risk indicators such as unusual data access patterns, mass downloads, sensitive data exfiltration attempts, or policy violations that may indicate malicious insider activity or compromised accounts.

Next Steps:
1. Review the specific insider risk alert details and policy violated
2. Investigate the user''s recent activity patterns and data access history
3. Check if the user has legitimate business justification for the flagged activity
4. Review the user''s role, permissions, and access to sensitive resources
5. Correlate with HR records for any recent disciplinary actions or employment changes
6. Examine network logs for any unusual data transfer patterns or external communications
7. Consider implementing additional monitoring or access restrictions if suspicious activity is confirmed
8. Escalate to security team and HR if malicious intent is suspected
', '["https://learn.microsoft.com/en-us/purview/insider-risk-management","https://attack.mitre.org/techniques/T1005/"]', 'equals("action", "InsiderRiskAlert") || (contains("log.PolicyName", "InsiderRisk") && equals("actionResult", "PolicyViolation")) || (oneOf("log.RiskLevel", ["High", "Critical"]) && equals("log.AlertSource", "InsiderRiskManagement"))
', '2026-02-09 16:58:37.457219', true, false, 'origin', null, '[]', '["lastEvent.log.PolicyName","lastEvent.log.RiskLevel","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (818, 'Microsoft 365 Exchange Anti-Phish Rule Modification', 2, 3, 2, 'Initial Access', 'T1566 - Phishing', 'Adversaries may send phishing messages to gain access to victim systems. All forms of phishing are electronically delivered social engineering. Phishing can be targeted, known as spearphishing. In spearphishing, a specific individual, company, or industry will be targeted by the adversary. More generally, adversaries can conduct non-targeted phishing, such as in mass malware spam campaigns.<br> Adversaries may send victims emails containsing malicious attachments or links, typically to execute malicious code on victim systems. Phishing may also be conducted via third-party services, like social media platforms. Phishing may also involve social engineering techniques, such as posing as a trusted source.<br> Identifies the modification of an anti-phishing rule in Microsoft 365. By default, Microsoft 365 includes built-in features that help protect users from phishing attacks. Anti-phishing rules increase this protection by refining settings to better detect and prevent attacks.', '["https://attack.mitre.org/techniques/T1566/","https://attack.mitre.org/tactics/TA0001/"]', 'equals("log.Workload", "Exchange") && oneOf("action", ["Remove-AntiPhishRule","Disable-AntiPhishRule"]) && oneOf("actionResult", ["Success","PartiallySucceeded","True"])
', '2026-02-09 16:58:37.607269', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (819, 'M365 Data Exfiltration to Unsanctioned Application', 3, 2, 1, 'Exfiltration', 'T1537 - Transfer Data to Cloud Account', 'Detects Microsoft Defender for Cloud Apps (CASB) alerts for data exfiltration to unsanctioned applications. This indicates sensitive organizational data is being transferred to unauthorized cloud services.

Next Steps:
1. Identify the unsanctioned application and the data being transferred
2. Review the user''s recent activity for other data exfiltration indicators
3. Check the volume and sensitivity of data transferred
4. Block the unsanctioned application if not already blocked
5. If unauthorized, investigate the user account for compromise
6. Review DLP policies for coverage gaps
7. Consider implementing session controls for risky applications
', '["https://learn.microsoft.com/en-us/defender-cloud-apps/discovered-apps","https://attack.mitre.org/techniques/T1537/"]', '(contains("action", "DlpRuleMatch") && contains("log.Parameters", "UnsanctionedApp")) ||
(equals("log.Workload", "MicrosoftDefenderForCloudApps") && contains("log.Parameters", "exfiltration"))
', '2026-02-09 16:58:37.747185', true, false, 'origin', null, '[]', '["lastEvent.log.Parameters","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (820, 'M365 New Federated Domain Added', 3, 3, 3, 'Persistence', 'T1556 - Modify Authentication Process', 'Detects when a new federated domain is added to Microsoft 365. Adding federated domains is a critical attack technique that enables Golden SAML attacks, allowing attackers to forge authentication tokens and maintain persistent backdoor access to the tenant.

Next Steps:
1. Immediately verify the federated domain addition was authorized
2. Review the federation configuration and signing certificates
3. Validate the identity provider endpoint URLs
4. Check the admin account that made the change for compromise
5. Review all authentications from the federated domain
6. If unauthorized, remove the federated domain immediately
7. Audit all changes to tenant federation settings
', '["https://learn.microsoft.com/en-us/microsoft-365/enterprise/plan-for-third-party-ssl-certificates","https://attack.mitre.org/techniques/T1556/"]', 'oneOf("action", ["Set domain authentication", "Add unverified domain", "Verify domain"]) &&
(contains("log.Parameters", "Federated") || contains("log.Parameters", "federation")) &&
exists("origin.user")
', '2026-02-09 16:58:37.882455', true, false, 'origin', null, '[]', '["adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (821, 'M365 Suspicious OAuth Application File Downloads', 3, 2, 1, 'Collection', 'T1530 - Data from Cloud Storage Object', 'Detects Microsoft Defender for Cloud Apps alerts for suspicious OAuth application file download activities. Malicious OAuth apps granted consent by phished users can mass-download files from SharePoint and OneDrive.

Next Steps:
1. Identify the OAuth application and its registered publisher
2. Review the application''s consented permissions (especially Files.Read.All)
3. Check which user consented to the application
4. Review the volume and types of files downloaded
5. If unauthorized, revoke the application consent and block the application
6. Check for other users who consented to the same application
7. Review the downloaded file contents for sensitivity
', '["https://learn.microsoft.com/en-us/defender-cloud-apps/investigate-anomaly-alerts","https://attack.mitre.org/techniques/T1530/"]', '(equals("log.Workload", "MicrosoftDefenderForCloudApps") && contains("log.Parameters", "Suspicious OAuth app file download")) ||
(contains("action", "AppFileDownloaded") && contains("log.Parameters", "OAuth"))
', '2026-02-09 16:58:38.017376', true, false, 'origin', null, '[]', '["lastEvent.log.Parameters","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (822, 'M365 Mailbox PST Export Detected', 3, 1, 1, 'Collection', 'T1114.002 - Email Collection: Remote Email Collection', 'Detects PST file exports from Microsoft 365 mailboxes. Bulk email export to PST format is a primary method of email exfiltration, often performed by compromised admin accounts or insider threats.

Next Steps:
1. Verify the PST export was authorized and part of a legitimate process
2. Check the user performing the export for proper authorization
3. Review which mailboxes were exported and their sensitivity
4. Check for associated eDiscovery search operations
5. If unauthorized, revoke the user''s eDiscovery permissions
6. Review the export download logs for destination information
7. Check for other mass data access by the same user
', '["https://learn.microsoft.com/en-us/purview/ediscovery-export-search-results","https://attack.mitre.org/techniques/T1114/002/"]', 'oneOf("action", ["New-ComplianceSearchAction", "SearchExportDownloaded"]) &&
contains("log.Parameters", "Export") &&
exists("origin.user")
', '2026-02-09 16:58:38.162529', true, false, 'origin', null, '[]', '["adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (823, 'Office 365 Mail Flow Rule Modified', 3, 3, 2, 'Defense Evasion', 'T1564.008 - Hide Artifacts: Email Hiding Rules', 'Detects modifications to mail flow rules (transport rules) in Office 365. Attackers may create or modify mail flow rules to redirect, delete, or hide emails, bypassing security controls or exfiltrating data. Mail flow rules can be used to automatically delete emails containing specific keywords, forward sensitive emails to external addresses, or modify email content.

Next Steps:
1. Review the specific mail flow rule that was modified, including its conditions and actions
2. Verify if the change was authorized and performed by a legitimate administrator
3. Check if the rule involves email forwarding to external domains or deletion of emails
4. Examine recent email traffic to identify any emails that may have been affected by the rule
5. Review mailbox audit logs for the affected user accounts
6. Check for other administrative changes made by the same user around the same time
7. If unauthorized, disable the malicious rule immediately and investigate the compromised account
', '["https://admindroid.com/how-to-audit-transport-rule-changes-report-in-microsoft-365","https://attack.mitre.org/techniques/T1564/008/"]', 'oneOf("action", ["New-TransportRule", "Set-TransportRule", "Remove-TransportRule", "Enable-TransportRule", "Disable-TransportRule"]) &&
equals("actionResult", "Success")
', '2026-02-09 16:58:38.302310', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_match","value":"TransportRule"}],"or":null,"within":"now-1h","count":3}]', '["lastEvent.action","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (824, 'Suspicious Mail Forwarding Rule Creation', 3, 2, 1, 'Data Exfiltration', 'T1114.001 - Email Collection: Local Email Collection', 'Detects creation or modification of inbox rules that forward emails to external recipients, which could indicate data exfiltration attempts. This rule monitors for the creation of new inbox rules or modifications to existing rules that contain forwarding parameters.

Next Steps:
1. Review the specific forwarding parameters in the log.Parameters field to identify the destination email address
2. Verify if the forwarding destination is a legitimate business email or an external/suspicious address
3. Check if the user who created the rule has legitimate business justification for email forwarding
4. Review recent authentication logs for the affected user account for signs of compromise
5. Examine the timing of the rule creation - if created outside business hours or immediately after login, investigate further
6. Check for other suspicious activities by the same user account around the same timeframe
7. If malicious, disable the forwarding rule and reset user credentials
', '["https://docs.microsoft.com/en-us/microsoft-365/compliance/auditing-troubleshooting-scenarios","https://attack.mitre.org/techniques/T1114/001/"]', 'oneOf("action", ["NewInboxRule", "Set-InboxRule", "UpdateInboxRules"]) && 
equals("actionResult", "Success") &&
(contains("log.Parameters", "ForwardTo") || contains("log.Parameters", "ForwardAsAttachmentTo") || contains("log.Parameters", "RedirectTo"))
', '2026-02-09 16:58:38.437051', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (825, 'Office 365 Mailbox Delegation Abuse', 3, 2, 1, 'Persistence', 'T1098.002 - Account Manipulation: Additional Email Delegate Permissions', 'Detects addition of mailbox delegation permissions including FullAccess, SendAs, and SendOnBehalf. Attackers may add mailbox permissions to access sensitive emails, send phishing messages as the compromised user, or maintain persistent access to communications.

Next Steps:
1. Verify the mailbox delegation was authorized by the mailbox owner or administrator
2. Review the specific permissions granted (FullAccess, SendAs, SendOnBehalf)
3. Check who the delegate user is and their relationship to the mailbox owner
4. Review recent authentication activity for both the admin and delegate accounts
5. Examine the timing of the delegation for suspicious patterns
6. If unauthorized, remove the delegation permissions immediately
7. Review the mailbox for signs of unauthorized access or data theft
8. Enable mailbox audit logging if not already enabled
', '["https://learn.microsoft.com/en-us/exchange/recipients-in-exchange-online/manage-permissions-for-recipients","https://attack.mitre.org/techniques/T1098/002/"]', 'oneOf("action", ["Add-MailboxPermission", "Add-RecipientPermission", "Set-Mailbox"]) &&
equals("actionResult", "Success") &&
(contains("log.Parameters", "FullAccess") ||
 contains("log.Parameters", "SendAs") ||
 contains("log.Parameters", "SendOnBehalf"))
', '2026-02-09 16:58:38.576764', true, false, 'origin', null, '[]', '["adversary.user","target.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (826, 'Office 365 Mailbox Export to PST', 3, 1, 1, 'Data Exfiltration', 'T1114.002 - Email Collection: Remote Email Collection', 'Detects creation of mailbox export requests which generate PST files containing email data. Attackers with compromised admin credentials may use New-MailboxExportRequest or eDiscovery export to bulk exfiltrate email data from target mailboxes.

Next Steps:
1. Verify the mailbox export was authorized for legitimate eDiscovery or compliance purposes
2. Identify the target mailbox(es) being exported
3. Review the administrator performing the export and confirm authorization
4. Check the export destination and ensure it is within organizational control
5. Review the content filters applied to the export request
