', '["https://learn.microsoft.com/en-us/exchange/policy-and-compliance/ediscovery/export-results-to-pst","https://attack.mitre.org/techniques/T1114/002/"]', 'oneOf("action", ["New-MailboxExportRequest", "New-ComplianceSearchAction", "SearchExportDownloaded"]) &&
equals("actionResult", "Success")
', '2026-02-09 16:58:38.722533', true, false, 'origin', null, '[]', '["lastEvent.action","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (827, 'Mass Email Deletion Detected', 2, 3, 2, 'Data Loss', 'T1114 - Email Collection', 'Detects when a user performs mass deletion of emails which could indicate data destruction, covering tracks, or malicious insider activity. Monitors for multiple HardDelete or SoftDelete operations within a short time window.

Next Steps:
1. Verify the legitimacy of the user performing the deletions
2. Check if this aligns with any scheduled maintenance or cleanup activities
3. Investigate the content and importance of deleted emails if possible
4. Review user''s recent access patterns and behavior
5. Check for any concurrent suspicious activities from the same user
6. Validate if the user has appropriate permissions for bulk email operations
7. Consider temporarily restricting the user''s access pending investigation
', '["https://learn.microsoft.com/en-us/purview/audit-mailboxes","https://attack.mitre.org/techniques/T1114/"]', 'oneOf("action", ["HardDelete", "SoftDelete"]) && exists("origin.user") && exists("origin.ip")
', '2026-02-09 16:58:38.877594', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"HardDelete"}],"or":[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"SoftDelete"}],"or":null,"within":"now-15m","count":100}],"within":"now-15m","count":100}]', '["adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (828, 'MFA Fatigue Push Spam Attack Detection', 3, 2, 1, 'Credential Access', 'T1621 - Multi-Factor Authentication Request Generation', 'Detects MFA fatigue attacks where an attacker repeatedly triggers MFA push notifications to overwhelm a user into accepting. Multiple failed MFA challenges followed by a successful authentication strongly indicates an MFA fatigue attack.

Next Steps:
1. Contact the user immediately to verify if they intentionally approved the MFA request
2. Review the source IP addresses of the MFA challenges
3. Check if the authentication was ultimately successful after the MFA spam
4. Review the user''s account for signs of compromise post-authentication
5. If MFA was approved under duress, immediately reset credentials and revoke sessions
6. Switch the user to phishing-resistant MFA methods (FIDO2, certificate-based)
7. Enable number matching for push notifications
8. Implement risk-based Conditional Access policies
', '["https://learn.microsoft.com/en-us/azure/active-directory/authentication/concept-mfa-howitworks","https://attack.mitre.org/techniques/T1621/"]', '(equals("action", "UserLoginFailed") || equals("action", "UserLoggedIn")) &&
(contains("log.Parameters", "MFA") ||
 contains("log.LogonError", "MfaDenied") ||
 contains("log.LogonError", "MfaIncomplete") ||
 equals("log.LogonError", "InvalidStrongAuthenticationMethod"))
', '2026-02-09 16:58:39.017690', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"log.LogonError","operator":"filter_match","value":"Mfa"}],"or":null,"within":"now-15m","count":5}]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (829, 'Multi-Geo Data Violations', 3, 2, 1, 'Data Loss', 'T1030 - Data Transfer Size Limits', 'Detects violations of multi-geo data residency policies including unauthorized data movements between regions, cross-geo access violations, or attempts to bypass geo-restrictions. This rule identifies activities such as site geo moves, cross-geo file operations, and data location parameter modifications that may indicate unauthorized data transfer or policy violations.

Next Steps:
1. Review the user''s authorization level for multi-geo operations
2. Verify if the geo movement was approved through proper change management
3. Check data classification and residency requirements for affected content
4. Examine the source and destination locations for compliance violations
5. Review audit logs for related suspicious activities by the same user
6. Validate that the operation aligns with organizational data governance policies
', '["https://learn.microsoft.com/en-us/microsoft-365/enterprise/microsoft-365-multi-geo","https://attack.mitre.org/techniques/T1030/"]', '(oneOf("action", ["SiteGeoMoveScheduled", "SiteGeoMoveCompleted", "SiteGeoMoveCancelled", "AllowedDataLocationAdded", "GeoQuotaAllocated", "MigrationJobCompleted"]) ||
(equals("log.Workload", "OneDrive") && contains("log.ItemName", "cross-geo")) ||
(exists("log.SourceFileName") && exists("log.DestinationFileName") && contains("log.SourceRelativeUrl", "geo") && contains("log.DestinationRelativeUrl", "geo")) ||
(contains("log.Parameters", "DataLocation") || contains("log.Parameters", "PreferredDataLocation"))) &&
exists("origin.user") &&
equals("actionResult", "Succeeded") &&
exists("origin.ip")
', '2026-02-09 16:58:39.161883', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"SiteGeoMoveScheduled"}],"or":[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"AllowedDataLocationAdded"}],"or":null,"within":"now-24h","count":2}],"within":"now-24h","count":3}]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (830, 'Office 365 Global Admin Role Assignment', 3, 3, 2, 'Privilege Escalation', 'T1098 - Account Manipulation', 'Detects assignment of high-privilege administrative roles in Office 365, particularly Global Administrator, Exchange Administrator, and SharePoint Administrator. These roles provide extensive control over the tenant and are high-value targets for persistence.

Next Steps:
1. Verify the role assignment was authorized through proper governance
2. Review the specific role being assigned and the target user
3. Check if the assigning administrator''s account shows signs of compromise
4. Verify the role assignment follows the principle of least privilege
5. Review the target user''s recent activities post-assignment
6. If unauthorized, immediately remove the role assignment
7. Implement Privileged Identity Management (PIM) for just-in-time access
8. Enable alerts on all privileged role modifications
', '["https://learn.microsoft.com/en-us/azure/active-directory/roles/permissions-reference","https://attack.mitre.org/techniques/T1098/"]', 'oneOf("action", ["Add member to role.", "Add eligible member to role in PIM requested (permanent)."]) &&
equals("actionResult", "Success")
', '2026-02-09 16:58:39.301520', true, false, 'origin', null, '[]', '["adversary.user","target.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (831, 'Office 365 Impossible Travel Login Detection', 3, 2, 1, 'Credential Access', 'T1078 - Valid Accounts', 'Detects Office 365 sign-ins from geographically impossible locations by correlating successful logins from different countries within a short time window. This pattern strongly indicates credential compromise and unauthorized account access.

Next Steps:
1. Review the login locations and IP addresses for the affected user
2. Check if the user uses VPN services that could explain different geolocations
3. Verify with the user whether both login sessions are legitimate
4. Review the actions performed in each session for data access or configuration changes
5. Check for inbox rule creation or mail forwarding changes
6. If compromised, immediately reset user credentials and revoke all active sessions
7. Enable MFA if not already configured
8. Review the affected user''s mailbox for signs of data theft
', '["https://learn.microsoft.com/en-us/microsoft-365/security/office-365-security/detect-and-remediate-outlook-rules-forms-attack","https://attack.mitre.org/techniques/T1078/"]', 'equals("action", "UserLoggedIn") &&
equals("actionResult", "Success") &&
exists("origin.geolocation.countryCode")
', '2026-02-09 16:58:39.427314', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"UserLoggedIn"},{"field":"origin.geolocation.countryCode","operator":"must_not_term","value":"{{origin.geolocation.countryCode}}"}],"or":null,"within":"now-30m","count":1}]', '["adversary.geolocation.countryCode","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (836, 'Power BI Suspicious Data Export', 3, 1, 1, 'Data Exfiltration', 'T1567 - Exfiltration Over Web Service', 'Detects bulk Power BI report exports and data downloads that may indicate data exfiltration. Attackers with access to Power BI may export reports and underlying datasets containing sensitive business data.

Next Steps:
1. Review the specific reports and datasets being exported
2. Verify the user has legitimate business need for the exports
3. Check the data sensitivity of the exported content
4. Review the export destination and format
5. Examine the volume and frequency of exports
6. If unauthorized, disable the user''s Power BI access and investigate
7. Implement Power BI data loss prevention policies
8. Enable row-level security on sensitive datasets
', '["https://learn.microsoft.com/en-us/power-bi/admin/service-admin-auditing","https://attack.mitre.org/techniques/T1567/"]', 'oneOf("action", ["ExportReport", "ExportDataflow", "DownloadReport", "ExportArtifact"]) &&
equals("actionResult", "Success")
', '2026-02-09 16:58:40.137225', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_match","value":"Export"}],"or":null,"within":"now-30m","count":5}]', '["adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (832, 'Office 365 OAuth Application Anomalous Activity', 3, 3, 2, 'Credential Access', 'T1528 - Steal Application Access Token', 'Detects anomalous OAuth application activities including suspicious consent patterns, high-privilege permission grants, or rapid consent events from a single user which may indicate compromised accounts or malicious OAuth apps. This rule identifies when users consent to OAuth applications with high-risk permissions such as Mail access, Files access, or User.ReadWrite permissions, followed by multiple consent events from the same IP address.

Next Steps:
- Review the OAuth application details and permissions granted
- Verify if the user intentionally consented to the application
- Check for any suspicious activities from the user account after consent
- Investigate the OAuth application''s reputation and publisher
- Consider revoking application permissions if deemed malicious
- Review other users who may have consented to the same application
- Implement conditional access policies to restrict high-risk OAuth consents
', '["https://office365itpros.com/2023/12/15/oauth-apps-security/","https://attack.mitre.org/techniques/T1528/"]', 'equals("action", "Consent to application") && equals("actionResult", "Success") && (contains("log.Scope", "Mail.") || contains("log.Scope", "Files.") || contains("log.Scope", "User.ReadWrite") || contains("log.Scope", ".All"))
', '2026-02-09 16:58:39.587722', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"},{"field":"action","operator":"filter_term","value":"Consent to application"}],"or":null,"within":"now-1h","count":5}]', '["lastEvent.log.appAccessContextClientAppId","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (833, 'OneDrive Mass File Access Detected', 3, 1, 2, 'Data Reconnaissance', 'T1530 - Data from Cloud Storage Object', 'Detects when a user accesses an abnormally high number of files in OneDrive within a short time period (200+ files in 30 minutes), which could indicate automated data collection, reconnaissance, or preparation for data exfiltration. This behavior is often associated with insider threats, compromised accounts, or malicious scripts designed to harvest sensitive data from cloud storage.

Next Steps:
1. Immediately verify the legitimacy of the user account and check for signs of compromise
2. Review the specific files accessed to determine sensitivity and business impact
3. Check for concurrent suspicious activities like bulk downloads or external sharing
4. Examine authentication logs for unusual login patterns or locations
5. Verify if the access pattern aligns with the user''s normal work responsibilities
6. Consider temporarily restricting the user''s OneDrive access pending investigation
7. Review OneDrive sharing permissions and external access configurations
8. Check for any automated tools or scripts that might be accessing the files
9. Correlate with other security events from the same user or IP address
10. Document findings and escalate to incident response team if malicious activity is confirmed
', '["https://o365reports.com/2024/01/30/audit-file-access-in-sharepoint-online-using-powershell/","https://attack.mitre.org/techniques/T1530/"]', 'oneOf("action", ["FileAccessed", "FileAccessedExtended", "FilePreviewed"]) && exists("origin.user") && equals("log.Workload", "OneDrive")
', '2026-02-09 16:58:39.727441', true, false, 'origin', '["adversary.user","adversary.ip"]', '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"FileAccessed"},{"field":"log.Workload","operator":"filter_term","value":"OneDrive"}],"or":[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"FileAccessedExtended"},{"field":"log.Workload","operator":"filter_term","value":"OneDrive"}],"or":null,"within":"now-30m","count":67},{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"FilePreviewed"},{"field":"log.Workload","operator":"filter_term","value":"OneDrive"}],"or":null,"within":"now-30m","count":67}],"within":"now-30m","count":67}]', null);
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (834, 'Microsoft 365 Possible Successful Password Guessing detected', 3, 2, 2, 'Credential Access', 'T1110.001 - Brute Force', 'Adversaries with no prior knowledge of legitimate credentials within the system or environment  may guess passwords to attempt access to accounts. Without knowledge of the password for an account,  an adversary may opt to systematically guess the password using a repetitive or iterative mechanism.  An adversary may guess login credentials without prior knowledge of system or environment passwords  during an operation by using a list of common passwords. Password guessing may or may not take into  account the target''s policies on password complexity or use policies that may lock accounts out after  a number of failed attempts.', '["https://attack.mitre.org/tactics/TA0006","https://attack.mitre.org/techniques/T1110/001/"]', 'oneOf("log.Workload", ["Exchange","AzureActiveDirectory"]) && equals("action", "UserLoginFailed") && oneOf("actionResult", ["Failed","False"]) && exists("origin.user") && exists("log.clientIP")
', '2026-02-09 16:58:39.867475', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"action","operator":"filter_term","value":"UserLoginFailed"},{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"log.clientIP","operator":"filter_term","value":"{{log.clientIP}}"}],"or":null,"within":"now-1m","count":10}]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (835, 'Suspicious Power Automate Flow Activity', 3, 3, 2, 'Process Automation Abuse', 'Automated Collection', 'Detects creation or modification of Power Automate flows that could be used for automated data exfiltration or unauthorized process automation. This rule identifies suspicious Power Automate activity including flow creation, modification, sharing, and connection management that may indicate malicious automation attempts.

Next Steps:
1. Investigate the user account performing the Power Automate actions - verify if this is legitimate business activity
2. Review the specific flows created or modified - analyze their triggers, actions, and data access patterns
3. Check if the flows are accessing sensitive data sources (SharePoint, OneDrive, databases, external APIs)
4. Examine flow sharing patterns - verify if flows are being shared with unauthorized users or external accounts
5. Review connection creation/deletion activities - check for connections to suspicious external services
6. Correlate with other Office 365 audit logs to identify broader attack patterns
7. If malicious, immediately disable the flows and revoke user permissions
8. Consider implementing Power Platform DLP policies to prevent future abuse
', '["https://docs.microsoft.com/en-us/power-platform/admin/audit-data-user-activity","https://attack.mitre.org/techniques/T1119/"]', 'oneOf("action", ["CreateFlow", "ShareFlow", "CreateConnection"]) &&
equals("actionResult", "Success") &&
equals("log.Workload", "PowerAutomate")
', '2026-02-09 16:58:40.002168', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"log.Workload","operator":"filter_term","value":"PowerAutomate"}],"or":null,"within":"now-6h","count":10}]', '["lastEvent.action","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (853, 'Application Hijacking prevented in Sophos Central', 3, 3, 3, 'Persistence', 'T1574 - Hijack Execution Flow', 'Adversaries may execute their own malicious payloads by hijacking the way operating systems run programs.  Hijacking execution flow can be for the purposes of persistence, since this hijacked execution may reoccur over time.  Adversaries may also use these mechanisms to elevate privileges or evade defenses, such as application control or other restrictions on execution.', '["https://attack.mitre.org/tactics/TA0003/","https://attack.mitre.org/techniques/T1574/"]', 'equals("log.type", "Event::Endpoint::HmpaApplicationHijacking")', '2026-02-09 16:58:42.801989', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (837, 'Power Apps Data Connector Suspicious Activity', 3, 2, 1, 'Data Exfiltration', 'T1530 - Data from Cloud Storage Object', 'Detects creation or modification of Power Apps data connectors that could lead to unauthorized data access or exfiltration from corporate data sources. This rule identifies suspicious Power Apps activities including app creation/modification, data connection changes, and data export/import operations that may indicate an attempt to access or exfiltrate sensitive organizational data.

Next Steps:
1. Review the specific Power Apps activity and determine if it was authorized
2. Verify the user''s role and permissions for Power Apps and data connectors
3. Examine the data sources being connected to and assess their sensitivity
4. Check for any recent data exports or unusual data access patterns
5. Review the user''s recent activity for other suspicious behavior
6. Validate the legitimacy of any new apps or data connections created
7. Consider implementing additional monitoring for the affected user account
8. If unauthorized, immediately revoke access and investigate potential data compromise
', '["https://docs.microsoft.com/en-us/power-platform/admin/audit-data-user-activity","https://attack.mitre.org/techniques/T1530/"]', 'oneOf("action", ["CreateDataConnection", "UpdateDataConnection", "ExportData", "ImportData"]) &&
equals("actionResult", "Success") &&
equals("log.Workload", "PowerApps")
', '2026-02-09 16:58:40.287583', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"CreateDataConnection"}],"or":[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"UpdateDataConnection"}],"or":null,"within":"now-12h","count":2},{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"ExportData"}],"or":null,"within":"now-12h","count":3}],"within":"now-12h","count":2}]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (838, 'Office 365 Safe Attachment Policy Violation', 3, 3, 2, 'Initial Access', 'T1566.001 - Phishing: Spearphishing Attachment', 'Detects violations of Safe Attachment policies including malicious files blocked during detonation, policy modifications that reduce protection, or attempts to bypass attachment scanning that could lead to malware delivery. This rule identifies when Safe Attachment policies are modified, disabled, or when malicious attachments are detected and blocked by Office 365 security controls.

Next Steps:
1. Review the specific Safe Attachment policy change or violation that occurred
2. Verify if the policy modification was authorized and legitimate
3. Check if any malicious attachments were successfully blocked or if any bypassed controls
4. Investigate the user account that performed the action for signs of compromise
5. Review email logs for any related suspicious email activity
6. Validate current Safe Attachment policy configurations are properly restrictive
7. Consider implementing additional email security controls if gaps are identified
', '["https://learn.microsoft.com/en-us/defender-office-365/safe-attachments-about","https://attack.mitre.org/techniques/T1566/001/"]', 'oneOf("action", ["Set-SafeAttachmentPolicy", "Remove-SafeAttachmentPolicy", "Disable-SafeAttachmentRule"]) &&
equals("actionResult", "Success")
', '2026-02-09 16:58:40.432455', true, false, 'origin', null, '[]', '["lastEvent.action","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (839, 'Safe Links Click Pattern Anomaly', 2, 3, 1, 'Defense Evasion', 'T1204.001 - User Execution: Malicious Link', 'Detects unusual patterns in Safe Links click behavior that may indicate phishing attempts or malicious URL access. This rule monitors for multiple clicks on suspicious URLs from the same user within a short timeframe, which could indicate either a persistent phishing campaign or user behavior that poses security risks.

Next Steps:
1. Review the user''s activity timeline to identify the source of the malicious links
2. Check email security logs for the original messages containing the blocked URLs
3. Verify if other users received similar phishing emails
4. Assess whether the user''s account has been compromised
5. Implement additional security awareness training for the affected user
6. Consider blocking the malicious domains at the network level
', '["https://learn.microsoft.com/en-us/defender-office-365/safe-links-about","https://attack.mitre.org/techniques/T1204/001/"]', 'equals("action", "ClickedSafeLink") && equals("actionResult", "Blocked") && exists("origin.user")
', '2026-02-09 16:58:40.582125', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"ClickedSafeLink"}],"or":null,"within":"now-30m","count":5}]', '["adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (840, 'Service Principal Credential Addition', 3, 3, 1, 'Persistence', 'T1098.001 - Account Manipulation: Additional Cloud Credentials', 'Detects addition of credentials (secrets or certificates) to application registrations and service principals. Attackers may add new credentials to existing service principals to establish persistent backdoor access to the tenant without relying on user credentials.

Next Steps:
1. Identify the application or service principal receiving the new credential
2. Verify the credential addition was authorized by the application owner
3. Review the application''s API permissions and scope of access
4. Check the credential type (secret, certificate) and its expiration
5. Review the identity adding the credential for signs of compromise
6. If unauthorized, remove the added credential and rotate existing ones
7. Review Azure AD audit logs for actions performed using the new credential
8. Implement Azure AD alerts for credential changes to critical applications
', '["https://learn.microsoft.com/en-us/azure/active-directory/develop/howto-create-service-principal-portal","https://attack.mitre.org/techniques/T1098/001/"]', 'oneOf("action", ["Add service principal credentials.", "Update application - Certificates and secrets management"]) &&
equals("actionResult", "Success")
', '2026-02-09 16:58:40.722927', true, false, 'origin', null, '[]', '["lastEvent.log.Parameters","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (841, 'SharePoint Mass File Download Detected', 3, 1, 2, 'Data Exfiltration', 'T1213 - Data from Information Repositories', 'Detects when a user downloads an unusually large number of files from SharePoint or OneDrive within a short time period, which could indicate data exfiltration or insider threat activity. This rule triggers when a user downloads 100 or more files within 30 minutes.

**Next Steps:**
1. Review the user''s recent activity patterns and determine if the download volume is consistent with their role and responsibilities
2. Check if the user has legitimate business justification for downloading large amounts of data
3. Examine the types of files downloaded and their sensitivity levels
4. Verify the user''s location and device used for the downloads
5. Look for any concurrent suspicious activities such as unusual login times or access from new locations
6. Contact the user''s manager to validate the business need for the file downloads
7. Consider implementing additional monitoring or restrictions if the activity appears suspicious
8. Review data loss prevention (DLP) policies and ensure they are properly configured
', '["https://www.sharepointdiary.com/2020/10/how-to-track-document-downloads-using-audit-log-in-sharepoint-online.html","https://attack.mitre.org/techniques/T1213/"]', 'equals("action", "FileDownloaded") && exists("origin.user") && oneOf("log.Workload", ["SharePoint", "OneDrive"])
', '2026-02-09 16:58:40.872231', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"action","operator":"filter_term","value":"FileDownloaded"}],"or":null,"within":"now-30m","count":100}]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (842, 'SharePoint Permission Escalation Detection', 3, 2, 1, 'Privilege Escalation', 'T1098 - Account Manipulation', 'Detects escalation of SharePoint permissions including adding site collection administrators and granting site admin privileges to external users. These changes can provide unauthorized access to sensitive SharePoint data and configuration settings.

Next Steps:
1. Verify the permission change was authorized by a legitimate site owner
2. Review the specific permissions granted and the target user
3. Check if the target user is an external or guest account
4. Review the affected site collection''s data sensitivity
5. Examine recent activities by the newly privileged user
6. If unauthorized, remove the elevated permissions immediately
7. Review SharePoint audit logs for data access by the privileged account
8. Implement SharePoint access governance policies
', '["https://learn.microsoft.com/en-us/sharepoint/manage-site-collection-administrators","https://attack.mitre.org/techniques/T1098/"]', 'oneOf("action", ["SiteCollectionAdminAdded", "SiteAdmin"]) &&
equals("actionResult", "Success")
', '2026-02-09 16:58:41.002263', true, false, 'origin', null, '[]', '["adversary.user","target.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (843, 'Suspicious Email Forwarding Rule Created', 3, 2, 1, 'Persistence', 'T1114.003 - Email Collection: Email Forwarding Rule', 'Detects creation or modification of inbox rules that forward emails to external domains, which is a common technique used by attackers to exfiltrate emails and maintain persistence after compromising an account. Attackers often create these rules to automatically forward sensitive emails to external addresses under their control.

Next Steps:
1. Verify if the user creating the rule is legitimate and authorized
2. Check the destination email address in the forwarding rule for external domains
3. Review recent authentication logs for the affected user account
4. Examine other administrative actions performed by this user recently
5. Check for any other suspicious inbox rules created by the same user
6. Validate if the forwarding address belongs to a legitimate business contact
7. Consider temporarily disabling the forwarding rule pending investigation
8. Review email logs to see what emails may have already been forwarded
', '["https://redcanary.com/blog/threat-detection/email-forwarding-rules/","https://attack.mitre.org/techniques/T1114/003/"]', 'oneOf("action", ["New-InboxRule", "Set-InboxRule"]) && exists("origin.user") && (contains("log.Parameters", "ForwardTo") || contains("log.Parameters", "RedirectTo") || contains("log.Parameters", "ForwardAsAttachmentTo"))
', '2026-02-09 16:58:41.136607', true, false, 'origin', null, '[]', '["adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (844, 'Suspicious Teams Message Export Activity', 3, 2, 1, 'Data Exfiltration', 'T1114 - Email Collection', 'Detects when Teams messages are exported or accessed in bulk through API calls, which could indicate an attempt to exfiltrate chat history and shared files from Microsoft Teams.

Next Steps:
1. Review the user''s recent Teams activity and authentication events
2. Check if the export activity was authorized or part of legitimate business operations
3. Examine the volume and scope of data accessed or exported
4. Verify the user''s current permissions and access levels
5. Look for any concurrent suspicious activities from the same user account
6. Contact the user to confirm if they initiated these export operations
7. Review any third-party applications that may have access to Teams data
', '["https://learn.microsoft.com/en-us/purview/audit-teams-audit-log-events","https://attack.mitre.org/techniques/T1114/"]', 'oneOf("action", ["MessagesListed", "MessagesExported", "RecordingExported", "TranscriptsExported"]) && exists("origin.user") && equals("log.Workload", "MicrosoftTeams")
', '2026-02-09 16:58:41.272231', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"log.Workload","operator":"filter_term","value":"MicrosoftTeams"}],"or":null,"within":"now-1h","count":20}]', '["lastEvent.log.appAccessContextClientAppId","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (845, 'Threat Intelligence Alert Pattern', 3, 3, 2, 'Initial Access', 'Phishing', 'Detects threat intelligence alerts from Office 365 security services indicating known malicious activities, threat actor patterns, or indicators of compromise matching threat intelligence feeds. These alerts are generated when Microsoft''s threat intelligence systems identify suspicious activities, malicious file attachments, URLs, or communication patterns associated with known threat actors.

Next Steps:
1. Immediately review the alert details and associated threat intelligence indicators
2. Investigate the affected user account for any compromise indicators
3. Check email activity and file access patterns for the affected user
4. Verify if any malicious files were opened or downloaded
5. Review authentication logs for unusual sign-in patterns
6. Examine network connections and data transfer activities
7. Check for lateral movement attempts within the organization
8. Implement containment measures if compromise is confirmed
9. Update security policies and user training based on attack vectors
10. Report findings to incident response team and document lessons learned
', '["https://learn.microsoft.com/en-us/microsoft-365/security/defender/threat-analytics","https://attack.mitre.org/techniques/T1566/"]', 'equals("action", "ThreatIntelligenceAlertTriggered") || (equals("log.AlertType", "ThreatIntelligence") && !equals("actionResult", "Success"))
', '2026-02-09 16:58:41.417169', true, false, 'origin', null, '[]', '["adversary.user","target.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (846, 'Microsoft Teams External User Phishing Detection', 2, 2, 1, 'Initial Access', 'T1566 - Phishing', 'Detects suspicious external user interactions in Microsoft Teams including external users sending messages with links, file sharing from external users, and mass external user additions. Teams is increasingly used as a phishing vector to bypass email security controls.

Next Steps:
1. Review the external user''s identity and their organization
2. Check the content of messages for phishing links or social engineering
3. Verify if external access is necessary for the affected teams and channels
4. Review any files shared by the external user for malicious content
5. Check if any users clicked on links or downloaded shared files
6. If malicious, remove the external user and block their domain
7. Implement Teams external access policies to restrict communication
8. Enable Safe Links and Safe Attachments for Teams
', '["https://learn.microsoft.com/en-us/microsoftteams/communicate-with-users-from-other-organizations","https://attack.mitre.org/techniques/T1566/"]', '(equals("action", "MemberAdded") || equals("action", "ChatCreated") || equals("action", "MessageSent")) &&
equals("actionResult", "Success") &&
contains("log.Parameters", "#EXT#")
', '2026-02-09 16:58:41.562518', true, false, 'origin', null, '[{"indexPattern":"v11-log-o365-*","with":[{"field":"origin.user","operator":"filter_term","value":"{{origin.user}}"},{"field":"log.Parameters","operator":"filter_match","value":"#EXT#"}],"or":null,"within":"now-1h","count":5}]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (854, 'Credential Theft Attemp detected in Sophos Central', 3, 3, 3, 'Credential Access', 'T1003 - OS Credential Dumping', 'The theft of access credentials to different pages or apps occurs due to the use  of insecure passwords, which are used in different accounts.  This data is often exposed as a result of leaks that arise from the exploitation of vulnerabilities in different platforms.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1003/"]', 'contains("log.type", "Event::Endpoint::HmpaCred")', '2026-02-09 16:58:42.937211', true, false, 'target', null, '[]', '["target.host","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (847, 'Sophos Central Behavioral Analysis Alert', 3, 3, 2, 'Suspicious Behavior', 'T1055 - Process Injection', 'Detects suspicious behavior patterns identified by Sophos behavioral analysis engine, including process injection attempts, privilege escalation, and other anomalous activities that indicate potential compromise.

Next Steps:
1. Review the specific behavioral detection details in the Sophos Central console
2. Examine the affected endpoint for signs of compromise
3. Check process execution history and parent-child relationships
4. Investigate network connections from the affected endpoint
5. Review file system changes and registry modifications
6. Consider isolating the endpoint if malicious activity is confirmed
7. Update endpoint security policies based on findings
', '["https://developer.sophos.com/siem-api-schemas","https://attack.mitre.org/techniques/T1055/"]', 'oneOf("log.type", ["Event::Endpoint::Threat::BehavioralDetection", "Event::Endpoint::BehaviorDetected"]) ||
(oneOf("log.detectionMethod", ["Behavioral", "HIPS"]) && oneOf("log.severity", ["medium", "high", "critical"])) ||
(contains("log.name", "Behavioral") && oneOf("log.severity", ["high", "critical"]))
', '2026-02-09 16:58:41.706992', true, false, 'origin', null, '[{"indexPattern":"v11-log-sophos-central-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-30m","count":3}]', '["lastEvent.log.processPath","adversary.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (848, 'Endpoint Threat Detection', 3, 3, 2, 'Malware Detection', 'T1055 - Process Injection', 'Detects threats identified on endpoints by Sophos Central, including malware, PUAs (Potentially Unwanted Applications), and suspicious behavior. This rule triggers when Sophos Central identifies threats such as process injection, malware execution, or other malicious activities on managed endpoints.

Next Steps:
1. Immediately isolate the affected endpoint from the network to prevent lateral movement
2. Review the threat details including threat name, file path, and detection method
3. Examine the endpoint''s recent activity logs for signs of compromise
4. Check if the threat was successfully quarantined or requires manual intervention
5. Verify if other endpoints in the environment show similar threat indicators
6. Review user activity on the affected endpoint around the time of detection
7. Perform forensic analysis of the affected files and processes if needed
8. Update security policies and endpoint configurations if gaps are identified
9. Conduct threat hunting across the environment for similar indicators of compromise
', '["https://developer.sophos.com/docs/endpoint-v1/1/routes/events/get","https://attack.mitre.org/techniques/T1055/"]', 'oneOf("log.type", ["Event::Endpoint::Threat::Detected", "Event::Endpoint::Threat::HIPSDetected", "Event::Endpoint::Threat::PuaDetected"]) ||
(oneOf("log.severity", ["high", "critical"]) && equals("log.category", "threat") && exists("log.threatName"))
', '2026-02-09 16:58:41.847184', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (849, 'Sophos Central Exploit Prevention Triggered', 3, 3, 2, 'Exploit Attempt', 'T1203 - Exploitation for Client Execution', 'Detects when Sophos exploit prevention is triggered, indicating attempted exploitation of vulnerable applications. This includes shellcode protection, CTF protocol exploitation attempts, and process hijacking attempts.

Next Steps:
1. Immediately isolate the affected endpoint to prevent lateral movement
2. Review the exploit details including target application and attack vector
3. Check for additional suspicious activity on the affected host within the past 24 hours
4. Verify if the targeted application is up to date with security patches
5. Examine network connections from the affected host for C2 communication
6. Review user activity and authentication logs for the affected endpoint
7. Consider running additional endpoint scans for indicators of compromise
8. Update security policies if the exploit targeted a previously unknown vulnerability
', '["https://developer.sophos.com/siem-api-schemas","https://attack.mitre.org/techniques/T1203/"]', 'oneOf("log.type", ["Event::Endpoint::Threat::ExploitPrevented", "Event::Endpoint::Exploit::Prevented"]) ||
(equals("log.name", "Exploit prevented") && oneOf("log.severity", ["high", "critical"]))
', '2026-02-09 16:58:41.977249', true, false, 'origin', null, '[{"indexPattern":"v11-log-sophos-central-*","with":[{"field":"log.endpointId","operator":"filter_term","value":"{{log.endpointId}}"}],"or":null,"within":"now-30m","count":2}]', '["lastEvent.log.name","adversary.host"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (850, 'Managed Threat Response Critical Alert', 3, 3, 3, 'Threat Detection', 'T1562 - Impair Defenses', 'Detects critical alerts from Sophos Managed Threat Response (MTR) service indicating active threats that require immediate investigation and response, including advanced persistent threats and sophisticated attack techniques.

Next Steps:
1. Review the MTR alert details in Sophos Central console
2. Examine the affected endpoint for signs of compromise
3. Check for lateral movement indicators on the network
4. Verify if the threat has been successfully contained
5. Update security policies based on threat intelligence from the alert
6. Document the incident and response actions taken
', '["https://docs.sophos.com/central/customer/help/en-us/ManageYourProducts/ThreatAnalysisCenter/index.html","https://attack.mitre.org/tactics/TA0005/"]', 'oneOf("log.type", ["mtr_alert", "threat_detection"]) &&
oneOf("log.severity", ["critical", "high"])
', '2026-02-09 16:58:42.117132', true, false, 'origin', null, '[{"indexPattern":"v11-log-sophos-central-*","with":[{"field":"log.endpointId","operator":"filter_term","value":"{{log.endpointId}}"},{"field":"log.severity","operator":"filter_term","value":"critical"}],"or":null,"within":"now-1h","count":3}]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (851, 'Sophos Central Ransomware Detection', 3, 3, 3, 'Ransomware Activity', 'T1486 - Data Encrypted for Impact', 'Detects ransomware activity including CryptoGuard alerts, master boot record attacks, and file system encryption attempts. This is a critical security event requiring immediate response.

Next Steps:
1. Immediately isolate the affected endpoint from the network
2. Identify the user account and processes involved in the ransomware activity
3. Check for lateral movement to other systems using the same user credentials
4. Verify backup integrity and availability for potential restoration
5. Analyze file system changes and encrypted file patterns
6. Review network connections for command and control communications
7. Search for ransomware notes or payment demands on the system
8. Coordinate with incident response team for containment and recovery
9. Monitor for similar patterns on other endpoints in the environment
10. Document all findings for forensic analysis and threat intelligence
', '["https://developer.sophos.com/siem-api-schemas","https://attack.mitre.org/techniques/T1486/"]', 'oneOf("log.type", ["Event::Endpoint::Threat::RansomwareDetected", "Event::Endpoint::CryptoGuard::FileEncryption"]) ||
(equals("log.name", "CryptoGuard") && equals("log.action", "blocked")) ||
(equals("log.name", "Ransomware detected") && equals("log.severity", "critical")) ||
(equals("log.type", "Event::Endpoint::Threat::Detected") && equals("log.threatType", "Ransomware"))
', '2026-02-09 16:58:42.256681', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (855, 'Potentially compromised or blocked device detected in Sophos Central', 3, 3, 3, 'Resource Development', 'T1584', 'Adversaries may compromise third-party infrastructure that can be used during targeting', '["https://attack.mitre.org/techniques/T1584/"]', 'oneOf("log.type", [''Event::Endpoint::Device::Blocked'', ''Event::UAV::PotentiallyCompromisedDevice''])', '2026-02-09 16:58:43.082661', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (852, 'Server Protection Alerts', 3, 3, 2, 'Server Security', 'T1505 - Server Software Component', 'Detects critical security alerts on servers protected by Sophos Central, including unauthorized access attempts, service tampering, and malware targeting server infrastructure. This rule monitors for high-severity threats specifically targeting server endpoints.

Next Steps:
1. Immediately isolate the affected server from the network if threat is confirmed active
2. Review the specific threat details in Sophos Central console to understand the attack vector
3. Check server logs for unauthorized access attempts or privilege escalation activities
4. Verify integrity of critical server services and configurations
5. Scan for additional indicators of compromise on the server and connected systems
6. Review recent server changes, updates, or new software installations
7. Check for lateral movement attempts from the compromised server
8. Implement additional monitoring for the affected server endpoint
9. Update security policies and access controls based on findings
10. Document the incident and update security procedures if necessary
', '["https://docs.sophos.com/central/customer/help/en-us/ManageYourProducts/Servers/index.html","https://attack.mitre.org/techniques/T1505/"]', 'oneOf("log.type", ["Event::Server::Threat::Detected", "Event::Server::Protection::Disabled", "Event::Server::Exploit::Prevented"]) ||
(equals("log.endpointType", "server") && oneOf("log.severity", ["high", "critical"]) && exists("log.threatName"))
', '2026-02-09 16:58:42.702862', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (857, 'Malware detected in Sophos Central', 3, 3, 3, 'Execution', 'T1204 - User Execution', 'A computer virus is a piece of malicious code that is prepended or appended to existing files on your computer.  Viruses are named after biological viruses because they use similar techniques to spread from one place to another.  Virus is often misused to refer to any threat. This usage is gradually being replaced with a more accurate term, malware (malicious software). Computer viruses primarly attack executable files and documents. In short, this is how a computer virus works:  after running the infected file, the malicious code is called and executed prior to the execution of the original application.  A virus can infect any files that the current user has write permissions for. Computer viruses can range in purpose and severity. Some of them are extremely dangerous because of their ability to delete files purposely from the hard drive.  On the other hand, some viruses do not cause any damage they only serve to annoy the user and demonstrate the technical skills of their authors.', '["https://www.mcafee.com/en-us/antivirus/malware.html"]', 'regexMatch("log.type", "^Event::Endpoint::(CoreDetection|CoreRemoteDetection|CoreHmpaClean|CoreClean)$|Event::Endpoint::(HmpaMalware|CoreHmpaCleanFailed|CoreCleanFailed)|Event::SpamOrVirus::Alert|Event::Endpoint::Threat::(HIPS|Dismissed|CleanedUp)|Event::OutboundMalwareProtection::BlockedSender")', '2026-02-09 16:58:43.377420', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (858, 'Man in the Middle Attack detected in Sophos Central', 3, 3, 3, 'Credential Access', 'T1557 - Adversary-in-the-Middle', 'Adversaries may attempt to position themselves between two or more networked devices  using an adversary-in-the-middle technique to support follow-on behaviors such as Network Sniffing  or Transmitted Data Manipulation. By abusing features of common networking protocols that can determine  the flow of network traffic (e.g. ARP, DNS, LLMNR, etc.), adversaries may force a device to communicate  through an adversary controlled system so they can collect information or perform additional actions.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1557/"]', 'contains("log.type", "Event::Smc::MitmAttackEvent")', '2026-02-09 16:58:43.532034', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (859, 'Possible Botnet detected in Sophos Central', 3, 3, 3, 'Impact', 'T1071 - Application Layer Protocol', 'A bot, or a web robot is an automated malware program that scans blocks of network addresses and infects vulnerable computers.  This allow hackers to take control of many computers at the same time and turn them into bots (also known as a zombie).  Hackers typically use bots to infect large numbers of computers, which form a network or a botnet.  Once the botnet is in your computer, it can be used in distributed denial of service (DDoS) attacks, proxy and also can be used to perform automated tasks over the Internet, without you knowing it  (for example sending spam, viruses or stealing personal and private information such as bank credentials or credit card numbers).', '["https://attack.mitre.org/tactics/TA0040/","https://attack.mitre.org/techniques/T1565/"]', 'equals("log.type", "Event::Firewall::FirewallAdvancedThreatProtection")', '2026-02-09 16:58:43.686491', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (860, 'Possible Brute Force Attack detected in Sophos Central', 3, 3, 3, 'Credential Access', 'T1110 - Brute Force', 'Adversaries may use brute force techniques to gain access to accounts when passwords are unknown or when password hashes are obtained.  Without knowledge of the password for an account or set of accounts, an adversary may systematically guess the password using a repetitive or iterative mechanism.  Brute forcing passwords can take place via interaction with a service that will check the validity of those credentials or offline against previously acquired credential data, such as password hashes.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1110/"]', 'equals("log.type", "Event::ZTNA::ZTNAAuthenticationFailure")', '2026-02-09 16:58:43.851632', true, false, 'origin', null, '[{"indexPattern":"v11-log-sophos-central-*","with":[{"field":"log.type","operator":"filter_term","value":"Event::ZTNA::ZTNAAuthenticationFailure"},{"field":"log.ip","operator":"filter_term","value":"{{log.ip}}"}],"or":null,"within":"now-5m","count":10}]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (861, 'Potential Password Spraying Attack detected in Sophos Central', 1, 2, 2, 'Credential Access', 'T1110 - Brute Force', 'Adversaries may use brute force techniques to gain access to accounts when passwords are unknown or when password hashes are obtained.  Without knowledge of the password for an account or set of accounts, an adversary may systematically guess the password using a repetitive or iterative mechanism.  Brute forcing passwords can take place via interaction with a service that will check the validity of those credentials or offline against previously acquired credential data, such as password hashes.', '["https://attack.mitre.org/tactics/TA0006/","https://attack.mitre.org/techniques/T1110/"]', 'equals("log.type", "Event::ZTNA::ZTNAAuthenticationFailure")', '2026-02-09 16:58:44.007299', true, false, 'origin', null, '[{"indexPattern":"v11-log-sophos-central-*","with":[{"field":"log.type","operator":"filter_term","value":"Event::ZTNA::ZTNAAuthenticationFailure"},{"field":"log.ip","operator":"filter_term","value":"{{log.ip}}"}],"or":null,"within":"now-1m","count":10}]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (862, 'Possible Ransomware Attack detected in Sophos Central', 3, 3, 2, 'Impact', 'T1486 - Data Encrypted for Impact', 'Ransomware, is a type of malware that prevents users from accessing their system or  personal files and requires payment of a ransom in order to gain access to them again. Identifies  ransomware attempts', '["https://attack.mitre.org/tactics/TA0040/","https://attack.mitre.org/techniques/T1565/"]', 'regexMatch("log.type", "Event::Endpoint::(HmpaCryptoGuardSMBOrigin|HmpaCryptoGuardSMB)|^Event::Endpoint::HmpaCryptoGuard$")', '2026-02-09 16:58:44.172646', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (863, 'Real Time Protection disabled in Sophos Central', 2, 2, 1, 'Defense Evasion', 'T1562 - Impair Defenses', 'Real-time protection has been disabled, which can help malware and attacks go undetected', '["https://www.makeuseof.com/real-time-protection/"]', 'equals("log.type", "Event::Endpoint::SavDisabled")', '2026-02-09 16:58:44.327132', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (871, 'Probable Sophos ip spoofing attack', 3, 3, 3, 'Impact', 'T1499 - Endpoint Denial of Service', 'IP spoofing is the creation of Internet Protocol (IP) packets which have a modified source address in order to either hide  the identity of the sender, to impersonate another computer system, or both. It is a technique often used by bad actors to  invoke DDoS attacks against a target device or the surrounding infrastructure.', '["https://support.sophos.com/support/s/article/KB-000035616?language=en_US","https://docs.sophos.com/nsg/sophos-firewall/17.5/Help/en-us/webhelp/onlinehelp/nsg/sfos/concepts/DoSBypassRuleManage.html","https://attack.mitre.org/tactics/TA0040","https://attack.mitre.org/techniques/T1499/","https://www.cloudflare.com/learning/ddos/glossary/ip-spoofing/"]', 'equals("log.component", "IP spoof")
', '2026-02-09 16:58:45.927282', true, false, 'origin', null, '[]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (864, 'Unknown Threat detected in Sophos Central', 3, 3, 2, 'Execution', 'T1204 - User Execution', 'A computer virus is a piece of malicious code that is prepended or appended to existing files on your computer.  Viruses are named after biological viruses because they use similar techniques to spread from one place to another.  Virus is often misused to refer to any threat. This usage is gradually being replaced with a more accurate term, malware (malicious software). Computer viruses primarly attack executable files and documents. In short, this is how a computer virus works:  after running the infected file, the malicious code is called and executed prior to the execution of the original application.  A virus can infect any files that the current user has write permissions for. Computer viruses can range in purpose and severity. Some of them are extremely dangerous because of their ability to delete files purposely from the hard drive.  On the other hand, some viruses do not cause any damage they only serve to annoy the user and demonstrate the technical skills of their authors.', '["https://www.mcafee.com/en-us/antivirus/malware.html"]', 'regexMatch("log.type", "Event::Endpoint::(CoreIps|HomeThreatRemnants|HmpaBehaviourPrevented|HmpaThreat|HmpaSafeBrowsing|CoreAmsi|CoreOutbreak)|Event::Endpoint::Threat::(CleanupFailed::|Ips|CommandAndControl)")', '2026-02-09 16:58:44.487064', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (865, 'Sophos Central Tamper Protection Alert', 2, 3, 2, 'Defense Evasion', 'T1562.001 - Impair Defenses: Disable or Modify Tools', 'Detects when tamper protection is triggered, indicating an attempt to disable or modify Sophos security components. This could indicate malware or an attacker attempting to bypass security controls.

Next Steps:
1. Immediately investigate the affected endpoint to determine the source of the tamper protection trigger
2. Check if the endpoint shows signs of malware infection or unauthorized software installation
3. Review recent user activity and process execution on the affected system
4. Verify the integrity of Sophos security components and ensure they are functioning properly
5. Scan the endpoint for threats and malware using full system scans
6. If malicious activity is confirmed, isolate the endpoint and perform incident response procedures
7. Review security policies and user permissions to prevent future tamper attempts
8. Consider implementing additional endpoint monitoring for systems with tamper protection alerts
', '["https://developer.sophos.com/siem-api-schemas","https://attack.mitre.org/techniques/T1562/001/"]', 'equals("log.type", "Event::Endpoint::Threat::TamperProtection") ||
(equals("log.name", "Tamper protection") && equals("log.severity", "high")) ||
(equals("log.type", "Event::Endpoint::TamperProtection") && equals("log.action", "blocked"))
', '2026-02-09 16:58:44.647015', true, false, 'origin', null, '[]', '["adversary.host","adversary.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (866, 'Sophos XG Advanced Threat Protection Alert', 3, 3, 2, 'Malware', 'T1204 - User Execution', 'Detects when Sophos XG Firewall''s Advanced Threat Protection (ATP) identifies malicious activity, including sandboxing results, malware detection, and zero-day threats. This rule triggers on ATP events indicating threat detection, malware identification, or virus findings.

Next Steps:
1. Immediately isolate the affected host from the network
2. Review the ATP threat details and sandbox analysis results
3. Check for any file transfers or downloads from the source IP
4. Scan the internal network for indicators of compromise
5. Update threat intelligence feeds and firewall signatures
6. Review user activity from the affected source
7. Consider reimaging the affected system if malware is confirmed
', '["https://docs.sophos.com/nsg/sophos-firewall/20.0/Help/en-us/webhelp/onlinehelp/AdministratorHelp/AdvancedProtection/index.html","https://attack.mitre.org/techniques/T1204/"]', 'equals("log.type", "ATP") && equals("log.component", "Threat Protection") &&
(oneOf("log.subType", ["Malware", "Threat"]) || exists("log.virus"))
', '2026-02-09 16:58:44.807367', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-sophos-xg-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-30m","count":2}]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (867, 'Probable Sophos denial of service (DoS) attack', 3, 3, 3, 'Impact', 'T1499 - Endpoint Denial of Service', 'A Denial of Service (DoS) attack is an attempt to make a machine or network resource unavailable to the intended users. One common method of attack involves saturating the target machine with external communications requests so that it cannot respond to legitimate traffic or the machine responds so slowly that it is essentially useless.', '["https://support.sophos.com/support/s/article/KB-000035754?language=en_US","https://docs.sophos.com/nsg/sophos-firewall/18.5/PDF/SF%20syslog%20guide%2018.5.pdf","https://attack.mitre.org/tactics/TA0040","https://attack.mitre.org/techniques/T1499/"]', 'equalsIgnoreCase("log.component", "dos attacks") && equalsIgnoreCase("log.subType", "dos")
', '2026-02-09 16:58:44.967319', true, false, 'origin', null, '[]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (868, 'Probable malware detected by sophos firewall', 3, 3, 3, 'Execution', 'T1204 - User Execution', 'The Sophos firewall has detected a suspicious event and made some actions according to his configuration', '["https://www.mcafee.com/en-us/antivirus/malware.html","https://www.fortinet.com/resources/cyberglossary/computer-virus"]', 'regexMatch("log.subType", "(?i)^(virus|pua)$")
', '2026-02-09 16:58:45.127029', true, false, 'origin', null, '[]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (869, 'Sophos detected high priority alerts', 3, 3, 3, 'Initial Access', 'T1190 - Exploit Public-Facing Application', 'The Sophos firewall device has detected a high priority event. For the alert purpose, high priority is when log priority is: Emergency, Critical or Alert, and not part of the list of risked applications. Please see the logs attached to this alert for additional details.', '["https://docs.sophos.com/nsg/sophos-firewall/17.5/Help/en-us/webhelp/onlinehelp/nsg/concepts/LogIDStructure.html","https://docs.sophos.com/nsg/sophos-firewall/17.5/Help/en-us/webhelp/onlinehelp/nsg/sfos/concepts/LogMessages.html"]', 'oneOf("log.priority", ["Emergency", "Critical", "Alert"]) &&
!regexMatch("log.application", "(Torrent|Proxy|EXE File Download|eMule P2P|Ares P2P|Avast Antivirus|NetFlix|McAfee Antivirus|AVG Antivirus|ISAKMP VPN|WeTransfer Base|Xbox LIVE|OSC_AMU)") &&
!regexMatch("log.applicationName", "(Torrent|Proxy|EXE File Download|eMule P2P|Ares P2P|Avast Antivirus|NetFlix|McAfee Antivirus|AVG Antivirus|ISAKMP VPN|WeTransfer Base|Xbox LIVE|OSC_AMU)")
', '2026-02-09 16:58:45.287251', true, false, 'origin', null, '[]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (870, 'Probable Sophos initial access vulnerability', 2, 2, 1, 'Initial Access', 'T1078.001 - Valid Accounts', 'Sophos firewall has detected the Guest account activation', '["https://attack.mitre.org/tactics/TA0001/","https://attack.mitre.org/techniques/T1078/001/"]', 'equals("log.Id", "17925")
', '2026-02-09 16:58:45.767336', true, false, 'origin', null, '[]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (872, 'Probable password guessing in Sophos Administrator account', 3, 3, 2, 'Credential Access', 'T1110.001 - Brute Force', 'Adversaries with no prior knowledge of legitimate credentials within the system or environment  may guess passwords to attempt access to accounts. Without knowledge of the password for an account,  an adversary may opt to systematically guess the password using a repetitive or iterative mechanism.  An adversary may guess login credentials without prior knowledge of system or environment passwords  during an operation by using a list of common passwords. Password guessing may or may not take into  account the target''s policies on password complexity or use policies that may lock accounts out after  a number of failed attempts.', '["https://support.sophos.com/support/s/article/KB-000034986?language=en_US","https://attack.mitre.org/tactics/TA0006","https://attack.mitre.org/techniques/T1110/001/"]', 'equals("log.Id", "17913")
', '2026-02-09 16:58:46.087527', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-sophos-xg-*","with":[{"field":"log.Id","operator":"filter_term","value":"17913"}],"or":null,"within":"now-15m","count":10}]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (873, 'Sophos XG IPS Alert Detection', 3, 3, 2, 'Intrusion Detection', 'T1190 - Exploit Public-Facing Application', 'Detects IPS alert triggers on Sophos XG Firewall indicating active exploitation attempts, vulnerability scanning, or known attack signatures targeting protected hosts.

Next Steps:
1. Review the IPS signature details and severity level
2. Investigate the source IP for additional malicious activity
3. Check if the attack was blocked or only logged
4. Verify the target system is patched against the detected vulnerability
5. Scan the target for signs of compromise if the attack may have succeeded
6. Update IPS signatures and security policies
', '["https://docs.sophos.com/nsg/sophos-firewall/20.0/Help/en-us/webhelp/onlinehelp/AdministratorHelp/IPS/index.html","https://attack.mitre.org/techniques/T1190/"]', 'equals("log.type", "IPS") &&
(oneOf("log.severity", ["Critical", "High"]) ||
 contains("log.priority", ["1", "2"])) &&
exists("origin.ip") &&
exists("target.ip")
', '2026-02-09 16:58:46.247310', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-sophos-xg-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-15m","count":3}]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (874, 'Sophos XG VPN Authentication Failures', 3, 2, 1, 'Credential Access', 'T1110 - Brute Force', 'Detects multiple VPN authentication failures on Sophos XG Firewall, indicating potential brute force attacks against SSL VPN or IPsec VPN services.

Next Steps:
1. Investigate the source IP and check geographic location
2. Verify the targeted user account exists and is active
3. Check for successful VPN connections from the same IP
4. Consider blocking the source IP
5. Enable MFA for VPN access
6. Review VPN portal exposure settings
', '["https://docs.sophos.com/nsg/sophos-firewall/20.0/Help/en-us/webhelp/onlinehelp/AdministratorHelp/VPN/index.html","https://attack.mitre.org/techniques/T1110/"]', '(equals("log.component", "SSL VPN") || equals("log.component", "IPSec")) &&
equals("log.type", "Event") &&
(contains("log.message", ["authentication failed", "login failed", "invalid credentials", "auth failure"]) ||
 contains("log.subType", "Authentication"))  &&
exists("origin.ip")
', '2026-02-09 16:58:46.421877', true, false, 'origin', null, '[{"indexPattern":"v11-log-firewall-sophos-xg-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-15m","count":10}]', '["adversary.ip","adversary.user"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (875, 'High level Suricata alert', 3, 3, 3, 'Initial Access', 'T1190 - Exploit Public-Facing Application', 'Suricata has detected a high severity alert. This indicates potential malicious activity targeting the network infrastructure, such as exploitation attempts, malware communication, or suspicious network behavior.', '["https://suricata.readthedocs.io/en/latest/"]', 'equals("log.eventType", "alert") && equals("severity", "high")', '2026-02-09 16:58:46.607661', true, false, 'origin', null, '[{"indexPattern":"v11-log-suricata-*","with":[{"field":"origin.ip","operator":"filter_term","value":"{{origin.ip}}"}],"or":null,"within":"now-15m","count":3}]', '["adversary.ip","target.ip"]');
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (876, 'Medium level Suricata alert', 2, 2, 2, 'Discovery', 'T1046 - Network Service Discovery', 'Suricata has detected a medium severity alert that may indicate reconnaissance or scanning attempts. This could include port scanning, protocol anomalies, or suspicious network patterns that warrant investigation but may not represent an immediate threat.', '["https://suricata.readthedocs.io/en/latest/"]', 'equals("log.eventType", "alert") && equals("severity", "medium")', '2026-02-09 16:58:46.767474', true, false, 'target', '["target.ip","target.ip"]', '[{"indexPattern":"v11-log-suricata-*","with":[{"field":"target.ip","operator":"filter_term","value":"{{target.ip}}"}],"or":null,"within":"now-15m","count":5}]', null);
insert into public.utm_correlation_rules (id, rule_name, rule_confidentiality, rule_integrity, rule_availability, rule_category, rule_technique, rule_description, rule_references_def, rule_definition_def, rule_last_update, rule_active, system_owner, rule_adversary, rule_deduplicate_by_def, rule_after_events_def, rule_group_by_def) values (877, 'Cross-Source Lateral Movement Detection', 3, 2, 1, 'Lateral Movement', 'T1021 - Remote Services', 'Detects patterns of authentication events across multiple log sources that indicate lateral movement. Monitors for remote service access patterns including RDP, SSH, SMB, and WMI connections followed by execution indicators.

Next Steps:
1. Map the authentication chain across systems
2. Identify the initial point of compromise
3. Verify each hop was from authorized activity
4. Check for credential reuse across systems
5. Investigate the final destination for post-exploitation activity
6. Implement network segmentation to limit lateral movement paths
', '["https://attack.mitre.org/techniques/T1021/"]', 'exists("origin.ip") &&
exists("origin.user") &&
(
  (exists("log.message") && (
    (contains("log.message", "remote") && contains("log.message", "login")) ||
    (contains("log.message", "authenticated") && contains("log.message", "from")) ||
    (contains("log.message", "session") && contains("log.message", "opened") && contains("log.message", "remote")) ||
    contains("log.message", "lateral movement") ||
    (contains("log.message", "RDP") && contains("log.message", "connection")) ||
    (contains("log.message", "SMB") && contains("log.message", "authenticated")) ||
    (contains("log.message", "WMI") && contains("log.message", "connection"))
  )) ||
  (exists("action") && (
    equals("action", "remote_login") ||
    equals("action", "network_logon") ||
    equals("action", "rdp_connection")
  ))
